def test_import_handoff_bundle_routes_non_staged_revision_context(
    tmp_path: Path,
) -> None:
    source = DoxaBase.create(tmp_path / "source.sqlite")
    source.record_map_dataset(
        "https://example.test/project#Orders",
        label="Orders",
        is_table=True,
    )
    manual = source.record_graph_revision(
        summary="Manual map review",
        rationale="Record non-staged review history with exact map snapshots.",
        changed_graphs=["map"],
        included_graphs=["map"],
    )
    staged = source.stage_graph_revision(
        summary="Stage shipment table",
        rationale="Create a staged patch alongside ordinary history context.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Shipments a rc:Dataset, rc:Table .
                """,
            }
        ],
    )
    trig_path = tmp_path / "project-handoff.trig"
    snapshot_path = tmp_path / "revision-snapshots.json"
    manifest_path = tmp_path / "handoff-manifest.json"
    source.export_handoff_bundle(
        trig_path,
        snapshot_path,
        manifest_path=manifest_path,
        revision_iris=[manual.revision_iri, staged.revision_iri],
        fail_on_sensitive=True,
    )

    receiver = DoxaBase.create(tmp_path / "receiver.sqlite")
    imported = receiver.import_handoff_bundle(manifest_path)

    assert imported.revision_iris == [manual.revision_iri, staged.revision_iri]
    assert imported.recovery_plan is not None
    plan = imported.recovery_plan
    assert plan.processed_revision_iris == [manual.revision_iri, staged.revision_iri]
    assert plan.next_action_queue_item_counts == {
        "apply_after_review": 1,
        "informational": 1,
    }
    lanes_by_source = {lane.source_revision_iri: lane for lane in plan.lanes}
    manual_lane = lanes_by_source[manual.revision_iri]
    assert manual_lane.batch_action == "skipped_non_staged_history_record"
    assert manual_lane.next_action is not None
    assert manual_lane.next_action.tool_name == "describe_graph_revision"
    assert plan.not_restageable_revision_iris_by_reason[
        "non_staged_history_record"
    ] == [manual.revision_iri]
    evidence_by_iri = {
        row.revision_iri: row for row in imported.post_import_snapshot_evidence
    }
    assert evidence_by_iri[manual.revision_iri].status == "history_plus_snapshot_rows"
    assert evidence_by_iri[staged.revision_iri].status == "history_plus_snapshot_rows"
    validation = receiver.validate_graph(scope="all")
    assert validation.conforms, validation.report_text


def test_export_preflight_blocks_sensitive_handoff_scope(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    fake_secret = "FAKE_SECRET_DO_NOT_USE_PREFLIGHT"
    db.record_map_storage_access(
        "https://example.test/project#orders_storage",
        storage_protocol="rc:LocalFilesystemStorage",
        storage_root=f"/tmp/{fake_secret}/orders",
    )
    staged = db.stage_graph_revision(
        summary="Stage preflight probe",
        rationale="Create a revision snapshot over the sensitive map graph.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:OrdersPreflightProbe a rc:Dataset .
                """,
            }
        ],
    )

    preflight = db.export_preflight(
        export_kind="handoff_bundle",
        revision_iris=[staged.revision_iri],
        limit=1,
    )

    assert preflight.decision == "block"
    assert preflight.scanner_clean is False
    assert preflight.shareability_review_required is True
    assert preflight.shareability_review_status == "required_not_completed"
    assert preflight.would_block_sensitive_export is True
    assert preflight.graphs == [
        "ontology",
        "map",
        "observations",
        "patterns",
        "evidence",
        "shapes",
        "history",
    ]
    assert preflight.revision_iris == [staged.revision_iri]
    assert preflight.snapshot_graph_roles == ["map"]
    assert preflight.sensitive_literal_count >= 2
    assert preflight.graph_sensitive_literal_count >= 1
    assert preflight.snapshot_sensitive_literal_count >= 1
    assert preflight.returned_match_count == 1
    assert preflight.omitted_match_count == (
        preflight.sensitive_literal_count - preflight.returned_match_count
    )
    assert preflight.matches[0].match_id.startswith("redacted-sha256:")
    assert preflight.privacy_warnings
    assert preflight.scanner_note in preflight.warnings
    assert [
        action.tool_name for action in preflight.suggested_next_actions
    ] == [
        "scan_sensitive_literals",
        "export_preflight",
        "preflight_context_slice_export",
    ]
    slice_action = preflight.suggested_next_actions[-1]
    assert slice_action.arguments == {
        "seed_iris": ["<target-resource-iri>"],
        "profile": "dataset_brief",
        "max_triples": 500,
        "limit": 20,
    }
    assert "review context" in slice_action.reason
    assert "not recovery-complete" in slice_action.reason
    assert fake_secret not in json.dumps(to_dict(preflight))


def test_profile_privacy_orientation_payloads_redact_sensitive_evidence_summaries(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    fake_secret = "FAKE_SECRET_DO_NOT_USE_PROFILE_ORIENTATION"
    redacted = "[REDACTED:fake_secret_marker]"
    dataset = "https://example.test/project#OrdersProfilePrivacy"
    evidence = "https://example.test/project#OrdersProfilePrivacyEvidence"

    db.record_dataset_profile(
        dataset,
        summary=f"Orders profile summary carried {fake_secret}.",
        evidence_summary=f"Orders profile evidence carried {fake_secret}.",
        evidence_sources=[f"test://profile/{fake_secret}/orders.json"],
        evidence_iri=evidence,
        sample_size=10,
        sample_scope=f"All rows in the profile fixture with {fake_secret}.",
        sample_method=f"Synthetic profiler run with {fake_secret}.",
        row_count=10,
        value_frequencies=[
            {"value": fake_secret, "frequency": 1},
            {"value": "ordinary", "frequency": 9},
        ],
        profile_metrics=[
            {
                "metric": "rc:MaximumValue",
                "value": f"metric value {fake_secret}",
            }
        ],
        map_label="Orders profile privacy",
        map_description=f"Dataset description carried {fake_secret}.",
        is_table=True,
    )

    profile_run = db.describe_profile_run(dataset, evidence)

    assert profile_run.dataset.description == redacted
    assert profile_run.evidence.summary == redacted
    assert profile_run.evidence.sources == [redacted]
    profile = profile_run.dataset_profile_observations[0]
    assert profile.summary == redacted
    assert profile.sample_scope == redacted
    assert profile.sample_method == redacted
    assert [item.value for item in profile.value_frequencies] == [
        "ordinary",
        redacted,
    ]
    assert redacted in {metric.value for metric in profile.profile_metrics}
    profile_run_payload = json.dumps(to_jsonable(profile_run), sort_keys=True)
    assert fake_secret not in profile_run_payload
    assert redacted in profile_run_payload

    query_context = db.describe_query_context(dataset)
    query_payload = json.dumps(
        to_jsonable(query_context.suggested_next_actions),
        sort_keys=True,
    )
    assert fake_secret not in query_payload
    assert redacted in query_payload

    review_bundle = db.export_profile_insight_review_bundle(
        dataset,
        evidence,
        tmp_path / "profile-review.md",
    )
    review_payload = json.dumps(to_jsonable(review_bundle), sort_keys=True)
    assert fake_secret not in review_payload
    assert redacted in review_payload

    route_dataset = "https://example.test/project#OrdersProfileRoutePrivacy"
    route_evidence = (
        "https://example.test/project#OrdersProfileRoutePrivacyEvidence"
    )
    project_metric = f"https://example.test/project#{fake_secret}"
    db.record_dataset_profile(
        route_dataset,
        summary="Orders profile route privacy.",
        evidence_summary="Orders profile route evidence.",
        evidence_sources=["test://profile/orders-route.json"],
        evidence_iri=route_evidence,
        row_count=10,
        update_map_snapshot=False,
        profile_metrics=[
            {
                "metric": project_metric,
                "value": "0.99",
                "datatype": "xsd:decimal",
            }
        ],
        map_label="Orders profile route privacy",
        is_table=True,
    )

    draft = db.draft_profile_map_updates(route_dataset, route_evidence)
    draft_payload = json.dumps(
        to_jsonable(draft.suggested_next_actions),
        sort_keys=True,
    )
    assert fake_secret in draft_payload

    brief = db.project_brief(limit=10, profile_candidate_limit=5)
    brief_payload = json.dumps(to_jsonable(brief), sort_keys=True)
    assert fake_secret not in brief_payload
    assert redacted in brief_payload


def test_export_preflight_returns_scanner_clean_export_action(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.record_map_dataset(
        "https://example.test/project#Orders",
        label="Orders",
        is_table=True,
    )

    preflight = db.export_preflight(export_kind="trig", graphs="workflow")

    assert preflight.decision == "clean_by_scanner_only"
    assert preflight.scanner_clean is True
    assert preflight.shareability_review_required is True
    assert preflight.shareability_review_status == "required_not_completed"
    assert preflight.would_block_sensitive_export is False
    assert preflight.sensitive_literal_count == 0
    assert preflight.matches == []
    assert preflight.privacy_warnings == []
    assert len(preflight.warnings) == 2
    assert "review context only" in preflight.warnings[0]
    assert "export_handoff_bundle" in preflight.warnings[0]
    assert preflight.warnings[1] == preflight.scanner_note
    assert [action.tool_name for action in preflight.suggested_next_actions] == [
        "export_trig"
    ]
    action = preflight.suggested_next_actions[0]
    assert action.arguments["graphs"] == [
        "map",
        "observations",
        "patterns",
        "evidence",
    ]
    assert action.arguments["fail_on_sensitive"] is True
    assert not (tmp_path / "<project-review-bundle.trig>").exists()

    workflow_export = db.export_trig(tmp_path / "workflow.trig", graphs="workflow")
    assert "review context only" in workflow_export.warnings[0]
    assert workflow_export.artifact_kind == "workflow_review_trig"
    assert workflow_export.importable is True
    assert workflow_export.recommended_import_tool == "doxabase.import_trig"
    assert workflow_export.recovery_complete is False

    project_preflight = db.export_preflight(export_kind="trig", graphs="project")
    assert project_preflight.warnings == [project_preflight.scanner_note]
    handoff_preflight = db.export_preflight(export_kind="handoff_bundle")
    assert handoff_preflight.warnings == [handoff_preflight.scanner_note]


def test_replace_graph_triples_can_create_same_count_digest_drift(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .
        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

        ex:Orders a rc:Dataset ;
            rdfs:label "Orders scratch table" .

        ex:Customers a rc:Dataset ;
            rdfs:label "Customers scratch table" .

        ex:OrderCustomerLink a rc:Relationship ;
            rc:sourceDataset ex:Orders .
        """,
        graph="map",
    )
    staged = db.stage_graph_revision(
        summary="Stage an Orders review comment",
        rationale="The staged patch should become stale after unrelated map drift.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Staged comment." .
                """,
            }
        ],
    )

    result = db.replace_graph_triples(
        "map",
        removals="""
            @prefix ex: <https://example.test/project#> .
            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

            ex:Customers rdfs:label "Customers scratch table" .
        """,
        additions="""
            @prefix ex: <https://example.test/project#> .
            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

            ex:Customers rdfs:label "Customers scratch table, drifted after staging" .
        """,
        expected_count=6,
    )

    assert result.graph == "map"
    assert result.before_count == 6
    assert result.after_count == 6
    assert result.count_delta == 0
    assert result.same_count is True
    assert result.digest_changed is True
    assert result.removal_triples == 1
    assert result.addition_triples == 1
    assert result.triples_removed == 1
    assert result.triples_added == 1
    assert result.before_digest.startswith("sha256:")
    assert result.after_digest.startswith("sha256:")
    assert result.before_digest != result.after_digest

    check = db.check_staged_revision_apply(staged.revision_iri)
    assert check.status == "conflict"
    assert check.blocking_reasons == ["target_digest_drift"]
    assert check.count_drifts == []
    drift = check.snapshot_drifts[0]
    assert drift.graph_role == "map"
    assert drift.snapshot_triple_count == 6
    assert drift.current_triple_count == 6
    assert drift.snapshot_content_digest == result.before_digest
    assert drift.current_content_digest == result.after_digest
    assert [triple.object for triple in drift.triples_added_since_snapshot] == [
        "Customers scratch table, drifted after staging"
    ]
    assert [triple.object for triple in drift.triples_removed_since_snapshot] == [
        "Customers scratch table"
    ]


def test_replace_graph_triples_rejects_count_change_before_mutating(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .

        ex:Orders a rc:Dataset .
        """,
        graph="map",
    )
    before_digest = db._graph_content_digest("map")

    with pytest.raises(DoxaBaseError, match="would change graph 'map' count"):
        db.replace_graph_triples(
            "map",
            additions="""
                @prefix ex: <https://example.test/project#> .
                @prefix rc: <https://richcanopy.org/ns/rc#> .

                ex:Customers a rc:Dataset .
            """,
        )

    assert db.triple_count("map") == 1
    assert db._graph_content_digest("map") == before_digest
    assert db.search("Customers", graph="map").matches == []


def test_replace_graph_triples_updates_stale_incoming_link_and_search_index(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .
        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

        ex:Orders a rc:Dataset ;
            rc:hasColumn ex:CustomerV1 .

        ex:CustomerV1 a rc:Column ;
            rc:columnName "customer_id" ;
            rdfs:label "Customer feed v1" .
        """,
        graph="map",
    )
    before_digest = db._graph_content_digest("map")

    result = db.replace_graph_triples(
        "map",
        removals="""
            @prefix ex: <https://example.test/project#> .
            @prefix rc: <https://richcanopy.org/ns/rc#> .
            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

            ex:Orders rc:hasColumn ex:CustomerV1 .

            ex:CustomerV1 a rc:Column ;
                rc:columnName "customer_id" ;
                rdfs:label "Customer feed v1" .
        """,
        additions="""
            @prefix ex: <https://example.test/project#> .
            @prefix rc: <https://richcanopy.org/ns/rc#> .
            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

            ex:Orders rc:hasColumn ex:CustomerV2 .

            ex:CustomerV2 a rc:Column ;
                rc:columnName "customer_id" ;
                rdfs:label "Customer feed v2" .
        """,
        expected_count=5,
    )

    assert result.before_count == 5
    assert result.after_count == 5
    assert result.same_count is True
    assert result.triples_removed == 4
    assert result.triples_added == 4
    assert result.before_digest == before_digest
    assert result.after_digest != before_digest
    assert db.search("Customer feed v1", graph="map").matches == []
    assert len(db.search("Customer feed v2", graph="map").matches) == 1


def test_export_trig_preserves_graph_roles_for_round_trip(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.import_trig(AIS_FIXTURE)
    export_path = tmp_path / "bundle.trig"

    result = db.export_trig(export_path)

    assert result.format == "trig"
    assert result.graphs == [
        "ontology",
        "map",
        "observations",
        "patterns",
        "evidence",
        "shapes",
        "history",
    ]
    assert result.graph_counts == {
        graph: db.triple_count(graph) for graph in result.graphs
    }
    assert result.triples == sum(db.triple_count(graph) for graph in result.graphs)
    assert result.warnings == []

    dataset = Dataset()
    dataset.parse(export_path, format="trig")
    identifiers = {str(context.identifier) for context in dataset.graphs() if len(context)}
    assert "https://richcanopy.org/graph/base_ontology" not in identifiers
    assert "https://richcanopy.org/graph/map" in identifiers
    assert "https://richcanopy.org/graph/observations" in identifiers

    round_trip = DoxaBase.create(tmp_path / "round-trip.sqlite")
    imported = round_trip.import_trig(export_path)
    assert imported["map"] == db.triple_count("map")
    assert imported["observations"] == db.triple_count("observations")
    assert imported["evidence"] == db.triple_count("evidence")
    assert imported["ontology"] == db.triple_count("ontology")


def test_export_trig_all_with_seeds_requires_explicit_seed_import(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    db.import_trig(AIS_FIXTURE)
    export_path = tmp_path / "all-with-seeds.trig"

    result = db.export_trig(export_path, graphs="all_with_seeds")

    assert result.graphs[:2] == ["base_ontology", "base_shapes"]
    assert result.graph_counts["base_ontology"] == db.triple_count("base_ontology")
    assert result.graph_counts["base_shapes"] == db.triple_count("base_shapes")

    round_trip = DoxaBase.create(tmp_path / "round-trip-with-seeds.sqlite")
