def test_list_graph_revisions_routes_handled_stale_to_applied_successor(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    source = db.stage_graph_revision(
        summary="Stage messages table",
        rationale="Messages should become durable map context after review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    db.record_map_dataset(
        "https://example.test/project#DriftMaker",
        label="Drift maker",
    )
    successor = db.restage_staged_revision(
        source.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    applied = db.apply_staged_revision(
        successor.revision_iri,
        created_at="2026-06-01T10:02:00Z",
    )

    listing = db.list_graph_revisions(include_apply_checks=True)
    by_iri = {item.iri: item for item in listing.revisions}
    source_row = by_iri[source.revision_iri]

    assert source_row.application_status == "conflict"
    assert source_row.restaged_by == successor.revision_iri
    assert source_row.current_restaged_by == successor.revision_iri
    assert source_row.stale_resolution_state == "stale_handled_by_restage"
    assert source_row.is_current_staged_work is False
    assert source_row.next_action is not None
    assert source_row.next_action.action_type == "inspect_already_applied"
    assert source_row.next_action.queue == "inspect_already_applied"
    assert source_row.next_action.tool_name == "describe_graph_revision"
    assert source_row.next_action.arguments == {"iri": applied.applied_revision_iri}
    assert source_row.suggested_next_actions[0].tool_name == (
        "describe_graph_revision"
    )
    assert source_row.suggested_next_actions[0].arguments == {
        "iri": applied.applied_revision_iri
    }
    assert listing.next_action_queue["inspect_already_applied"].count(
        source.revision_iri
    ) == 1
    source_queue_item = next(
        item
        for item in listing.next_action_queue_items
        if item.row_iri == source.revision_iri
    )
    assert source_queue_item.queue == "inspect_already_applied"
    assert source_queue_item.action_type == "inspect_already_applied"
    assert source_queue_item.resolved_target_iri == applied.applied_revision_iri
    assert source_queue_item.resolved_target_record_kind == "applied_event"
    assert source_queue_item.resolved_target_iri_source == (
        "next_action.arguments.iri"
    )
    assert source_queue_item.row_is_target is False
    assert source_queue_item.application_status == "conflict"
    assert source_queue_item.stale_resolution_state == "stale_handled_by_restage"
    assert source_queue_item.alternative_semantic_review_required is False
    assert listing.next_action_queue_item_counts["inspect_already_applied"] >= 1
    assert listing.semantic_review_required_queue_counts == {}

    resource_listing = db.list_resource_revisions(
        "https://example.test/project#Messages",
        include_apply_checks=True,
    )
    assert "returned page" in resource_listing.timeline_note
    assert [
        event.revision_iri for event in resource_listing.timeline
    ] == [
        source.revision_iri,
        successor.revision_iri,
        applied.applied_revision_iri,
    ]
    assert [
        event.timeline_role for event in resource_listing.timeline
    ] == [
        "restaged_source",
        "applied_source",
        "applied_event",
    ]
    timeline_by_iri = {
        event.revision_iri: event for event in resource_listing.timeline
    }
    source_event = timeline_by_iri[source.revision_iri]
    assert source_event.next_action_call == (
        "describe_graph_revision("
        f"iri='{applied.applied_revision_iri}'"
        ")"
    )
    assert source_event.resolved_target_iri == applied.applied_revision_iri
    assert source_event.resolved_target_record_kind == "applied_event"
    assert source_event.row_is_target is False
    assert timeline_by_iri[successor.revision_iri].applied_revision_iri == (
        applied.applied_revision_iri
    )
    assert timeline_by_iri[applied.applied_revision_iri].staged_revision_iri == (
        successor.revision_iri
    )


def test_restage_staged_revision_preserves_patch_sequence(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    addition_operation = db.expand_iri("rc:AdditionPatch")
    removal_operation = db.expand_iri("rc:RemovalPatch")
    patch_role = db.expand_iri("rc:FramingPatch")

    def ordered_patch(operation: str, content: str) -> dict:
        patch_graph = Graph()
        patch_graph.parse(data=content, format="turtle")
        return {
            "patch_iri": db._mint_iri("graph-patch"),
            "operation": operation,
            "target_graph": "map",
            "format": "turtle",
            "patch_role": patch_role,
            "content": content,
            "graph": patch_graph,
        }

    source = db.stage_graph_revision(
        summary="Replace Orders label",
        rationale="Exercise restage replay of a removal-first patch sequence.",
        validation_scope="all",
        _ordered_patch_specs=[
            ordered_patch(
                removal_operation,
                """
                @prefix ex: <https://example.test/project#> .
                @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                ex:Orders rdfs:label "Orders" .
                """,
            ),
            ordered_patch(
                addition_operation,
                """
                @prefix ex: <https://example.test/project#> .
                @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                ex:Orders rdfs:label "Preferred orders" .
                """,
            ),
        ],
    )

    assert [patch.operation for patch in source.patches] == [
        removal_operation,
        addition_operation,
    ]
    assert db.check_staged_revision_apply(source.revision_iri).status == "ready"
    db.record_map_dataset(
        "https://example.test/project#InterveningDataset",
        label="Intervening dataset",
    )

    restaged = db.restage_staged_revision(source.revision_iri)

    assert [patch.operation for patch in restaged.patches] == [
        removal_operation,
        addition_operation,
    ]
    assert [patch.sequence_index for patch in restaged.patches] == [1, 2]
    assert restaged.patches[0].before_triple_count == db.triple_count("map")
    assert restaged.patches[0].after_triple_count == db.triple_count("map") - 1
    assert restaged.patches[1].before_triple_count == db.triple_count("map") - 1
    assert restaged.patches[1].after_triple_count == db.triple_count("map")
    assert db.check_staged_revision_apply(restaged.revision_iri).status == "ready"


def test_stage_graph_revision_can_record_repaired_restage_successor(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    source = db.stage_graph_revision(
        summary="Stage old orders label",
        rationale="Original stale candidate used a label that later proved wrong.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Old orders" .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    db.record_map_dataset(orders, label="Current orders", is_table=True)
    assert db.check_staged_revision_apply(source.revision_iri).status == "conflict"

    repair = db.stage_graph_revision(
        summary="Repair stale orders label",
        rationale=(
            "Caller-authored repair for the stale label candidate; replaces "
            "the current label instead of replaying the old add-only patch."
        ),
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Preferred orders" .
                """,
            }
        ],
        removals=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Current orders" .
                """,
            }
        ],
        restages_revision=source.revision_iri,
        review_recommendation="Review repaired successor before applying.",
    )

    assert repair.restaged_from == source.revision_iri
    assert repair.restage_reason is not None
    assert "Caller-authored repair" in repair.restage_reason
    source_description = db.describe_staged_revision(source.revision_iri)
    assert source_description.restaged_by is not None
    assert source_description.restaged_by.iri == repair.revision_iri
    repair_description = db.describe_staged_revision(repair.revision_iri)
    assert repair_description.restaged_from is not None
    assert repair_description.restaged_from.iri == source.revision_iri
    current_work = db.list_graph_revisions(
        current_staged_work_only=True,
        include_apply_checks=True,
    )
    current_work_iris = {item.iri for item in current_work.revisions}
    assert source.revision_iri not in current_work_iris
    assert repair.revision_iri in current_work_iris
    with pytest.raises(DoxaBaseError, match="already has a refreshed successor"):
        db.stage_graph_revision(
            summary="Parallel repaired successor",
            rationale="This would create an ambiguous successor chain.",
            additions=[
                {
                    "graph": "map",
                    "content": """
                        @prefix ex: <https://example.test/project#> .
                        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                        ex:Orders rdfs:comment "Parallel repair." .
                    """,
                }
            ],
            restages_revision=source.revision_iri,
        )


def test_ready_restage_source_apply_check_redirects_to_successor(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    source = db.stage_graph_revision(
        summary="Stage old orders label",
        rationale="Original candidate is still mechanically ready.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Old orders" .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    repair = db.stage_graph_revision(
        summary="Supersede ready source",
        rationale="Caller-authored successor should become the active candidate.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Preferred orders" .
                """,
            }
        ],
        restages_revision=source.revision_iri,
    )

    source_check = db.check_staged_revision_apply(source.revision_iri)

    assert source_check.can_apply is False
    assert source_check.status == "superseded_by_restage"
    assert source_check.decision == "inspect_current_successor"
    assert source_check.blocking_reasons == ["superseded_by_restage"]
    assert source_check.validation_conforms is True
    assert source_check.suggested_next_actions[0].tool_name == (
        "describe_staged_revision"
    )
    assert source_check.suggested_next_actions[0].action_label == (
        "Inspect current refreshed successor"
    )
    assert source_check.suggested_next_actions[0].arguments == {
        "iri": repair.revision_iri
    }
    with pytest.raises(DoxaBaseError, match="refreshed successor"):
        db.apply_staged_revision(source.revision_iri)

    described_source = db.describe_staged_revision(
        source.revision_iri,
        include_current_apply_check=True,
    )
    assert described_source.current_apply_check is not None
    assert described_source.current_apply_check.status == "superseded_by_restage"
    assert described_source.current_apply_check.next_action is not None
    assert described_source.current_apply_check.next_action.action_type == (
        "inspect_current_successor"
    )
    assert described_source.current_apply_check.next_action.queue == "informational"
    assert described_source.current_apply_check.next_action.arguments == {
        "iri": repair.revision_iri
    }
    listing = db.list_graph_revisions(
        current_staged_work_only=True,
        include_apply_checks=True,
    )
    assert [item.iri for item in listing.revisions] == [repair.revision_iri]
    export_path = tmp_path / "ready-superseded-review.md"
    export = db.export_staged_revisions(
        [source.revision_iri, repair.revision_iri],
        export_path,
    )
    summaries = {item.revision_iri: item for item in export.revision_summaries}
    assert summaries[source.revision_iri].apply_status == "superseded_by_restage"
    assert summaries[source.revision_iri].suggested_next_actions[0].tool_name == (
        "describe_staged_revision"
    )
    assert summaries[source.revision_iri].suggested_next_actions[0].arguments == {
        "iri": repair.revision_iri
    }
    assert not any(
        action.tool_name == "apply_staged_revision"
        for action in summaries[source.revision_iri].suggested_next_actions
    )
    assert summaries[repair.revision_iri].apply_status == "ready"
    assert any(
        action.tool_name == "apply_staged_revision"
        for action in summaries[repair.revision_iri].suggested_next_actions
    )
    exported = export_path.read_text(encoding="utf-8")
    source_section = exported.split("## Revision 1: Stage old orders label", 1)[
        1
    ].split(
        "## Revision 2:",
        1,
    )[0]
    assert "**Inspect current refreshed successor:**" in source_section
    assert "apply_staged_revision" not in source_section
    assert repair.revision_iri in source_section


def test_stage_map_assertion_change_can_repair_stale_assertion_successor(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Current orders", is_table=True)
    source = db.stage_graph_revision(
        summary="Stage old orders label",
        rationale="Original candidate should be repaired as a replacement.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:label "Old orders" .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    db.record_map_dataset(orders, label="Intervening orders", is_table=True)

    repair = db.stage_map_assertion_change(
        subject=orders,
        predicate="http://www.w3.org/2000/01/rdf-schema#label",
        object="Preferred orders",
        object_kind="literal",
        change_kind="replace",
        rationale="Repair the stale label candidate by replacing the current label.",
        restages_revision=source.revision_iri,
    )

    assert repair.revision_iri == repair.staged_revision.revision_iri
    assert repair.staged_revision.restaged_from == source.revision_iri
    assert repair.staged_revision.restage_reason is not None
    assert "Repair the stale label candidate" in (
        repair.staged_revision.restage_reason
    )
    source_description = db.describe_staged_revision(source.revision_iri)
    assert source_description.restaged_by is not None
    assert (
        source_description.restaged_by.iri
        == repair.staged_revision.revision_iri
    )
    applied = db.apply_staged_revision(repair.staged_revision.revision_iri)
    assert applied.applied_revision_iri
    current_work = db.list_graph_revisions(
        current_staged_work_only=True,
        include_apply_checks=True,
    )
    current_work_iris = {item.iri for item in current_work.revisions}
    assert source.revision_iri not in current_work_iris
    assert repair.staged_revision.revision_iri not in current_work_iris


def test_stale_row_semantics_add_suggests_same_slot_replacement(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    source = db.stage_graph_revision(
        summary="Model Orders as snapshot rows",
        rationale="Original row-grain proposal before an intervening map edit.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders rc:rowSemantics rc:SnapshotRow .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    db.record_map_dataset(orders, row_semantics="rc:EventRow")

    check = db.check_staged_revision_apply(source.revision_iri)

    assert check.status == "conflict"
    assert check.decision == "restage_against_current_graph"
    assert check.routing_decision == "stage_same_slot_replacement"
    assert check.recommended_resolution is not None
    assert "stage_map_assertion_change replacement" in (
        check.recommended_resolution
    )
    assert "mechanically restaging" in check.recommended_resolution
    assert check.next_action is not None
    assert check.next_action.action_type == "repair_or_replace"
    assert check.next_action.queue == "repair_or_replace"
    assert check.next_action.tool_name == "stage_map_assertion_change"
    action_tools = [action.tool_name for action in check.suggested_next_actions]
    assert "stage_map_assertion_change" in action_tools
    assert "restage_staged_revision" not in action_tools
    action = next(
        action
        for action in check.suggested_next_actions
        if action.tool_name == "stage_map_assertion_change"
    )
    assert action.action_label == "Stage same-slot replacement"
    assert action.arguments["subject"] == orders
    assert action.arguments["predicate"] == RC + "rowSemantics"
    assert action.arguments["object"] == RC + "SnapshotRow"
    assert action.arguments["object_kind"] == "iri"
    assert action.arguments["change_kind"] == "replace"
    assert action.arguments["graph"] == "map"
    assert action.arguments["restages_revision"] == source.revision_iri
    assert action.arguments["validation_scope"] == "all"
    draft = db.draft_staged_revision_rebase(source.revision_iri)
    assert draft.result_kind == "staged_revision_rebase_draft"
    assert draft.mode == "non_executed_review_draft"
    assert draft.source_revision_iri == source.revision_iri
    assert draft.current_revision_iri == source.revision_iri
    assert draft.draft_status == "drafted"
    assert draft.draft_kind == "same_slot_replacement"
    assert draft.reason_codes == ["same_slot_replacement"]
    assert draft.apply_check.routing_decision == "stage_same_slot_replacement"
    assert draft.preferred_action is not None
    assert draft.preferred_action.arguments == action.arguments
    assert draft.next_action is not None
    assert draft.next_action.queue == "repair_or_replace"
    assert draft.next_action.tool_name == "stage_map_assertion_change"
    assert [
        action.tool_name for action in draft.suggested_next_actions
    ] == [
        "stage_map_assertion_change",
        "describe_staged_revision",
        "export_staged_revision",
    ]
    assert draft.next_action_queue_item is not None
    assert draft.next_action_queue_item.row_iri == source.revision_iri
    assert draft.next_action_queue_item.row_is_target is False
    assert draft.repair_candidates[0].current_same_subject_predicate_triples[0].object == (
        RC + "EventRow"
    )
    assert draft.repair_candidates[0].proposed_triples[0].object == (
        RC + "SnapshotRow"
    )
    described = db.describe_staged_revision(
        source.revision_iri,
        include_current_apply_check=True,
    )
    assert described.current_apply_check is not None
    assert described.current_apply_check.decision == "restage_against_current_graph"
    assert described.current_apply_check.routing_decision == (
        "stage_same_slot_replacement"
    )

    with pytest.raises(DoxaBaseError, match="same-slot replacement conflict"):
        db.restage_staged_revision(source.revision_iri)

    repair = db.stage_map_assertion_change(**action.arguments)
    assert repair.staged_revision.restaged_from == source.revision_iri
    assert [value.object for value in repair.current_values_before] == [
        RC + "EventRow"
    ]
    repair_check = db.check_staged_revision_apply(
        repair.staged_revision.revision_iri
    )
    assert repair_check.status == "ready"


def test_staged_revision_recovery_session_replans_live_state(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    staged = db.stage_graph_revision(
        summary="Stage messages table",
        rationale="Messages should become durable map context after review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
    )
    db.record_map_dataset(
        "https://example.test/project#OtherDataset",
        label="Other dataset",
    )

    session = db.start_staged_revision_recovery_session(
        [staged.revision_iri],
        summary="Messages recovery session",
        handoff_manifest_path="/tmp/messages-handoff-manifest.json",
        drift_detail="exact",
        created_at="2026-01-02T03:04:05+00:00",
        created_by="https://example.test/agents#TrialAgent",
    )

    assert session.helper == "start_staged_revision_recovery_session"
    assert session.mode == "recorded_session"
    assert session.created_triples is not None
    assert session.created_triples > 0
    assert session.summary == "Messages recovery session"
    assert session.created_at == "2026-01-02T03:04:05+00:00"
    assert session.created_by == "https://example.test/agents#TrialAgent"
    assert session.handoff_manifest_path == "/tmp/messages-handoff-manifest.json"
    assert session.source_revision_iris == [staged.revision_iri]
    assert session.initial_lane_counts == {"restage_after_review": 1}
    assert session.session_status == "active"
    assert session.repair_draft_limit == 1
    assert session.current_plan.repair_draft_limit == 1
    assert session.current_plan.lane_counts == {"restage_after_review": 1}
    assert session.source_states[0].workflow_state == "active"
    assert session.source_states[0].lane == "restage_after_review"
    assert session.source_states[0].effective_recovery_action == (
        "restage_after_review"
    )
    assert session.source_states[0].next_action_tool_name == (
        "restage_staged_revision"
    )
    session_resource = db.describe_resource(session.session_iri, graph="history")
    assert any(
        triple.predicate == str(RDF.type)
        and triple.object == RC + "StagedRevisionRecoverySession"
        for triple in session_resource.outgoing
    )
    assert any(
        triple.predicate == RC + "recoverySessionRepairDraftLimit"
        and triple.object == "1"
        for triple in session_resource.outgoing
    )

    restaged = db.restage_staged_revision(staged.revision_iri)
    after_restage = db.describe_staged_revision_recovery_session(
        session.session_iri,
        drift_detail="exact",
    )

    assert after_restage.helper == "describe_staged_revision_recovery_session"
    assert after_restage.mode == "read_only_description"
    assert after_restage.session_status == "active"
    assert after_restage.repair_draft_limit == 1
    assert after_restage.current_plan.lane_counts == {"apply_after_review": 1}
    assert after_restage.source_states[0].current_revision_iri == (
        restaged.revision_iri
    )
    assert after_restage.source_states[0].effective_recovery_action == (
        "apply_after_review"
    )
    assert after_restage.source_states[0].next_action_tool_name == (
        "apply_staged_revision"
    )

    applied = db.apply_staged_revision(restaged.revision_iri)
    after_apply = db.describe_staged_revision_recovery_session(
        session.session_iri,
        drift_detail="exact",
    )

    assert after_apply.session_status == "complete"
    assert after_apply.current_plan.lane_counts == {"inspect_already_applied": 1}
    assert after_apply.completed_source_revision_iris == [staged.revision_iri]
    assert after_apply.active_source_revision_iris == []
    assert after_apply.applied_event_iris == [applied.applied_revision_iri]
    source_state = after_apply.source_states[0]
    assert source_state.workflow_state == "applied"
    assert source_state.applied_revision_iri == applied.applied_revision_iri
    assert source_state.latest_role == "applied_event"
    assert source_state.next_action_tool_name == "describe_graph_revision"
    assert any(
        action.tool_name == "describe_applied_revision_diff"
        for action in after_apply.suggested_next_actions
    )
    assert db.validate_graph(scope="all").conforms


def test_plan_staged_revision_recovery_routes_mixed_staged_queue(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    repair_source = db.stage_graph_revision(
        summary="Model Orders as snapshot rows",
        rationale="Original row-grain proposal before an intervening map edit.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders rc:rowSemantics rc:SnapshotRow .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    db.record_map_dataset(orders, row_semantics="rc:EventRow")
    informational_source = db.stage_graph_revision(
        summary="Stage already-effective table",
        rationale="This staged source will already be current map state.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:AlreadyEffective a rc:Dataset .
                """,
            }
        ],
    )
    db.record_map_dataset(
        "https://example.test/project#AlreadyEffective",
        label="Already effective",
    )
    stale = db.stage_graph_revision(
        summary="Stage stale messages table",
        rationale="This proposal will need mechanical restage after map drift.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
    )
    handled_source = db.stage_graph_revision(
        summary="Stage handled table",
        rationale="This stale source will already have a refreshed successor.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Handled a rc:Dataset .
                """,
            }
        ],
    )
    applied_source = db.stage_graph_revision(
        summary="Stage applied table",
        rationale="This staged source will already be durable.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Applied a rc:Dataset .
                """,
            }
        ],
    )
    applied_event = db.apply_staged_revision(applied_source.revision_iri)
    handled_successor = db.restage_staged_revision(handled_source.revision_iri)
    ready = db.stage_graph_revision(
        summary="Stage ready table",
        rationale="This proposal is staged against current map state.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Ready a rc:Dataset .
                """,
            }
        ],
    )
    counts_before = _mutable_graph_counts(db)

    plan = db.plan_staged_revision_recovery(
        [
            ready.revision_iri,
            stale.revision_iri,
            handled_source.revision_iri,
            repair_source.revision_iri,
            applied_source.revision_iri,
            informational_source.revision_iri,
        ]
    )

    assert _mutable_graph_counts(db) == counts_before
    assert plan.result_kind == "staged_revision_recovery_plan"
    assert plan.mode == "read_only_plan"
    assert plan.selection_mode == "explicit_revision_iris"
    assert plan.returned_count == 6
    assert plan.current_revision_by_source[handled_source.revision_iri] == (
        handled_successor.revision_iri
    )
    assert plan.would_restage_revision_iris == [stale.revision_iri]
    assert plan.repair_first_revision_iris == []
    assert plan.repair_or_replace_source_revision_iris == [
        repair_source.revision_iri
    ]
    lanes_by_source = {lane.source_revision_iri: lane for lane in plan.lanes}
    assert lanes_by_source[ready.revision_iri].lane == "apply_after_review"
    assert (
        lanes_by_source[ready.revision_iri].effective_recovery_action
        == "apply_after_review"
    )
    assert lanes_by_source[ready.revision_iri].batch_action == (
        "skipped_not_restageable"
    )
    assert lanes_by_source[ready.revision_iri].not_restageable_reason == "ready"
    assert lanes_by_source[ready.revision_iri].status_after == "ready"
    assert lanes_by_source[stale.revision_iri].lane == "restage_after_review"
    assert (
        lanes_by_source[stale.revision_iri].effective_recovery_action
        == "restage_after_review"
    )
    assert lanes_by_source[stale.revision_iri].batch_action == "would_restage"
    handled_lane = lanes_by_source[handled_source.revision_iri]
    assert handled_lane.current_revision_iri == handled_successor.revision_iri
    assert handled_lane.row_iri == handled_successor.revision_iri
    assert handled_lane.lane == "apply_after_review"
    assert handled_lane.batch_action == "skipped_already_handled"
    repair_lane = lanes_by_source[repair_source.revision_iri]
    assert repair_lane.lane == "repair_or_replace"
    assert repair_lane.not_restageable_reason == "same_slot_replacement"
    assert repair_lane.repair_draft is not None
    assert repair_lane.repair_draft.draft_kind == "same_slot_replacement"
    assert repair_lane.repair_draft.preferred_action is not None
    assert repair_lane.repair_draft.preferred_action.arguments["restages_revision"] == (
        repair_source.revision_iri
    )
    assert repair_lane.next_action is not None
    assert repair_lane.next_action.tool_name == "stage_map_assertion_change"
    assert any(
        action.tool_name == "stage_map_assertion_change"
        for action in repair_lane.suggested_next_actions
    )
    applied_lane = lanes_by_source[applied_source.revision_iri]
    assert applied_lane.lane == "inspect_already_applied"
    assert applied_lane.resolved_target_iri == applied_event.applied_revision_iri
    assert applied_lane.resolved_target_record_kind == "applied_event"
    assert applied_lane.row_is_target is False
    informational_lane = lanes_by_source[informational_source.revision_iri]
    assert informational_lane.lane == "informational"
    assert informational_lane.not_restageable_reason == "already_effective"
    assert informational_lane.resolved_target_iri == informational_source.revision_iri
    assert plan.next_action_queue_item_counts == {
        "apply_after_review": 2,
        "restage_after_review": 1,
        "repair_or_replace": 1,
        "inspect_already_applied": 1,
        "informational": 1,
    }
    assert plan.mutation_frontier_iris == [
        ready.revision_iri,
        stale.revision_iri,
        handled_successor.revision_iri,
    ]
    assert [
        action.tool_name for action in plan.helper_mutation_frontier_actions
    ] == ["stage_map_assertion_change"]
    assert plan.helper_mutation_frontier_actions[0].arguments[
        "restages_revision"
    ] == repair_source.revision_iri
    assert plan.helper_mutation_frontier_calls == [
        plan.helper_mutation_frontier_actions[0].call
    ]
    assert [
        item.item_kind for item in plan.mutation_frontier_items
    ] == [
        "revision_target",
        "revision_target",
        "revision_target",
        "helper_action",
    ]
    assert [
        item.target_iri
        for item in plan.mutation_frontier_items
        if item.item_kind == "revision_target"
    ] == plan.mutation_frontier_iris
    helper_item = plan.mutation_frontier_items[-1]
    assert helper_item.queue == "repair_or_replace"
    assert helper_item.target_iri is None
    assert helper_item.source_revision_iris == [repair_source.revision_iri]
    assert helper_item.action == plan.helper_mutation_frontier_actions[0]
    assert any(
        "helper_mutation_frontier_actions" in warning
        and "not represented by mutation_frontier_iris" in warning
        for warning in plan.warnings
    )
    assert plan.resolved_target_group_counts == plan.next_action_queue_item_counts
    assert plan.requires_recheck_after_each_apply is True
    assert set(plan.sequential_apply_recheck_candidate_iris) == {
        ready.revision_iri,
        handled_successor.revision_iri,
    }
    assert any(
        "apply at most one ready row" in warning for warning in plan.warnings
    )
    batch_dry_run_action = plan.suggested_next_actions[0]
    assert batch_dry_run_action.tool_name == "restage_staged_revisions"
    assert batch_dry_run_action.arguments == {
        "revision_iris": [stale.revision_iri],
        "dry_run": True,
    }
    assert any(
        action.tool_name == "restage_staged_revision"
        and action.arguments == {"iri": stale.revision_iri}
        for action in plan.suggested_next_actions
    )

    alias_plan = db.plan_staged_revision_recovery(
        [
            handled_source.revision_iri,
            handled_successor.revision_iri,
            applied_source.revision_iri,
        ]
    )
    assert alias_plan.lane_counts == {
        "apply_after_review": 2,
        "inspect_already_applied": 1,
    }
    assert alias_plan.next_action_queue_item_counts == {
        "apply_after_review": 2,
        "inspect_already_applied": 1,
    }
    assert alias_plan.next_action_queue["apply_after_review"] == [
        handled_successor.revision_iri
    ]
    assert alias_plan.mutation_frontier_iris == [handled_successor.revision_iri]
    assert alias_plan.resolved_target_group_counts == {
        "apply_after_review": 1,
        "inspect_already_applied": 1,
    }
    groups_by_target = {
        group.resolved_target_iri: group
        for group in alias_plan.resolved_target_groups
    }
    handled_group = groups_by_target[handled_successor.revision_iri]
    assert handled_group.queue == "apply_after_review"
    assert handled_group.lane_count == 2
    assert handled_group.row_iris == [handled_successor.revision_iri]
    assert handled_group.source_revision_iris == [
        handled_source.revision_iri,
        handled_successor.revision_iri,
    ]
    assert handled_group.requested_revision_iris == [
        handled_source.revision_iri,
        handled_successor.revision_iri,
    ]
    assert handled_group.current_revision_iris == [handled_successor.revision_iri]
    assert handled_group.latest_revision_iris == [handled_successor.revision_iri]
    assert set(handled_group.restage_chain_iris) == {
        handled_source.revision_iri,
        handled_successor.revision_iri,
    }
    assert handled_group.row_is_target_all is True
    assert handled_group.row_is_target_any is True
    applied_group = groups_by_target[applied_event.applied_revision_iri]
    assert applied_group.queue == "inspect_already_applied"
    assert applied_group.lane_count == 1
    assert applied_group.applied_event_iris == [applied_event.applied_revision_iri]
    assert applied_group.row_is_target_all is False
    assert applied_group.row_is_target_any is False

    dry_run = db.restage_staged_revisions(
        plan.would_restage_revision_iris,
        dry_run=True,
    )

    assert dry_run.would_restage_revision_iris == [stale.revision_iri]

    batch = db.restage_staged_revisions(dry_run.would_restage_revision_iris)
    restaged_stale_iri = batch.restaged_revision_iris[0]
    applied_ready = db.apply_staged_revision(ready.revision_iri)

    assert set(applied_ready.post_apply_recheck_revision_iris) == {
        restaged_stale_iri,
        handled_successor.revision_iri,
        informational_source.revision_iri,
        repair_source.revision_iri,
    }

    followup_plan = db.plan_staged_revision_recovery(
        current_staged_work_only=True
    )

    assert followup_plan.next_action_queue_item_counts == {
        "restage_after_review": 2,
        "repair_or_replace": 1,
        "informational": 1,
    }
    assert set(followup_plan.would_restage_revision_iris) == {
        restaged_stale_iri,
        handled_successor.revision_iri,
    }
    followup_batch_action = followup_plan.suggested_next_actions[0]
    assert followup_batch_action.tool_name == "restage_staged_revisions"
    assert set(followup_batch_action.arguments["revision_iris"]) == {
        restaged_stale_iri,
        handled_successor.revision_iri,
    }
    assert followup_batch_action.arguments["dry_run"] is True
    assert set(followup_plan.mutation_frontier_iris) == {
        restaged_stale_iri,
        handled_successor.revision_iri,
    }
    assert followup_plan.repair_or_replace_source_revision_iris == [
        repair_source.revision_iri
    ]
    assert informational_source.revision_iri not in (
        followup_plan.mutation_frontier_iris
    )


