def test_list_graph_revisions_summarizes_history_and_apply_status(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    staged = db.stage_graph_revision(
        summary="Stage messages table",
        rationale="Messages should become durable map context after review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )

    staged_listing = db.list_graph_revisions(
        revision_type="rc:StagedRevision",
        include_apply_checks=True,
    )
    assert staged_listing.count == 1
    assert staged_listing.returned_count == 1
    assert staged_listing.total_count == 1
    assert staged_listing.drift_detail == "summary"
    assert staged_listing.record_kind is None
    assert staged_listing.application_status is None
    assert staged_listing.staged_validation_status is None
    assert staged_listing.stale_resolution_state is None
    assert staged_listing.current_staged_work_only is False
    assert staged_listing.returned_current_staged_work_application_status_counts == {
        "ready": 1
    }
    assert staged_listing.revisions[0].iri == staged.revision_iri
    assert staged_listing.revisions[0].record_kind == "staged_patch"
    assert staged_listing.revisions[0].is_current_staged_work is True
    assert staged_listing.revisions[0].not_current_staged_work_reason is None
    assert staged_listing.revisions[0].revision_type == RC + "StagedRevision"
    assert staged_listing.revisions[0].revision_type_label == "staged revision"
    assert staged_listing.revisions[0].has_patch_payload is True
    assert staged_listing.revisions[0].patch_count == 1
    assert staged_listing.revisions[0].snapshot_evidence.status == (
        "history_plus_snapshot_rows"
    )
    assert staged_listing.revisions[0].snapshot_evidence.exact_snapshot_graph_roles == [
        "map"
    ]
    assert staged_listing.revisions[0].application_status == "ready"
    assert staged_listing.revisions[0].staged_validation_status == "conforms"
    assert staged_listing.revisions[0].application_can_apply is True
    assert staged_listing.revisions[0].stale_resolution_state == "ready"
    assert staged_listing.revisions[0].application_summary is not None
    assert staged_listing.revisions[0].application_summary.startswith("Ready to apply")
    assert staged_listing.revisions[0].application_recommended_resolution is not None
    assert staged_listing.revisions[0].application_validation_skipped_reason is None
    assert staged_listing.revisions[0].suggested_next_actions

    applied = db.apply_staged_revision(
        staged.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    listing = db.list_graph_revisions(include_apply_checks=True)

    assert listing.count == 2
    assert listing.returned_count == 2
    assert listing.total_count == 2
    by_iri = {item.iri: item for item in listing.revisions}
    assert by_iri[staged.revision_iri].applied_by == applied.applied_revision_iri
    assert by_iri[staged.revision_iri].application_status == "already_applied"
    assert by_iri[staged.revision_iri].stale_resolution_state == "already_applied"
    assert by_iri[staged.revision_iri].is_current_staged_work is False
    assert (
        by_iri[staged.revision_iri].not_current_staged_work_reason
        == "already_applied_source"
    )
    assert by_iri[staged.revision_iri].application_summary == (
        f"Already applied by {applied.applied_revision_iri}."
    )
    assert by_iri[staged.revision_iri].application_validation_skipped_reason == (
        "already_applied"
    )
    assert by_iri[applied.applied_revision_iri].applies_staged_revision == (
        staged.revision_iri
    )
    assert by_iri[applied.applied_revision_iri].record_kind == "applied_event"
    assert by_iri[applied.applied_revision_iri].has_patch_payload is False
    assert by_iri[applied.applied_revision_iri].patch_count == 0
    assert by_iri[applied.applied_revision_iri].application_status == "applied_event"
    assert by_iri[applied.applied_revision_iri].stale_resolution_state is None
    assert by_iri[applied.applied_revision_iri].is_current_staged_work is False
    assert (
        by_iri[applied.applied_revision_iri].not_current_staged_work_reason
        == "applied_event_record"
    )
    assert listing.revisions[0].iri == applied.applied_revision_iri

    stale = db.stage_graph_revision(
        summary="Stage other table",
        rationale="Exercise list status for count drift.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:OtherMessages a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:02:00Z",
    )
    db.record_map_dataset(
        "https://example.test/project#DriftMaker",
        label="Drift maker",
    )
    restaged = db.restage_staged_revision(
        stale.revision_iri,
        created_at="2026-06-01T10:03:00Z",
    )
    manual = db.record_graph_revision(
        summary="Record manual review note",
        rationale="Exercise current staged work reason for non-staged history.",
        changed_graphs=["map"],
        created_at="2026-06-01T10:04:00Z",
    )

    drift_listing = db.list_graph_revisions(include_apply_checks=True)
    assert drift_listing.drift_detail == "summary"
    assert "conflict" in drift_listing.returned_application_status_counts
    assert drift_listing.returned_current_staged_work_application_status_counts == {
        "ready": 1
    }
    drift_by_iri = {item.iri: item for item in drift_listing.revisions}
    stale_item = drift_by_iri[stale.revision_iri]
    assert stale_item.application_status == "conflict"
    assert stale_item.application_summary is not None
    assert stale_item.application_summary.startswith(
        "Handled by restage; inspect successor"
    )
    assert restaged.revision_iri in stale_item.application_summary
    assert stale_item.application_recommended_resolution is not None
    assert "already has a refreshed successor" in (
        stale_item.application_recommended_resolution
    )
    assert restaged.revision_iri in stale_item.application_recommended_resolution
    assert stale_item.application_validation_skipped_reason == "conflicts_present"
    assert stale_item.application_blocking_reasons == ["target_count_drift"]
    assert stale_item.application_count_drifts[0].target_graph == "map"
    assert stale_item.restaged_by == restaged.revision_iri
    assert stale_item.stale_resolution_state == "stale_handled_by_restage"
    assert stale_item.is_current_staged_work is False
    assert stale_item.not_current_staged_work_reason == "superseded_by_restage"
    assert stale_item.suggested_next_actions[-1].tool_name == "describe_staged_revision"
    assert stale_item.suggested_next_actions[-1].arguments == {
        "iri": restaged.revision_iri
    }
    assert drift_by_iri[restaged.revision_iri].restaged_from == stale.revision_iri
    assert (
        drift_by_iri[restaged.revision_iri].stale_resolution_state
        == "restaged_successor_ready"
    )
    assert drift_by_iri[restaged.revision_iri].is_current_staged_work is True
    assert (
        drift_by_iri[restaged.revision_iri].not_current_staged_work_reason is None
    )
    assert drift_by_iri[manual.revision_iri].record_kind == "history_record"
    assert drift_by_iri[manual.revision_iri].is_current_staged_work is False
    assert (
        drift_by_iri[manual.revision_iri].not_current_staged_work_reason
        == "history_record"
    )

    current_work_listing = db.list_graph_revisions(
        revision_type="rc:StagedRevision",
        current_staged_work_only=True,
    )
    assert current_work_listing.current_staged_work_only is True
    assert current_work_listing.include_apply_checks is True
    assert current_work_listing.returned_count == 1
    assert current_work_listing.total_count == 1
    assert [item.iri for item in current_work_listing.revisions] == [
        restaged.revision_iri
    ]

    ready_listing = db.list_graph_revisions(
        revision_type="rc:StagedRevision",
        application_status="ready",
        current_staged_work_only=True,
    )
    assert ready_listing.include_apply_checks is True
    assert ready_listing.application_status == "ready"
    assert ready_listing.current_staged_work_only is True
    assert [item.iri for item in ready_listing.revisions] == [restaged.revision_iri]

    stored_conforms_listing = db.list_graph_revisions(
        revision_type="rc:StagedRevision",
        staged_validation_status="conforms",
    )
    assert stored_conforms_listing.include_apply_checks is False
    assert stored_conforms_listing.staged_validation_status == "conforms"
    assert restaged.revision_iri in {
        item.iri for item in stored_conforms_listing.revisions
    }

    handled_listing = db.list_graph_revisions(
        revision_type="rc:StagedRevision",
        stale_resolution_state="stale_handled_by_restage",
    )
    assert handled_listing.include_apply_checks is True
    assert handled_listing.stale_resolution_state == "stale_handled_by_restage"
    assert [item.iri for item in handled_listing.revisions] == [stale.revision_iri]

    applied_events = db.list_graph_revisions(record_kind="applied_event")
    assert applied_events.record_kind == "applied_event"
    assert [item.iri for item in applied_events.revisions] == [
        applied.applied_revision_iri
    ]

    def page_counts(field_name: str, page) -> dict[str, int]:
        counts: dict[str, int] = {}
        for item in page.revisions:
            value = getattr(item, field_name)
            if value is None:
                continue
            counts[value] = counts.get(value, 0) + 1
        return counts

    def current_work_page_counts(field_name: str, page) -> dict[str, int]:
        counts: dict[str, int] = {}
        for item in page.revisions:
            if not item.is_current_staged_work:
                continue
            value = getattr(item, field_name)
            if value is None:
                continue
            counts[value] = counts.get(value, 0) + 1
        return counts

    def page_queue(page) -> dict[str, list[str]]:
        queues: dict[str, list[str]] = {}
        for item in page.revisions:
            if item.next_action is None:
                continue
            queues.setdefault(item.next_action.queue, []).append(item.iri)
        return queues

    def page_queue_item_counts(page) -> dict[str, int]:
        counts: dict[str, int] = {}
        for item in page.next_action_queue_items:
            counts[item.queue] = counts.get(item.queue, 0) + 1
        return counts

    def page_semantic_gate_counts(page) -> dict[str, int]:
        counts: dict[str, int] = {}
        for item in page.next_action_queue_items:
            if not item.alternative_semantic_review_required:
                continue
            counts[item.queue] = counts.get(item.queue, 0) + 1
        return counts

    full_page = db.list_graph_revisions(include_apply_checks=True)
    first_page = db.list_graph_revisions(
        include_apply_checks=True,
        limit=2,
        offset=0,
    )
    second_page = db.list_graph_revisions(
        include_apply_checks=True,
        limit=2,
        offset=2,
    )
    assert first_page.count == full_page.count
    assert second_page.count == full_page.count
    assert full_page.returned_count == len(full_page.revisions)
    assert full_page.total_count == full_page.count
    assert first_page.returned_count == 2
    assert first_page.total_count == full_page.count
    assert second_page.returned_count == 2
    assert second_page.total_count == full_page.count
    assert len(first_page.revisions) == 2
    assert len(second_page.revisions) == 2
    assert first_page.returned_application_status_counts == page_counts(
        "application_status",
        first_page,
    )
    assert first_page.returned_current_staged_work_application_status_counts == (
        current_work_page_counts(
            "application_status",
            first_page,
        )
    )
    assert first_page.returned_stale_resolution_state_counts == page_counts(
        "stale_resolution_state",
        first_page,
    )
    assert first_page.returned_staged_validation_status_counts == page_counts(
        "staged_validation_status",
        first_page,
    )
    assert first_page.next_action_queue == page_queue(first_page)
    assert first_page.next_action_queue_item_counts == page_queue_item_counts(
        first_page
    )
    assert first_page.semantic_review_required_queue_counts == (
        page_semantic_gate_counts(first_page)
    )
    assert second_page.returned_application_status_counts == page_counts(
        "application_status",
        second_page,
    )
    assert second_page.returned_current_staged_work_application_status_counts == (
        current_work_page_counts(
            "application_status",
            second_page,
        )
    )
    assert second_page.next_action_queue == page_queue(second_page)
    assert second_page.next_action_queue_item_counts == page_queue_item_counts(
        second_page
    )
    assert second_page.semantic_review_required_queue_counts == (
        page_semantic_gate_counts(second_page)
    )
    assert first_page.returned_application_status_counts != (
        full_page.returned_application_status_counts
    )
    assert first_page.next_action_queue != full_page.next_action_queue


def test_list_graph_versions_lists_stored_graph_timeline(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    staged = db.stage_graph_revision(
        summary="Stage messages table",
        rationale="Messages should become durable map context after review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    applied = db.apply_staged_revision(
        staged.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )

    versions = db.list_graph_versions("map")

    assert versions.graph_role == "map"
    assert versions.graph == "history"
    assert versions.exact_only is False
    assert versions.include_current is True
    assert versions.count == 2
    assert versions.total_count == 2
    assert versions.returned_count == 2
    assert versions.current_graph is not None
    assert versions.current_graph.graph_role == "map"
    assert versions.current_graph.triple_count == db.triple_count("map")
    assert versions.current_graph.content_digest == db._graph_content_digest("map")
    assert versions.snapshot_evidence_status_counts == {
        "history_plus_snapshot_rows": 2
    }
    assert versions.exact_snapshot_available_count == 2
    assert "not a temporal checkout engine" in versions.note

    rows_by_iri = {item.revision_iri: item for item in versions.versions}
    staged_row = rows_by_iri[staged.revision_iri]
    applied_row = rows_by_iri[applied.applied_revision_iri]

    assert staged_row.record_kind == "staged_patch"
    assert staged_row.snapshot_semantics == "staged_before_graph"
    assert staged_row.summary == "Stage messages table"
    assert staged_row.created_at == "2026-06-01T10:00:00+00:00"
    assert staged_row.changed_graphs == ["map"]
    assert staged_row.included_graphs == ["map"]
    assert staged_row.triple_count == 0
    assert staged_row.count_basis == "stored_snapshot_rows"
    assert staged_row.exact_snapshot_available is True
    assert staged_row.snapshot_evidence_status == "history_plus_snapshot_rows"
    assert staged_row.suggested_next_actions[0].tool_name == (
        "describe_revision_graph_snapshot"
    )
    assert staged_row.suggested_next_actions[1].tool_name == (
        "describe_graph_version_diff"
    )
    assert staged_row.suggested_next_actions[1].arguments == {
        "graph_role": "map",
        "before_revision_iri": staged.revision_iri,
        "compare_to_current": True,
    }

    assert applied_row.record_kind == "applied_event"
    assert applied_row.snapshot_semantics == "applied_after_graph"
    assert applied_row.created_at == "2026-06-01T10:01:00+00:00"
    assert applied_row.applies_staged_revision == staged.revision_iri
    assert applied_row.triple_count == db.triple_count("map")
    assert applied_row.exact_snapshot_available is True

    exact_staged = db.list_graph_versions(
        "map",
        exact_only=True,
        include_current=False,
        record_kind="staged_patch",
    )
    assert exact_staged.exact_only is True
    assert exact_staged.include_current is False
    assert exact_staged.record_kind == "staged_patch"
    assert exact_staged.current_graph is None
    assert [item.revision_iri for item in exact_staged.versions] == [
        staged.revision_iri
    ]

    first_page = db.list_graph_versions("map", limit=1, offset=0)
    second_page = db.list_graph_versions("map", limit=1, offset=1)
    assert first_page.count == 2
    assert first_page.returned_count == 1
    assert first_page.versions[0].revision_iri == applied.applied_revision_iri
    assert second_page.count == 2
    assert second_page.returned_count == 1
    assert second_page.versions[0].revision_iri == staged.revision_iri


def test_describe_graph_version_diff_compares_versions_and_current(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    first_staged = db.stage_graph_revision(
        summary="Stage messages table",
        rationale="Messages should become durable map context after review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Messages a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    first_applied = db.apply_staged_revision(
        first_staged.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    second_staged = db.stage_graph_revision(
        summary="Stage messages label and orders table",
        rationale="A later revision extends the map after the first snapshot.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Messages rdfs:label "Messages" .
                    ex:Orders a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:02:00Z",
    )
    second_applied = db.apply_staged_revision(
        second_staged.revision_iri,
        created_at="2026-06-01T10:03:00Z",
    )

    stored_diff = db.describe_graph_version_diff(
        "map",
        first_staged.revision_iri,
        after_revision_iri=first_applied.applied_revision_iri,
    )

    assert stored_diff.graph_role == "map"
    assert stored_diff.graph == "history"
    assert stored_diff.before_revision_iri == first_staged.revision_iri
    assert stored_diff.after_revision_iri == first_applied.applied_revision_iri
    assert stored_diff.compare_to_current is False
    assert stored_diff.after_target_kind == "stored_revision_snapshot"
    assert stored_diff.before_snapshot.triple_count == 0
    assert stored_diff.after_snapshot is not None
    assert stored_diff.after_snapshot.triple_count == 1
    assert stored_diff.current_graph is None
    assert stored_diff.count_basis == "target_graph_only"
    assert stored_diff.before_triple_count == 0
    assert stored_diff.after_triple_count == 1
    assert stored_diff.count_delta == 1
    assert stored_diff.digest_changed is True
    assert stored_diff.exact_changed_triples_available is True
    assert stored_diff.exact_changed_triples_included is False
    assert stored_diff.triples_added_count == 1
    assert stored_diff.triples_removed_count == 0
    assert stored_diff.triples_added_truncated is True
    assert stored_diff.triples_removed_truncated is False
    assert [action.tool_name for action in stored_diff.suggested_next_actions] == [
        "describe_revision_graph_snapshot",
        "describe_revision_graph_snapshot",
        "describe_graph_version_diff",
    ]

    current_diff = db.describe_graph_version_diff(
        "map",
        first_applied.applied_revision_iri,
        include_triples=True,
        max_triples=1,
    )

    assert current_diff.after_revision_iri is None
    assert current_diff.compare_to_current is True
    assert current_diff.after_target_kind == "current_graph"
    assert current_diff.before_snapshot.triple_count == 1
    assert current_diff.after_snapshot is None
    assert current_diff.current_graph is not None
    assert current_diff.current_graph.triple_count == db.triple_count("map")
    assert current_diff.after_triple_count == db.triple_count("map")
    assert current_diff.count_delta == 2
    assert current_diff.digest_changed is True
    assert current_diff.exact_changed_triples_available is True
    assert current_diff.exact_changed_triples_included is True
    assert current_diff.triples_added_count == 2
    assert current_diff.triples_removed_count == 0
    assert current_diff.triples_added_truncated is True
    assert current_diff.triples_removed_truncated is False
    assert current_diff.max_triples == 1
    assert len(current_diff.triples_added) == 1
    assert current_diff.triples_removed == []
    assert {triple.subject for triple in current_diff.triples_added} <= {
        "https://example.test/project#Messages",
        "https://example.test/project#Orders",
    }
    assert "Exact graph-version changed triples" in current_diff.note

    same_current_diff = db.describe_graph_version_diff(
        "map",
        second_applied.applied_revision_iri,
    )
    assert same_current_diff.count_delta == 0
    assert same_current_diff.digest_changed is False
    assert same_current_diff.triples_added_count == 0
    assert same_current_diff.triples_removed_count == 0
    assert [
        action.tool_name for action in same_current_diff.suggested_next_actions
    ] == ["describe_revision_graph_snapshot"]

    with pytest.raises(DoxaBaseError, match="after_revision_iri is required"):
        db.describe_graph_version_diff(
            "map",
            first_applied.applied_revision_iri,
            compare_to_current=False,
        )
    with pytest.raises(DoxaBaseError, match="max_triples must be at least 1"):
        db.describe_graph_version_diff(
            "map",
            first_applied.applied_revision_iri,
            max_triples=0,
        )


def test_describe_revision_lineage_summarizes_restage_and_apply_chain(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    first = db.stage_graph_revision(
        summary="Model order rows as raw events",
        rationale="Keep the raw event framing available for review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:OrderEvents a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    second = db.stage_graph_revision(
        summary="Model order rows as lifecycle entities",
        rationale="Keep the lifecycle entity framing available for review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:OrderLifecycles a rc:Dataset .
                """,
            }
        ],
        alternative_to=first.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    db.record_map_dataset(
        "https://example.test/project#DriftDataset",
        label="Drift dataset",
    )
    first_restaged = db.restage_staged_revision(first.revision_iri)
    second_restaged = db.restage_staged_revision(second.revision_iri)
    applied = db.apply_staged_revision(first_restaged.revision_iri)

    source_lineage = db.describe_revision_lineage(first.revision_iri)

    assert source_lineage.selected_role == "restaged_source"
    assert source_lineage.selected_revision_iri == first.revision_iri
    assert source_lineage.paired_revision is None
    assert source_lineage.paired_revision_iri is None
    assert source_lineage.applied_revision_iri == applied.applied_revision_iri
    assert source_lineage.staged_revision_iri == first.revision_iri
    assert source_lineage.applied_source_revision_iri == first_restaged.revision_iri
    assert source_lineage.current_staged_revision_iri is None
    assert source_lineage.current_revision_iri is None
    assert source_lineage.latest_revision_iri == applied.applied_revision_iri
    assert source_lineage.latest_role == "applied_event"
    assert source_lineage.restage_chain_iris == [
        first.revision_iri,
        first_restaged.revision_iri,
    ]
    assert second_restaged.revision_iri in source_lineage.alternative_revision_iris
    assert source_lineage.next_action is not None
    assert source_lineage.next_action.queue == "inspect_already_applied"
    assert source_lineage.next_action_queue_item is not None
    assert source_lineage.next_action_queue_item.row_iri == first.revision_iri
    assert (
        source_lineage.next_action_queue_item.resolved_target_iri
        == applied.applied_revision_iri
    )
    assert source_lineage.next_action_queue_item.row_is_target is False
    assert (
        source_lineage.next_action_queue_item.resolved_target_record_kind
        == "applied_event"
    )
    assert source_lineage.suggested_next_calls == [
        (
            "describe_graph_revision(iri='"
            f"{applied.applied_revision_iri}')"
        ),
        (
            "describe_applied_revision_diff(iri='"
            f"{applied.applied_revision_iri}')"
        ),
        (
            "describe_staged_revision(iri='"
            f"{first_restaged.revision_iri}')"
        ),
    ]
    assert source_lineage.warnings == []

    staged_lineage = db.describe_revision_lineage(first_restaged.revision_iri)

    assert staged_lineage.selected_role == "applied_source"
    assert staged_lineage.selected_revision_iri == first_restaged.revision_iri
    assert staged_lineage.paired_revision is not None
    assert staged_lineage.paired_revision.iri == applied.applied_revision_iri
    assert staged_lineage.paired_revision_iri == applied.applied_revision_iri
    assert staged_lineage.paired_role == "applied_event"
    assert staged_lineage.staged_revision_iri == first_restaged.revision_iri
    assert staged_lineage.applied_source_revision_iri == first_restaged.revision_iri
    assert staged_lineage.applied_revision_iri == applied.applied_revision_iri

    applied_lineage = db.describe_revision_lineage(applied.applied_revision_iri)

    assert applied_lineage.selected_role == "applied_event"
    assert applied_lineage.selected_revision_iri == applied.applied_revision_iri
    assert applied_lineage.paired_revision is not None
    assert applied_lineage.paired_revision.iri == first_restaged.revision_iri
    assert applied_lineage.paired_revision_iri == first_restaged.revision_iri
    assert applied_lineage.paired_role == "applied_source"
    assert applied_lineage.applied_source_revision_iri == first_restaged.revision_iri
    assert applied_lineage.restage_chain_iris == [
        first.revision_iri,
        first_restaged.revision_iri,
    ]
    assert applied_lineage.suggested_next_calls == [
        (
            "describe_graph_revision(iri='"
            f"{applied.applied_revision_iri}')"
        ),
        (
            "describe_applied_revision_diff(iri='"
            f"{applied.applied_revision_iri}')"
        ),
        (
            "describe_staged_revision(iri='"
            f"{first_restaged.revision_iri}')"
        ),
    ]

    active_lineage = db.describe_revision_lineage(second_restaged.revision_iri)

    assert active_lineage.selected_role == "current_staged_revision"
    assert active_lineage.current_staged_revision_iri == second_restaged.revision_iri
    assert active_lineage.current_revision_iri == second_restaged.revision_iri
    assert active_lineage.applied_revision_iri is None
    assert active_lineage.applied_source_revision_iri is None
    assert active_lineage.latest_revision_iri == second_restaged.revision_iri
    assert active_lineage.next_action is not None
    assert active_lineage.next_action.queue == "restage_after_review"
    assert active_lineage.restage_chain_iris == [
        second.revision_iri,
        second_restaged.revision_iri,
    ]
    assert applied.applied_revision_iri in active_lineage.related_revision_iris


def test_describe_revision_lineage_warns_about_imported_odd_history(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    source_iri = "https://example.test/project#ambiguous-source"
    successor_a_iri = "https://example.test/project#ambiguous-a-successor"
    successor_z_iri = "https://example.test/project#ambiguous-z-successor"
    manual_iri = "https://example.test/project#manual-restage-note"
    parallel_applied_iri = "https://example.test/project#parallel-applied-event"
    missing_source_iri = "https://example.test/project#missing-applied-source"
    applied_iri = "https://example.test/project#applied-event-missing-source"
    source_dataset_iri = "https://example.test/project#SourceDataset"

    source = db.stage_graph_revision(
        summary="Source proposal",
        rationale="Keep an imported-lineage source available.",
        revision_iri=source_iri,
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:SourceDataset a rc:Dataset .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    successor_a = db.stage_graph_revision(
        summary="First successor",
        rationale="Caller-authored restage successor A.",
        revision_iri=successor_a_iri,
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:SuccessorA a rc:Dataset .
                """,
            }
        ],
        restages_revision=source.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    db.import_turtle(
        f"""
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .

        <{successor_z_iri}> a rc:GraphRevision ;
            rc:summary "Imported parallel successor" ;
            rc:revisionType rc:StagedRevision ;
            rc:hasGraphPatch ex:ambiguousZPatch ;
            rc:restagesRevision <{source.revision_iri}> ;
            rc:createdAt "2026-06-01T10:02:00Z" .

        ex:ambiguousZPatch a rc:GraphPatch .

        <{manual_iri}> a rc:GraphRevision ;
            rc:summary "Manual restage note" ;
            rc:revisionType rc:ManualRevision ;
            rc:restagesRevision <{successor_a.revision_iri}> ;
            rc:createdAt "2026-06-01T10:03:00Z" .

        <{parallel_applied_iri}> a rc:GraphRevision ;
            rc:summary "Applied parallel successor" ;
            rc:revisionType rc:AppliedStagedRevision ;
            rc:appliesStagedRevision <{successor_z_iri}> ;
            rc:createdAt "2026-06-01T10:03:30Z" .

        <{applied_iri}> a rc:GraphRevision ;
            rc:summary "Applied event missing source" ;
            rc:revisionType rc:AppliedStagedRevision ;
            rc:appliesStagedRevision <{missing_source_iri}> ;
            rc:createdAt "2026-06-01T10:04:00Z" .
        """,
        graph="history",
    )

    source_lineage = db.describe_revision_lineage(source.revision_iri)

    assert source_lineage.restage_chain_iris == [
        source.revision_iri,
        successor_a.revision_iri,
        manual_iri,
    ]
    assert {
        successor_a.revision_iri,
        successor_z_iri,
        manual_iri,
        parallel_applied_iri,
    }.issubset(set(source_lineage.related_revision_iris))
    assert any(
        "multiple visible successors" in warning
        and successor_a.revision_iri in warning
        and successor_z_iri in warning
        for warning in source_lineage.warnings
    )
    assert any(
        "non-staged revision" in warning
        and manual_iri in warning
        and "history_record" in warning
        for warning in source_lineage.warnings
    )
    resource_lineage = db.describe_resource_revision_lineage(
        source_dataset_iri,
        source.revision_iri,
    )
    assert {
        successor_a.revision_iri,
        successor_z_iri,
        manual_iri,
        parallel_applied_iri,
    }.issubset(set(resource_lineage.related_revision_iris))
    assert any(
        "multiple visible successors" in warning
        and successor_a.revision_iri in warning
        and successor_z_iri in warning
        for warning in resource_lineage.warnings
    )
    export = db.export_staged_revisions(
        [source.revision_iri],
        tmp_path / "parallel-successor-review.md",
    )
    assert parallel_applied_iri in (
        export.bundle_summary.recommended_applied_inspection_iris
    )
    assert any(
        "Parallel restage successor" in warning
        and successor_z_iri in warning
        and parallel_applied_iri in warning
        for warning in export.bundle_summary.warnings
    )

    missing_source_lineage = db.describe_revision_lineage(applied_iri)

    assert missing_source_lineage.selected_role == "applied_event"
    assert missing_source_lineage.applied_revision_iri == applied_iri
    assert missing_source_lineage.staged_revision_iri is None
    assert missing_source_lineage.restage_chain_iris == []
    assert any(
        "points to missing staged source" in warning
        and missing_source_iri in warning
        for warning in missing_source_lineage.warnings
    )


def test_list_resource_revisions_finds_anchors_patches_and_applied_sources(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    other = "https://example.test/project#OtherOrders"
    db.record_map_dataset(orders, label="Orders", is_table=True)

    anchored = db.stage_graph_revision(
        summary="Classify Orders as current table",
        rationale="Anchor and patch should both mention Orders.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders a rc:Table .
                """,
            }
        ],
        revision_anchors=[orders],
        created_at="2026-06-01T10:00:00Z",
    )
    unanchored = db.stage_graph_revision(
        summary="Add Orders stewardship note",
        rationale="Patch touches Orders without an explicit revision anchor.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Owned by the operations team." .
                """,
            }
        ],
        created_at="2026-06-01T10:01:00Z",
    )
    applied = db.apply_staged_revision(
        unanchored.revision_iri,
        created_at="2026-06-01T10:02:00Z",
    )
    unrelated = db.stage_graph_revision(
        summary="Add unrelated table",
        rationale="This proposal should not appear in the Orders resource list.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:OtherOrders a rc:Dataset .
                """,
            }
        ],
        revision_anchors=[other],
        created_at="2026-06-01T10:03:00Z",
    )

    listing = db.list_resource_revisions(orders)

    assert listing.resource.iri == orders
    assert listing.include_patch_mentions is True
    assert listing.patch_mention_scan.status == "complete"
    assert listing.patch_mention_scan.unreadable_patch_count == 0
    assert listing.patch_mention_scan.unreadable_revision_count == 0
    assert listing.patch_mention_scan.omitted_match_risk is False
    assert listing.include_apply_checks is True
    assert listing.count == 3
    by_iri = {item.revision.iri: item for item in listing.revisions}
    assert {item.revision_iri for item in listing.revisions} == set(by_iri)
    assert set(by_iri) == {
        anchored.revision_iri,
        unanchored.revision_iri,
        applied.applied_revision_iri,
    }
    assert unrelated.revision_iri not in by_iri

    anchored_item = by_iri[anchored.revision_iri]
    assert anchored_item.revision_anchor_match is True
    assert anchored_item.patch_mention_match is True
    assert anchored_item.match_types == ["revision_anchor", "patch_subject"]
    assert anchored_item.patch_mentions[0].matched_term_roles == ["subject"]
    assert anchored_item.patch_mentions[0].matched_triples == 1
    assert anchored_item.patch_mentions[0].triple_count == 1
    assert anchored_item.patch_mentions_incomplete is False
    assert anchored_item.patch_mentions_unreadable_count == 0
    assert anchored_item.revision.application_status == "conflict"
    assert anchored_item.revision.stale_resolution_state == "stale_unresolved"

    unanchored_item = by_iri[unanchored.revision_iri]
    assert unanchored_item.revision_anchor_match is False
    assert unanchored_item.patch_mention_match is True
    assert unanchored_item.match_types == ["patch_subject"]
    assert unanchored_item.revision.application_status == "already_applied"

    applied_item = by_iri[applied.applied_revision_iri]
    assert applied_item.revision.record_kind == "applied_event"
    assert applied_item.applied_source_match is True
    assert applied_item.applied_source_revision_iri == unanchored.revision_iri
    assert applied_item.match_types == ["applied_source_patch_subject"]
    assert applied_item.applied_source_patch_mentions[0].target_graph == "map"
    assert applied_item.applied_source_patch_mentions[0].matched_triples == 1
    assert applied_item.applied_source_patch_mentions_incomplete is False
    assert applied_item.applied_source_patch_mentions_unreadable_count == 0
    lineage = db.describe_resource_revision_lineage(
        orders,
        applied.applied_revision_iri,
        include_triples=True,
    )
    assert lineage.resource.iri == orders
    assert lineage.selected_revision.revision.iri == applied.applied_revision_iri
    assert lineage.selected_revision_iri == applied.applied_revision_iri
    assert lineage.selected_role == "applied_event"
    assert lineage.paired_revision is not None
    assert lineage.paired_revision.revision.iri == unanchored.revision_iri
    assert lineage.paired_revision_iri == unanchored.revision_iri
    assert lineage.paired_role == "applied_source"
    assert lineage.applied_revision_iri == applied.applied_revision_iri
    assert lineage.staged_revision_iri == unanchored.revision_iri
    assert lineage.current_staged_revision_iri is None
    assert lineage.current_revision_iri is None
    assert lineage.latest_revision_iri == applied.applied_revision_iri
    assert lineage.latest_role == "applied_event"
    assert lineage.restage_chain_iris == [unanchored.revision_iri]
    assert lineage.alternative_revision_iris == []
    assert lineage.related_revision_iris == [
        applied.applied_revision_iri,
        unanchored.revision_iri,
    ]
    assert lineage.patch_mention_scan.status == "complete"
    assert lineage.applied_diff_status == "available"
    assert lineage.applied_diff is not None
    assert lineage.applied_diff.changed_graphs == ["map"]
    assert lineage.applied_diff.include_triples is True
    map_diff = lineage.applied_diff.graph_diffs[0]
    assert map_diff.graph_role == "map"
    assert map_diff.count_basis == "target_graph_only"
    assert map_diff.exact_changed_triples_available is True
    assert map_diff.exact_changed_triples_included is True
    assert map_diff.resource_triples_added_count == 1
    assert map_diff.resource_triples_removed_count == 0
    assert map_diff.resource_triples_added[0].subject == orders
    assert map_diff.resource_triples_added_truncated is False

    source_lineage = db.describe_resource_revision_lineage(
        orders,
        unanchored.revision_iri,
        include_applied_diff=False,
    )
    assert source_lineage.selected_role == "applied_source"
    assert source_lineage.selected_revision_iri == unanchored.revision_iri
    assert source_lineage.paired_revision is not None
    assert source_lineage.paired_revision.revision.iri == applied.applied_revision_iri
    assert source_lineage.paired_revision_iri == applied.applied_revision_iri
    assert source_lineage.latest_revision_iri == applied.applied_revision_iri
    assert source_lineage.latest_role == "applied_event"
    assert source_lineage.next_action_queue_item is not None
    assert source_lineage.next_action_queue_item.row_iri == unanchored.revision_iri
    assert (
        source_lineage.next_action_queue_item.resolved_target_iri
        == applied.applied_revision_iri
    )
    assert source_lineage.next_action_queue_item.row_is_target is False
    assert (
        source_lineage.next_action_queue_item.resolved_target_record_kind
        == "applied_event"
    )
    assert source_lineage.applied_diff_status == "omitted"
    assert source_lineage.applied_diff is None

    anchor_only = db.list_resource_revisions(orders, include_patch_mentions=False)
    assert anchor_only.patch_mention_scan.status == "not_requested"
    assert anchor_only.patch_mention_scan.unreadable_patch_count == 0
    assert anchor_only.patch_mention_scan.omitted_match_risk is False
    assert anchor_only.count == 1
    assert anchor_only.revisions[0].revision.iri == anchored.revision_iri
    assert anchor_only.revisions[0].match_types == ["revision_anchor"]


def test_resource_revision_lineage_tracks_current_restage_successor(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    original = db.stage_graph_revision(
        summary="Classify Orders as dataset",
        rationale="Exercise resource lineage across restage and apply.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders a rc:Dataset .
                """,
            }
        ],
        revision_anchors=[orders],
        created_at="2026-06-01T10:00:00Z",
    )
    db.record_map_dataset(
        "https://example.test/project#DriftMaker",
        label="Drift maker",
    )
    restaged = db.restage_staged_revision(
        original.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )

    stale_lineage = db.describe_resource_revision_lineage(
        orders,
        original.revision_iri,
    )
    assert stale_lineage.selected_role == "restaged_source"
    assert stale_lineage.applied_revision_iri is None
    assert stale_lineage.applied_source_revision_iri is None
    assert stale_lineage.current_staged_revision_iri == restaged.revision_iri
    assert stale_lineage.current_revision_iri == restaged.revision_iri
    assert stale_lineage.latest_revision_iri == restaged.revision_iri
    assert stale_lineage.latest_role == "current_staged_revision"
    assert stale_lineage.restage_chain_iris == [
        original.revision_iri,
        restaged.revision_iri,
    ]
    assert stale_lineage.alternative_revision_iris == []
    assert stale_lineage.related_revision_iris == [
        original.revision_iri,
        restaged.revision_iri,
    ]
    current_resource_lineage = db.describe_resource_revision_lineage(
        orders,
        restaged.revision_iri,
    )
    assert current_resource_lineage.selected_role == "current_staged_revision"
    assert current_resource_lineage.applied_revision_iri is None
    assert current_resource_lineage.applied_source_revision_iri is None
    current_graph_lineage = db.describe_revision_lineage(restaged.revision_iri)
    assert current_graph_lineage.applied_revision_iri is None
    assert current_graph_lineage.applied_source_revision_iri is None

    applied = db.apply_staged_revision(
        restaged.revision_iri,
        created_at="2026-06-01T10:02:00Z",
    )
    applied_source_lineage = db.describe_resource_revision_lineage(
        orders,
        original.revision_iri,
    )
    assert applied_source_lineage.selected_role == "restaged_source"
    assert applied_source_lineage.current_staged_revision_iri is None
    assert applied_source_lineage.current_revision_iri is None
    assert applied_source_lineage.latest_revision_iri == applied.applied_revision_iri
    assert applied_source_lineage.latest_role == "applied_event"
    assert applied_source_lineage.applied_revision_iri == applied.applied_revision_iri
    assert applied_source_lineage.staged_revision_iri == restaged.revision_iri
    assert applied_source_lineage.applied_source_revision_iri == (
        restaged.revision_iri
    )
    assert applied_source_lineage.restage_chain_iris == [
        original.revision_iri,
        restaged.revision_iri,
    ]
    assert applied_source_lineage.related_revision_iris == [
        original.revision_iri,
        applied.applied_revision_iri,
        restaged.revision_iri,
    ]
    assert applied_source_lineage.next_action is not None
    assert applied_source_lineage.next_action.action_type == (
        "inspect_applied_event"
    )
    assert applied_source_lineage.next_action_queue_item is not None
    assert (
        applied_source_lineage.next_action_queue_item.row_iri
        == original.revision_iri
    )
    assert (
        applied_source_lineage.next_action_queue_item.resolved_target_iri
        == applied.applied_revision_iri
    )
    assert applied_source_lineage.next_action_queue_item.row_is_target is False
    assert applied_source_lineage.next_action.arguments == {
        "iri": applied.applied_revision_iri,
    }
    assert [
        action.tool_name for action in applied_source_lineage.suggested_next_actions
    ][:3] == [
        "describe_graph_revision",
        "describe_applied_revision_diff",
        "describe_staged_revision",
    ]
    assert applied_source_lineage.suggested_next_calls[0] == (
        "describe_graph_revision("
        f"iri={applied.applied_revision_iri!r})"
    )
    assert applied_source_lineage.applied_diff_status == "available"
    assert applied_source_lineage.applied_diff is not None
    assert applied_source_lineage.applied_diff.applied_revision_iri == (
        applied.applied_revision_iri
    )
    assert applied_source_lineage.applied_diff.staged_revision_iri == (
        restaged.revision_iri
    )
    assert applied_source_lineage.applied_diff.changed_graphs == ["map"]
    assert (
        applied_source_lineage.applied_diff.graph_diffs[0].resource_triples_added_count
        == 1
    )
    applied_event_lineage = db.describe_resource_revision_lineage(
        orders,
        applied.applied_revision_iri,
    )
    assert applied_event_lineage.restage_chain_iris == [
        original.revision_iri,
        restaged.revision_iri,
    ]
    assert applied_event_lineage.latest_revision_iri == applied.applied_revision_iri
    assert applied_event_lineage.latest_role == "applied_event"
    assert applied_event_lineage.suggested_next_calls == [
        (
            "describe_graph_revision("
            f"iri={applied.applied_revision_iri!r})"
        ),
        (
            "describe_applied_revision_diff("
            f"iri={applied.applied_revision_iri!r})"
        )
    ]
    assert applied_event_lineage.related_revision_iris == [
        applied.applied_revision_iri,
        restaged.revision_iri,
        original.revision_iri,
    ]


def test_list_resource_revisions_recovers_imported_applied_source_anchors(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    source_iri = "https://example.test/project#ImportedStagedSource"
    applied_iri = "https://example.test/project#ImportedAppliedEvent"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    db.record_graph_revision(
        summary="Imported staged source with anchors only",
        rationale="Imported handoff preserved anchors but omitted patch payloads.",
        changed_graphs=["map"],
        revision_type="rc:StagedRevision",
        revision_iri=source_iri,
        revision_anchors=[orders],
        created_at="2026-06-01T10:00:00Z",
    )
    db.import_trig(
        f"""
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .
        @prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

        GRAPH <https://richcanopy.org/graph/history> {{
            ex:ImportedAppliedEvent a rc:GraphRevision ;
                rc:revisionType rc:AppliedStagedRevision ;
                rc:summary "Imported applied event" ;
                rc:revisionRationale "Applied an imported staged source." ;
                rc:changedGraph "map" ;
                rc:createdAt "2026-06-01T10:01:00Z"^^xsd:dateTime ;
                rc:appliesStagedRevision <{source_iri}> .
        }}
        """
    )

    listing = db.list_resource_revisions(orders)

    assert listing.patch_mention_scan.status == "complete"
    assert listing.patch_mention_scan.omitted_match_risk is False
    by_iri = {item.revision.iri: item for item in listing.revisions}
    assert set(by_iri) == {source_iri, applied_iri}
    source_item = by_iri[source_iri]
    assert source_item.revision_anchor_match is True
    assert source_item.match_types == ["revision_anchor"]
    applied_item = by_iri[applied_iri]
    assert applied_item.revision.record_kind == "applied_event"
    assert applied_item.applied_source_match is True
    assert applied_item.applied_source_revision_iri == source_iri
    assert applied_item.match_types == ["applied_source_revision_anchor"]
    assert applied_item.applied_source_patch_mentions == []
    assert applied_item.applied_source_patch_mentions_incomplete is False
    assert applied_item.applied_source_patch_mentions_unreadable_count == 0
    lineage = db.describe_resource_revision_lineage(orders, applied_iri)
    assert lineage.selected_revision.revision.iri == applied_iri
    assert lineage.selected_role == "applied_event"
    assert lineage.paired_revision is not None
    assert lineage.paired_revision.revision.iri == source_iri
    assert lineage.paired_role == "applied_source"
    assert lineage.applied_revision_iri == applied_iri
    assert lineage.staged_revision_iri == source_iri
    assert lineage.applied_source_revision_iri == source_iri
    assert lineage.applied_diff_status == "unavailable"
    assert lineage.applied_diff is not None
    assert lineage.applied_diff.graph_diffs[0].exact_changed_triples_available is False

    without_patch_mentions = db.list_resource_revisions(
        orders,
        include_patch_mentions=False,
    )
    assert {
        item.revision.iri: item.match_types
        for item in without_patch_mentions.revisions
    } == {
        source_iri: ["revision_anchor"],
        applied_iri: ["applied_source_revision_anchor"],
    }
    patch_only = db.stage_graph_revision(
        summary="Unanchored Orders patch",
        rationale="Patch payload mentions Orders without anchoring it.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders rc:hasKnownCaveat ex:OrdersPatchOnlyCaveat .
                """,
            }
        ],
    )
    with_patch_mentions = db.describe_resource_revision_lineage(
        orders,
        patch_only.revision_iri,
    )
    assert (
        with_patch_mentions.selected_revision.revision.iri
        == patch_only.revision_iri
    )
    assert with_patch_mentions.selected_revision.match_types == ["patch_subject"]
    with pytest.raises(DoxaBaseError) as disabled_scan_excinfo:
        db.describe_resource_revision_lineage(
            orders,
            patch_only.revision_iri,
            include_patch_mentions=False,
        )
    disabled_scan_message = str(disabled_scan_excinfo.value)
    assert "patch payload scanning was disabled" in disabled_scan_message
    assert "include_patch_mentions=True" in disabled_scan_message
    assert "Revision exists in history" in disabled_scan_message


def test_list_resource_revisions_filters_current_staged_work_before_pagination(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    stale = db.stage_graph_revision(
        summary="Add Orders stewardship note",
        rationale="Patch-only source exercises resource live-work filtering.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Owned by the operations team." .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    db.record_map_dataset(
        "https://example.test/project#DriftMaker",
        label="Drift maker",
    )
    restaged = db.restage_staged_revision(
        stale.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )

    full_listing = db.list_resource_revisions(
        orders,
        include_apply_checks=True,
        limit=1,
        offset=0,
    )
    assert full_listing.count == 2
    assert len(full_listing.revisions) == 1
    assert full_listing.revisions[0].revision.iri == restaged.revision_iri

    live_listing = db.list_resource_revisions(
        orders,
        include_apply_checks=False,
        current_staged_work_only=True,
        limit=1,
        offset=0,
    )

    assert live_listing.current_staged_work_only is True
    assert live_listing.include_apply_checks is True
    assert live_listing.count == 1
    assert [item.revision.iri for item in live_listing.revisions] == [
        restaged.revision_iri
    ]
    assert live_listing.revisions[0].revision.is_current_staged_work is True
    assert live_listing.revisions[0].revision.application_status == "ready"
    assert live_listing.next_action_queue == {
        "apply_after_review": [restaged.revision_iri]
    }

    stale_lineage = db.describe_resource_revision_lineage(
        orders,
        stale.revision_iri,
    )
    assert stale_lineage.current_revision_iri == restaged.revision_iri
    assert stale_lineage.latest_revision_iri == restaged.revision_iri
    assert stale_lineage.latest_role == "current_staged_revision"

    hidden_patch_only_live_work = db.list_resource_revisions(
        orders,
        include_patch_mentions=False,
        current_staged_work_only=True,
    )
    assert hidden_patch_only_live_work.count == 0
    assert hidden_patch_only_live_work.patch_mention_scan.status == "not_requested"


def test_list_resource_revisions_filters_noisy_patch_only_current_work(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    applied_source = db.stage_graph_revision(
        summary="Add applied Orders note",
        rationale="Creates historical patch-only rows for the resource family.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Historical applied note." .
                """,
            }
        ],
        created_at="2026-06-01T10:00:00Z",
    )
    applied_source_event = db.apply_staged_revision(
        applied_source.revision_iri,
        created_at="2026-06-01T10:01:00Z",
    )
    stale_simple = db.stage_graph_revision(
        summary="Add current Orders note",
        rationale="Patch-only current work should survive live-work filtering.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Current operations note." .
                """,
            }
        ],
        created_at="2026-06-01T10:02:00Z",
    )
    applied_alternative = db.stage_graph_revision(
        summary="Model Orders as event rows",
        rationale="First semantic alternative for review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Event-row interpretation." .
                """,
            }
        ],
        created_at="2026-06-01T10:03:00Z",
    )
    stale_alternative = db.stage_graph_revision(
        summary="Model Orders as snapshot rows",
        rationale="Competing semantic alternative for review.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders rdfs:comment "Snapshot-row interpretation." .
                """,
            }
        ],
        alternative_to=applied_alternative.revision_iri,
        created_at="2026-06-01T10:04:00Z",
    )
    applied_alternative_event = db.apply_staged_revision(
        applied_alternative.revision_iri,
        created_at="2026-06-01T10:05:00Z",
    )
    simple_current = db.restage_staged_revision(
        stale_simple.revision_iri,
        created_at="2026-06-01T10:06:00Z",
    )
    semantic_current = db.restage_staged_revision(
        stale_alternative.revision_iri,
        created_at="2026-06-01T10:07:00Z",
    )
    manual_history = db.record_graph_revision(
        summary="Manual Orders review note",
        rationale="Newest anchored non-staged history should not enter live work.",
        changed_graphs=["map"],
        revision_anchors=[orders],
        created_at="2026-06-01T10:08:00Z",
    )

    full_page = db.list_resource_revisions(
        orders,
        include_apply_checks=True,
        limit=1,
        offset=0,
    )
    assert full_page.count == 9
    assert full_page.returned_count == 1
    assert full_page.total_count == 9
    assert full_page.revisions[0].revision.iri == manual_history.revision_iri
    full_listing = db.list_resource_revisions(
        orders,
        include_apply_checks=True,
    )
    by_iri = {item.revision.iri: item for item in full_listing.revisions}
    assert by_iri[manual_history.revision_iri].revision.record_kind == (
        "history_record"
    )
    assert by_iri[applied_source.revision_iri].revision.application_status == (
        "already_applied"
    )
    assert by_iri[applied_source_event.applied_revision_iri].revision.record_kind == (
        "applied_event"
    )
    assert by_iri[stale_simple.revision_iri].revision.stale_resolution_state == (
        "stale_handled_by_restage"
    )
    assert by_iri[stale_alternative.revision_iri].revision.stale_resolution_state == (
        "stale_handled_by_restage"
    )

    live_listing = db.list_resource_revisions(
        orders,
        include_apply_checks=False,
        current_staged_work_only=True,
    )
    assert live_listing.current_staged_work_only is True
    assert live_listing.include_apply_checks is True
    assert live_listing.count == 2
    assert live_listing.returned_count == 2
    assert live_listing.total_count == 2
    assert [item.revision.iri for item in live_listing.revisions] == [
        semantic_current.revision_iri,
        simple_current.revision_iri,
    ]
    assert [item.match_types for item in live_listing.revisions] == [
        ["patch_subject"],
        ["patch_subject"],
    ]
    assert all(
        item.revision.is_current_staged_work for item in live_listing.revisions
    )
    assert live_listing.next_action_queue == {
        "apply_after_review": [
            semantic_current.revision_iri,
            simple_current.revision_iri,
        ]
    }
    semantic_queue_item = next(
        item
        for item in live_listing.next_action_queue_items
        if item.row_iri == semantic_current.revision_iri
    )
    assert semantic_queue_item.row_is_target is True
    assert semantic_queue_item.resolved_target_iri == semantic_current.revision_iri
    assert semantic_queue_item.alternative_semantic_review_required is True
    assert semantic_queue_item.alternative_applied_source_iri == (
        applied_alternative.revision_iri
    )
    assert semantic_queue_item.alternative_applied_revision_iri == (
        applied_alternative_event.applied_revision_iri
    )

    first_live_page = db.list_resource_revisions(
        orders,
        current_staged_work_only=True,
        limit=1,
        offset=0,
    )
    second_live_page = db.list_resource_revisions(
        orders,
        current_staged_work_only=True,
        limit=1,
        offset=1,
    )
    assert first_live_page.count == 2
    assert second_live_page.count == 2
    assert first_live_page.returned_count == 1
    assert first_live_page.total_count == 2
    assert second_live_page.returned_count == 1
    assert second_live_page.total_count == 2
    assert first_live_page.revisions[0].revision.iri == semantic_current.revision_iri
    assert second_live_page.revisions[0].revision.iri == simple_current.revision_iri

    hidden_patch_only_live_work = db.list_resource_revisions(
        orders,
        include_patch_mentions=False,
        current_staged_work_only=True,
    )
    assert hidden_patch_only_live_work.count == 0
    assert hidden_patch_only_live_work.patch_mention_scan.status == "not_requested"


def test_list_resource_revisions_marks_unreadable_patch_mentions_incomplete(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    orders = "https://example.test/project#Orders"
    db.record_map_dataset(orders, label="Orders", is_table=True)
    staged = db.stage_graph_revision(
        summary="Malformed anchored patch for Orders",
        rationale="Anchor keeps the revision discoverable despite bad patch RDF.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders a rc:Table .
                """,
            }
        ],
        revision_anchors=[orders],
    )
    _corrupt_staged_patch_content(
        db,
        staged.patches[0].patch_iri,
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .

        ex:Orders a rc:Table
        ex:Other a rc:Dataset .
        """,
    )
    unanchored = db.stage_graph_revision(
        summary="Malformed unanchored patch for Orders",
        rationale="Only patch parsing could reveal whether this mentions Orders.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:Orders rc:hasColumn ex:OrdersStatus .
                """,
            }
        ],
    )
    _corrupt_staged_patch_content(
        db,
        unanchored.patches[0].patch_iri,
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .

        ex:Orders rc:hasColumn ex:OrdersStatus
        ex:Other a rc:Dataset .
        """,
    )

    listing = db.list_resource_revisions(orders)

    assert listing.patch_mention_scan.status == "incomplete"
    assert listing.patch_mention_scan.unreadable_patch_count == 2
    assert listing.patch_mention_scan.unreadable_revision_count == 2
    assert listing.patch_mention_scan.omitted_match_risk is True
    assert listing.count == 1
    item = listing.revisions[0]
    assert item.revision.iri == staged.revision_iri
    assert item.match_types == ["revision_anchor"]
    assert item.patch_mentions == []
    assert item.patch_mentions_incomplete is True
    assert item.patch_mentions_unreadable_count == 1
    with pytest.raises(DoxaBaseError) as excinfo:
        db.describe_resource_revision_lineage(orders, unanchored.revision_iri)
    message = str(excinfo.value)
    assert "was not found in resource lineage" in message
    assert "Resource patch mention scan was incomplete" in message
    assert "unreadable_patch_count=2" in message
    assert "unreadable_revision_count=2" in message
    assert "omitted_match_risk=True" in message


def test_apply_check_reports_validation_failed_status(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    staged = db.stage_graph_revision(
        summary="Stage invalid value type",
        rationale="Exercise apply-check status for a clean patch with SHACL errors.",
        additions=[
            {
                "graph": "ontology",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:BadValueType a rc:ValueType ;
                        rc:requiredPhysicalType "VARCHAR" .
                """,
            }
        ],
        validation_scope="all",
    )

    check = db.check_staged_revision_apply(staged.revision_iri)
    assert check.can_apply is False
    assert check.status == "validation_failed"
    assert check.decision == "inspect_validation_results"
    assert check.review_recommended is False
    assert check.blocking_reasons == ["validation_failed"]
    assert check.recommended_resolution is not None
    assert "validation_results" in check.recommended_resolution
    assert check.conflicts == []
    assert check.validation_conforms is False
    assert check.validation_skipped_reason is None
    assert check.validation_results
    assert check.summary == (
        "Patch counts replay cleanly, but preview validation failed with "
        f"{check.validation_result_count} result(s)."
    )
    assert check.next_action is not None
    assert check.next_action.queue == "repair_or_replace"
    assert check.next_action.tool_name == "draft_staged_revision_rebase"
    assert [action.tool_name for action in check.suggested_next_actions] == [
        "draft_staged_revision_rebase",
        "describe_staged_revision",
        "export_staged_revision",
    ]
    assert "read-only repair/rebase plan" in check.suggested_next_actions[0].reason
    assert "stage a repaired" in check.suggested_next_actions[1].reason
    assert "validation-failed" in check.suggested_next_actions[2].arguments["path"]
    description = db.describe_staged_revision(
        staged.revision_iri,
        include_current_apply_check=True,
    )
    assert description.current_apply_check is not None
    validation_summary = description.current_apply_check
    assert validation_summary.status == "validation_failed"
    assert validation_summary.decision == "inspect_validation_results"
    assert validation_summary.validation_conforms is False
    assert validation_summary.validation_result_count == check.validation_result_count
    assert validation_summary.next_action is not None
    assert validation_summary.next_action.action_type == "repair_or_replace"
    assert validation_summary.next_action.queue == "repair_or_replace"
    assert validation_summary.next_action.arguments == {
        "iri": staged.revision_iri,
        "validation_scope": "all",
    }
    assert validation_summary.suggested_next_actions[0].tool_name == (
        "draft_staged_revision_rebase"
    )
    assert validation_summary.error is None

    export = db.export_staged_revisions(
        [staged.revision_iri],
        tmp_path / "validation-failed-review.md",
    )
    assert export.bundle_summary.validation_failed_revision_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.staged_validation_failed_revision_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.post_apply_recheck_revision_iris == []
    assert export.bundle_summary.recommended_mutation_review_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.recommended_apply_or_restage_review_iris == []
    assert export.bundle_summary.recommended_repair_review_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.recommended_applied_inspection_iris == []
    assert export.revision_summaries[0].apply_recommended_resolution is not None
    assert (
        export.revision_summaries[0].apply_recommendation_scope
        == "current_apply_check"
    )
    assert "validation_results" in (
        export.revision_summaries[0].apply_recommended_resolution
    )
    assert export.revision_summaries[0].summary_recommendation == (
        export.revision_summaries[0].apply_recommended_resolution
    )
    assert (
        export.revision_summaries[0].summary_recommendation_source
        == "apply_recommended_resolution"
    )
    exported = (tmp_path / "validation-failed-review.md").read_text(
        encoding="utf-8"
    )
    assert "Inspect validation_results" in exported

    with pytest.raises(
        DoxaBaseError,
        match="Applying staged revision would fail",
    ) as excinfo:
        db.apply_staged_revision(staged.revision_iri)
    error = str(excinfo.value)
    assert staged.revision_iri in error
    assert "describe_staged_revision(" in error
    assert "include_current_apply_check=True" in error


def test_staged_row_semantics_validation_hint_guides_clean_recipe(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    bad = db.stage_graph_revision(
        summary="Stage prose row semantics",
        rationale="The review payload should explain how to repair row semantics.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:Orders a rc:Dataset, rc:Table ;
                        rdfs:label "Orders" ;
                        rc:rowSemantics "one row per order event" .
                """,
            }
        ],
        validation_scope="all",
    )

    check = db.check_staged_revision_apply(bad.revision_iri)

    assert check.status == "validation_failed"
    assert check.validation_results
    diagnostic = check.validation_results[0]
    assert diagnostic.result_path == RC + "rowSemantics"
    assert diagnostic.hint is not None
    assert "rc:EventRow" in diagnostic.hint
    assert "rdfs:comment" in diagnostic.hint
    description = db.describe_staged_revision(bad.revision_iri)
    assert description.validation_results[0].hint == diagnostic.hint
    export_path = tmp_path / "bad-row-semantics.md"
    db.export_staged_revision(bad.revision_iri, export_path)
    assert "Hint: Use one of rc:EventRow" in export_path.read_text()

    clean = db.stage_graph_revision(
        summary="Stage controlled row semantics",
        rationale="Use controlled row semantics and keep row-grain prose in a comment.",
        additions=[
            {
                "graph": "map",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ex:CleanOrders a rc:Dataset, rc:Table ;
                        rdfs:label "Clean orders" ;
                        rdfs:comment "One row per order event." ;
                        rc:rowSemantics rc:EventRow ;
                        rc:schemaStability rc:FixedSchema .
                """,
            }
        ],
        validation_scope="all",
    )

    clean_check = db.check_staged_revision_apply(clean.revision_iri)

    assert clean.validation_conforms is True
    assert clean_check.status == "ready"


def test_staged_pattern_support_hint_distinguishes_revision_metadata(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Tickets"
    supported_pattern = "https://example.test/project#SupportedWorkflowPattern"
    db.record_map_dataset(dataset, label="Tickets", is_table=True)
    observation = db.record_observation(
        summary="Tickets profile showed workflow-state ambiguity.",
        observed_asset=dataset,
        evidence_sources=["test://tickets/profile"],
    )
    unsupported = db.stage_graph_revision(
        summary="Stage unsupported workflow pattern",
        rationale=(
            "The staged revision has support metadata, but the pattern Turtle "
            "itself omits support triples."
        ),
        additions=[
            {
                "graph": "patterns",
                "content": f"""
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:WorkflowPattern a rc:Pattern ;
                        rc:summary "Workflow-state ambiguity pattern" ;
                        rc:patternText "Workflow state interpretation varies." ;
                        rc:rationale "Observed in profile evidence." ;
                        rc:patternTarget <{dataset}> ;
                        rc:patternStability rc:EmergingPattern .
                """,
            }
        ],
        supporting_observations=[observation.observation_iri],
        evidence=[observation.evidence_iri],
        validation_scope="all",
    )

    assert unsupported.validation_conforms is False
    staged_diagnostic = unsupported.validation_results[0]
    assert staged_diagnostic.source_shape == RC + "PatternShape"
    assert staged_diagnostic.hint is not None
    assert "Revision-level support metadata does not satisfy" in (
        staged_diagnostic.hint
    )
    assert "rc:supportingObservation" in staged_diagnostic.hint
    assert "pattern framing Turtle" in staged_diagnostic.hint

    check = db.check_staged_revision_apply(unsupported.revision_iri)
    description = db.describe_staged_revision(unsupported.revision_iri)
    assert check.validation_results[0].hint == staged_diagnostic.hint
    assert description.validation_results[0].hint == staged_diagnostic.hint
    export_path = tmp_path / "unsupported-pattern.md"
    db.export_staged_revision(unsupported.revision_iri, export_path)
    assert "Hint: Revision-level support metadata" in export_path.read_text()

    repaired = db.stage_graph_revision(
        summary="Stage supported workflow pattern",
        rationale="The pattern Turtle carries the support required by PatternShape.",
        additions=[
            {
                "graph": "patterns",
                "content": f"""
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:SupportedWorkflowPattern a rc:Pattern ;
                        rc:summary "Workflow-state ambiguity pattern" ;
                        rc:patternText "Workflow state interpretation varies." ;
                        rc:rationale "Observed in profile evidence." ;
                        rc:patternTarget <{dataset}> ;
                        rc:supportingObservation <{observation.observation_iri}> ;
                        rc:evidence <{observation.evidence_iri}> ;
                        rc:patternStability rc:EmergingPattern .
                """,
            }
        ],
        supporting_observations=[observation.observation_iri],
        evidence=[observation.evidence_iri],
        revision_anchors=[supported_pattern],
        validation_scope="all",
    )

    assert repaired.validation_conforms is True
    assert db.check_staged_revision_apply(repaired.revision_iri).status == "ready"


def test_list_graph_revisions_filters_staged_validation_after_live_conflict(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    staged = db.stage_graph_revision(
        summary="Stage invalid value type",
        rationale="Exercise stored validation diagnostics after target drift.",
        additions=[
            {
                "graph": "ontology",
                "content": """
                    @prefix ex: <https://example.test/project#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:BadValueType a rc:ValueType ;
                        rc:requiredPhysicalType "VARCHAR" .
                """,
            }
        ],
        validation_scope="all",
    )

    before_drift = db.list_graph_revisions(
        application_status="validation_failed",
        staged_validation_status="failed",
    )

    assert before_drift.include_apply_checks is True
    assert before_drift.application_status == "validation_failed"
    assert before_drift.staged_validation_status == "failed"
    assert [item.iri for item in before_drift.revisions] == [staged.revision_iri]
    assert before_drift.revisions[0].staged_validation_status == "failed"

    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

        ex:BenignOntologyTerm a rdfs:Class ;
            rdfs:label "Benign ontology term" .
        """,
        graph="ontology",
    )

    live_validation_failed = db.list_graph_revisions(
        application_status="validation_failed",
    )
    stored_validation_failed = db.list_graph_revisions(
        staged_validation_status="failed",
    )
    conflicted_stored_validation_failed = db.list_graph_revisions(
        application_status="conflict",
        staged_validation_status="failed",
    )

    assert live_validation_failed.count == 0
    assert stored_validation_failed.staged_validation_status == "failed"
    assert [item.iri for item in stored_validation_failed.revisions] == [
        staged.revision_iri
    ]
    stored_row = stored_validation_failed.revisions[0]
    assert stored_row.application_status is None
    assert stored_row.validation_conforms is False
    assert stored_row.validation_result_count == 1
    assert stored_row.staged_validation_status == "failed"
    assert conflicted_stored_validation_failed.include_apply_checks is True
    assert [item.iri for item in conflicted_stored_validation_failed.revisions] == [
        staged.revision_iri
    ]
    conflict_row = conflicted_stored_validation_failed.revisions[0]
    assert conflict_row.application_status == "conflict"
    assert conflict_row.stale_resolution_state == "stale_unresolved"
    assert conflict_row.application_validation_skipped_reason == "conflicts_present"
    assert conflict_row.next_action is not None
    assert conflict_row.next_action.action_type == "repair_or_replace"
    assert conflict_row.next_action.queue == "repair_or_replace"
    assert conflict_row.next_action.tool_name == "draft_staged_revision_rebase"

    export = db.export_staged_revisions(
        [staged.revision_iri],
        tmp_path / "validation-after-drift.md",
    )

    assert export.bundle_summary.validation_failed_revision_iris == []
    assert export.bundle_summary.staged_validation_failed_revision_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.recommended_repair_review_iris == [
        staged.revision_iri
    ]
    assert export.bundle_summary.next_action_queue == {
        "repair_or_replace": [staged.revision_iri]
    }


def test_stage_graph_revision_rejects_immutable_seed_targets(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")

    with pytest.raises(ImmutableGraphError, match="base_ontology"):
        db.stage_graph_revision(
            summary="Invalid staged seed patch",
            rationale="Project-level staged revisions must not target shipped seeds.",
            additions=[
                {
                    "graph": "base_ontology",
                    "content": (
                        "@prefix ex: <https://example.test/> . "
                        "ex:s ex:p ex:o ."
                    ),
                }
            ],
        )


def test_stage_graph_revision_rejects_history_target_without_metadata_write(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    before_history_count = db.triple_count("history")

    with pytest.raises(
        DoxaBaseError,
        match="cannot target 'history'.*record_graph_revision",
    ):
        db.stage_graph_revision(
            summary="Invalid staged history patch",
            rationale="Staged patch metadata is itself written to history.",
            additions=[
                {
                    "graph": "history",
                    "content": (
                        "@prefix ex: <https://example.test/> . "
                        "ex:review ex:note \"Manual review note\" ."
                    ),
                }
            ],
        )

    assert db.triple_count("history") == before_history_count


def test_stage_systematisation_preserves_alternative_rdf_framings(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    observation = db.record_observation(
        "Message-like rows repeatedly require identity reasoning.",
        evidence_summary="Synthetic test note backing the staged systematisation.",
        evidence_sources=["test://identity-ladder"],
    )
    before_ontology_count = db.triple_count("ontology")
    before_patterns_count = db.triple_count("patterns")

    ontology_framing = """
    @prefix ex: <https://example.test/project#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    ex:IdentityLadder a rdfs:Class ;
        rdfs:label "Identity ladder" ;
        rdfs:comment "A project-local way to model progressively stronger identity hints." .
    """
    pattern_framing = f"""
    @prefix ex: <https://example.test/project#> .
    @prefix rc: <https://richcanopy.org/ns/rc#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    ex:IdentityLadderPattern a rc:Pattern ;
        rdfs:label "Identity ladder pattern" ;
        rc:summary "Identity hints become stronger as more columns agree." ;
        rc:patternText "Repeated message-like rows appear to form a ladder of identity hints rather than one fixed key." ;
        rc:rationale "This may generalise better than forcing every source into a single key model." ;
        rc:patternTarget ex:Messages ;
        rc:supportingObservation <{observation.observation_iri}> ;
        rc:patternStability rc:EmergingPattern .
    """

    draft = db.stage_systematisation(
        summary="Explore identity-ladder modelling",
        intent=(
            "Keep two RDF framings alive while deciding whether this belongs in "
            "project vocabulary or as a pattern first."
        ),
        rationale=(
            "The concept is deliberately awkward: it may need ontology surface "
            "before it can become a map fact."
        ),
        anchors=[observation.observation_iri, "https://example.test/project#Messages"],
        framings=[
            {
                "label": "Project vocabulary term",
                "graph": "ontology",
                "content": ontology_framing,
                "stance": "rc:AlternativeSystematisation",
                "review_note": "This names the concept directly, but it may be premature.",
                "review_recommendation": "Keep as an alternative while more cases accumulate.",
            },
            {
                "label": "Pattern first",
                "graph": "patterns",
                "content": pattern_framing,
                "rationale": (
                    "This keeps the insight tentative while preserving the "
                    "intuition that the map may need a new concept later."
                ),
                "review_note": "This keeps the bold hunch alive without forcing the map.",
                "review_recommendation": "Preferred for now.",
            },
        ],
        validation_scope="all",
    )

    assert draft.result_kind == "systematisation_draft"
    assert draft.summary == "Explore identity-ladder modelling"
    assert draft.profile_route_source_count == 0
    assert draft.anchors == [
        observation.observation_iri,
        "https://example.test/project#Messages",
    ]
    assert len(draft.staged_revisions) == 2
    assert draft.staged_revisions[0].summary == (
        "Explore identity-ladder modelling: Project vocabulary term"
    )
    assert draft.staged_revisions[0].review_note == (
        "This names the concept directly, but it may be premature."
    )
    assert draft.staged_revisions[0].review_recommendation == (
        "Keep as an alternative while more cases accumulate."
    )
    assert draft.staged_revisions[1].summary == (
        "Explore identity-ladder modelling: Pattern first"
    )
    assert draft.staged_revisions[1].review_note == (
        "This keeps the bold hunch alive without forcing the map."
    )
    assert draft.staged_revisions[1].review_recommendation == "Preferred for now."
    assert len(draft.framings) == 2
    assert draft.framings[0].target_graphs == ["ontology"]
    assert draft.framings[1].target_graphs == ["patterns"]
    assert all(framing.validation_conforms for framing in draft.framings)
    assert draft.framings[0].stance == RC + "AlternativeSystematisation"
    assert draft.framings[1].stance == RC + "ExploratoryHunch"
    assert draft.framings[1].review_note == (
        "This keeps the bold hunch alive without forcing the map."
    )
    assert draft.framings[1].review_recommendation == "Preferred for now."
    revision_iris = [revision.revision_iri for revision in draft.staged_revisions]
    assert draft.next_action_queue == {"apply_after_review": revision_iris}
    assert draft.next_action_queue_item_counts == {"apply_after_review": 2}
    assert draft.semantic_review_required_queue_counts == {}
    assert [item.row_iri for item in draft.next_action_queue_items] == revision_iris
    assert [
        item.resolved_target_iri for item in draft.next_action_queue_items
    ] == revision_iris
    assert all(item.row_is_target for item in draft.next_action_queue_items)
    assert [
        item.alternative_set_iris for item in draft.next_action_queue_items
    ] == [revision_iris, revision_iris]
    assert [
        item.alternative_set_source_iri for item in draft.next_action_queue_items
    ] == [revision_iris[0], revision_iris[0]]
    assert [
        item.alternative_set_role for item in draft.next_action_queue_items
    ] == ["source", "alternative"]
    assert draft.suggested_next_actions[0].tool_name == "export_staged_revisions"
    assert draft.suggested_next_actions[0].arguments["revision_iris"] == revision_iris
    assert draft.suggested_next_actions[0].arguments["fail_on_sensitive"] is True
    draft_export_path = draft.suggested_next_actions[0].arguments["path"]
    assert draft_export_path.startswith("/tmp/systematisation-review-")
    assert draft_export_path.endswith(".md")
    assert [
        action.arguments
        for action in draft.suggested_next_actions
        if action.tool_name == "check_staged_revision_apply"
    ] == [{"iri": revision_iri} for revision_iri in revision_iris]
    first_export_action = next(
        action
        for action in db.check_staged_revision_apply(
            revision_iris[0],
        ).suggested_next_actions
        if action.tool_name == "export_staged_revision"
    )
    second_export_action = next(
        action
        for action in db.check_staged_revision_apply(
            revision_iris[1],
        ).suggested_next_actions
        if action.tool_name == "export_staged_revision"
    )
    first_export_path = first_export_action.arguments["path"]
    second_export_path = second_export_action.arguments["path"]
    assert first_export_path.startswith("/tmp/staged-revision-review-")
    assert second_export_path.startswith("/tmp/staged-revision-review-")
    assert first_export_path.endswith(".md")
    assert second_export_path.endswith(".md")
    assert first_export_path != second_export_path
    assert first_export_action.arguments["fail_on_sensitive"] is True
    assert second_export_action.arguments["fail_on_sensitive"] is True
    assert db.triple_count("ontology") == before_ontology_count
    assert db.triple_count("patterns") == before_patterns_count

    first = db.describe_staged_revision(draft.staged_revisions[0].revision_iri)
    second = db.describe_staged_revision(draft.staged_revisions[1].revision_iri)
    assert {anchor.iri for anchor in first.revision_anchors} == {
        observation.observation_iri,
        "https://example.test/project#Messages",
    }
    assert {anchor.iri for anchor in second.revision_anchors} == {
        observation.observation_iri,
        "https://example.test/project#Messages",
    }
    assert first.alternative_to is None
    assert second.alternative_to is not None
    assert second.alternative_to.iri == first.iri
    assert "Systematisation intent:" in second.rationale
    assert first.review_recommendation == (
        "Keep as an alternative while more cases accumulate."
    )
    assert second.review_note == "This keeps the bold hunch alive without forcing the map."
    assert second.review_recommendation == "Preferred for now."
    assert "Identity ladder" in first.patches[0].content
    assert "IdentityLadderPattern" in second.patches[0].content
    assert db.validate_graph(scope="all").conforms

    export_path = tmp_path / "identity-ladder-review.md"
    export = db.export_staged_revisions(
        [revision.revision_iri for revision in draft.staged_revisions],
        export_path,
        title="Identity ladder alternatives",
        executive_summary=(
            "Prefer the pattern-first framing for now, while preserving the "
            "ontology alternative as useful pressure on the model."
        ),
    )
    exported = export_path.read_text(encoding="utf-8")

    assert export.revision_iris == [
        revision.revision_iri for revision in draft.staged_revisions
    ]
    assert [item.revision_iri for item in export.revision_summaries] == [
        revision.revision_iri for revision in draft.staged_revisions
    ]
    assert [item.alternative_to for item in export.revision_summaries] == [
        None,
        draft.staged_revisions[0].revision_iri,
    ]
    assert [item.current_alternative_to for item in export.revision_summaries] == [
        None,
        draft.staged_revisions[0].revision_iri,
    ]
    assert [
        item.alternative_set_iris
        for item in export.bundle_summary.next_action_queue_items
    ] == [revision_iris, revision_iris]
    assert [
        item.alternative_set_source_iri
        for item in export.bundle_summary.next_action_queue_items
    ] == [revision_iris[0], revision_iris[0]]
    assert [
        item.alternative_set_role
        for item in export.bundle_summary.next_action_queue_items
    ] == ["source", "alternative"]
    assert export.bundle_summary.changed_graph_counts == {
        "ontology": 1,
        "patterns": 1,
    }
    assert len(export.bundle_summary.choose_one_groups) == 1
    choose_one = export.bundle_summary.choose_one_groups[0]
    assert choose_one.row_indexes == [1, 2]
    assert choose_one.revision_iris == revision_iris
    assert choose_one.alternative_set_source_iri == revision_iris[0]
    assert choose_one.source_row_index == 1
    assert choose_one.alternative_set_roles == ["source", "alternative"]
    assert export.bundle_summary.modelling_choice_summary is not None
    assert "choose-one group" in export.bundle_summary.modelling_choice_summary
    assert [
        row.modelling_role
        for row in export.bundle_summary.modelling_choice_rows
    ] == [
        "vocabulary_or_shape_candidate",
        "pattern_first_alternative",
    ]
    assert [
        row.alternative_set_role
        for row in export.bundle_summary.modelling_choice_rows
    ] == ["source", "alternative"]
    assert [
        row.queue for row in export.bundle_summary.modelling_choice_rows
    ] == ["apply_after_review", "apply_after_review"]
    assert [
        row.support_counts["anchors"]
        for row in export.bundle_summary.modelling_choice_rows
    ] == [2, 2]
    assert "choose-one group" in export.bundle_summary.decision_headline
    assert [item.apply_status for item in export.revision_summaries] == [
        "ready",
        "ready",
    ]
    assert [item.apply_decision for item in export.revision_summaries] == [
        "review_then_apply",
        "review_then_apply",
    ]
    assert [item.current_validation for item in export.revision_summaries] == [
        "True (0 result(s))",
        "True (0 result(s))",
    ]
    assert export.revision_summaries[1].review_recommendation == "Preferred for now."
    assert (
        export.revision_summaries[1].summary_recommendation
        == export.revision_summaries[1].apply_recommended_resolution
    )
    assert (
        export.revision_summaries[1].summary_recommendation_source
        == "apply_recommended_resolution"
    )
    assert (
        export.revision_summaries[1].active_recommendation_field
        == "summary_recommendation"
    )
    assert export.revision_summaries[1].next_action is not None
    assert export.revision_summaries[1].next_action.queue == "apply_after_review"
    assert export.revision_summaries[1].next_action.tool_name == (
        "apply_staged_revision"
    )
    assert export.revision_summaries[1].suggested_next_actions[-1].tool_name == (
        "apply_staged_revision"
    )
    assert export.bytes_written == len(exported.encode("utf-8"))
    assert exported.startswith("# Identity ladder alternatives\n")
    assert "## Review Summary" in exported
    assert "Prefer the pattern-first framing for now" in exported
    assert "## At A Glance" in exported
    assert "- Changed graphs: ontology: 1, patterns: 1" in exported
    assert "- Choose-one groups:" in exported
    assert "## Modelling Choice Summary" in exported
    assert "vocabulary_or_shape_candidate" in exported
    assert "pattern_first_alternative" in exported
    assert exported.index("## At A Glance") < exported.index(
        "## Modelling Choice Summary"
    )
    assert exported.index("## Modelling Choice Summary") < exported.index(
        "## Reviewer Decision Matrix"
    )
    assert "## Reviewer Decision Matrix" in exported
    assert (
        "Rows 1 and 2 are competing alternatives. Apply at most one before "
        "regenerating or rechecking the bundle."
    ) in exported
    assert (
        "| Row | Candidate | Suggested human action | Why | "
        "Authored recommendation |"
    ) in exported
    decision_matrix = exported.split(
        "## Reviewer Decision Matrix",
        1,
    )[1].split("## Summary", 1)[0]
    assert (
        decision_matrix.count("Choose only if this alternative is preferred")
        == 2
    )
    assert "Apply after semantic review" not in decision_matrix
    assert "## Summary" in exported
    assert "Apply status" in exported
    assert "Current validation" in exported
    assert "Staged validation" in exported
    assert "True (0 result(s))" in exported
    assert "review_then_apply" in exported
    assert "Recommendation" in exported
    assert "Preferred for now." in exported
    assert "## Review Notes" in exported
    assert "This keeps the bold hunch alive without forcing the map." in exported
    assert "| 1 | Explore identity-ladder modelling: Project vocabulary term" in exported
    assert "| 2 | Explore identity-ladder modelling: Pattern first" in exported
    assert "## Revision 1: Explore identity-ladder modelling: Project vocabulary term" in exported
    assert "## Revision 2: Explore identity-ladder modelling: Pattern first" in exported
    assert "\n# Explore identity-ladder modelling: Project vocabulary term" not in exported
    assert "\n# Explore identity-ladder modelling: Pattern first" not in exported
    assert "## Alternative To" in exported
    assert "IdentityLadderPattern" in exported

    recovery = db.plan_staged_revision_recovery(revision_iris)
    assert [
        item.alternative_set_iris for item in recovery.next_action_queue_items
    ] == [revision_iris, revision_iris]
    assert [
        lane.next_action_queue_item.alternative_set_role
        for lane in recovery.lanes
        if lane.next_action_queue_item is not None
    ] == ["source", "alternative"]


def test_stage_pattern_promotion_rolls_pattern_support_into_staged_revision(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    base = "https://example.test/ais#"
    mmsi_column = f"{base}broadcasts__mmsi"
    caveat = f"{base}mmsi_operational_identity_caveat"
    observation = db.record_observation(
        "MMSI appears repeatedly as a useful but imperfect grouping key.",
        observed_column=mmsi_column,
        evidence_summary="Synthetic profile note for pattern promotion.",
        evidence_sources=["test://mmsi-profile"],
    )
    claim = db.record_claim_observation(
        summary="MMSI identity caveat.",
        claim_text="MMSI is useful for grouping broadcasts but is not stable vessel identity.",
        claim_kind="rc:CaveatClaim",
        claim_targets=[mmsi_column],
        evidence_sources=["test://mmsi-caveat"],
    )
    pattern = db.record_pattern(
        summary="MMSI is operational identity, not vessel identity.",
        pattern_text=(
            "Repeated checks support treating MMSI as an operational grouping key "
            "with identity caveats."
        ),
        rationale=(
            "The observation and claim agree that MMSI is useful but should not "
            "be promoted as a stable vessel identifier."
        ),
        pattern_targets=[mmsi_column],
        supporting_observations=[observation.observation_iri],
        supporting_claims=[claim.claim_iri],
        evidence_iri=claim.evidence_iri,
        map_implications=[caveat],
        confidence="rc:HighConfidence",
        pattern_stability="rc:RepeatedPattern",
    )
    before_map_count = db.triple_count("map")
    before_ontology_count = db.triple_count("ontology")

    draft = db.stage_pattern_promotion(
        patterns=[pattern.pattern_iri],
        summary="Promote MMSI caveat from pattern",
        intent="Preserve the MMSI hunch as current map caveat plus a project term.",
        rationale=(
            "This is a cautious promotion: the strong pattern becomes a caveat, "
            "not a hard identity-key assertion."
        ),
        shared_additions=[
            {
                "graph": "ontology",
                "content": """
                    @prefix ais: <https://example.test/ais#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ais:OperationalIdentityCaveat a rdfs:Class ;
                        rdfs:subClassOf rc:KnownCaveat ;
                        rdfs:label "Operational identity caveat" .
                """,
            }
        ],
        framings=[
            {
                "label": "Map caveat",
                "graph": "map",
                "content": f"""
                    @prefix ais: <https://example.test/ais#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    ais:mmsi_operational_identity_caveat
                        a rc:KnownCaveat, ais:OperationalIdentityCaveat ;
                        rdfs:label "MMSI operational identity caveat" ;
                        rdfs:comment "MMSI can group broadcasts but should not be treated as stable vessel identity." ;
                        rc:caveatDescription "MMSI can group broadcasts but should not be treated as stable vessel identity." ;
                        rc:impact "Identity-level analysis should avoid assuming one MMSI equals one vessel." ;
                        rc:severity rc:Moderate .

                    <{mmsi_column}> rc:hasKnownCaveat ais:mmsi_operational_identity_caveat .
                """,
                "review_note": "Pattern support is strong, but the map change remains staged.",
            }
        ],
        validation_scope="all",
    )

    assert draft.summary == "Promote MMSI caveat from pattern"
    assert draft.intent == (
        "Preserve the MMSI hunch as current map caveat plus a project term."
    )
    assert draft.anchors == [pattern.pattern_iri, mmsi_column, caveat]
    assert draft.framings[0].target_graphs == ["ontology", "map"]
    assert draft.framings[0].validation_conforms is True
    assert db.triple_count("map") == before_map_count
    assert db.triple_count("ontology") == before_ontology_count

    staged = db.describe_staged_revision(draft.staged_revisions[0].revision_iri)
    assert staged.revision_stance == RC + "CandidateRevision"
    assert staged.rationale is not None
    assert "Selected pattern support" in staged.rationale
    assert "Promotion rationale" in staged.rationale
    assert {pattern_summary.iri for pattern_summary in staged.supporting_patterns} == {
        pattern.pattern_iri
    }
    assert {
        observation_summary.iri
        for observation_summary in staged.supporting_observations
    } == {observation.observation_iri}
    assert {claim_summary.iri for claim_summary in staged.supporting_claims} == {
        claim.claim_iri
    }
    assert {evidence_summary.iri for evidence_summary in staged.evidence} == {
        claim.evidence_iri
    }
    assert {anchor.iri for anchor in staged.revision_anchors} == {
        pattern.pattern_iri,
        mmsi_column,
        caveat,
    }


def test_stage_pattern_promotion_keeps_claim_evidence_indirect_unless_passed(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    base = "https://example.test/profile#"
    dataset = f"{base}Orders"
    metric = f"{base}CompletenessRatio"
    db.record_map_dataset(dataset, label="Orders", is_table=True)
    claim = db.record_claim_observation(
        summary="Completeness ratio was reviewed.",
        claim_text=(
            "The Orders completeness ratio is meaningful only after excluding "
            "synthetic heartbeat rows."
        ),
        claim_kind="rc:MetricClaim",
        claim_targets=[metric],
        evidence_sources=["test://orders-completeness-review"],
    )
    assert claim.evidence_iri is not None
    pattern = db.record_pattern(
        summary="Completeness ratio needs project vocabulary.",
        pattern_text=(
            "Orders profiles reuse a completeness ratio with project-specific "
            "denominator semantics."
        ),
        rationale="The supporting claim carries the source evidence.",
        pattern_targets=[dataset],
        supporting_claims=[claim.claim_iri],
        map_implications=[metric],
    )
    framing = {
        "label": "Metric vocabulary",
        "graph": "ontology",
        "content": f"""
            @prefix rc: <https://richcanopy.org/ns/rc#> .
            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

            <{metric}> a rc:ProfileMetricKind ;
                rdfs:label "Completeness ratio" .
        """,
    }

    indirect = db.stage_pattern_promotion(
        patterns=[pattern.pattern_iri],
        summary="Promote metric without direct evidence",
        intent="Show that claim evidence stays indirect unless selected.",
        framings=[framing],
        validation_scope="all",
    )

    indirect_staged = db.describe_staged_revision(
        indirect.staged_revisions[0].revision_iri
    )
    assert {item.iri for item in indirect_staged.supporting_claims} == {
        claim.claim_iri
    }
    assert indirect_staged.evidence == []

    explicit = db.stage_pattern_promotion(
        patterns=[pattern.pattern_iri],
        summary="Promote metric with explicit evidence",
        intent="Show how callers promote claim evidence into direct revision evidence.",
        framings=[framing],
        evidence=[claim.evidence_iri],
        validation_scope="all",
    )

    explicit_staged = db.describe_staged_revision(
        explicit.staged_revisions[0].revision_iri
    )
    assert {item.iri for item in explicit_staged.supporting_claims} == {
        claim.claim_iri
    }
    assert {item.iri for item in explicit_staged.evidence} == {claim.evidence_iri}


def test_stage_pattern_promotion_mixed_alternatives_group_review_queues(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    base = "https://example.test/awkward-temporal#"
    ft = "https://example.test/awkward-temporal/systematisation#"
    dataset = f"{base}dispatch_events"
    clock = f"{base}dispatch_events__event_local_time"
    timezone = f"{base}dispatch_events__source_timezone_hint"
    normalized = f"{base}dispatch_events__event_utc"
    partition = f"{base}dispatch_events__ingest_partition_date"
    temporal_scope = f"{ft}dispatch_event_temporal_scope_v1"
    caveat = f"{ft}temporal_interpretation_caveat"
    observation = db.record_observation(
        "Raw local clock text is not an event instant.",
        observed_column=clock,
        evidence_summary=(
            "Synthetic temporal sample mixed offset-bearing, naive, and "
            "placeholder local clock values."
        ),
        evidence_sources=["test://awkward-temporal-profile"],
    )
    claim = db.record_claim_observation(
        summary="Temporal interpretation needs timezone evidence.",
        claim_text=(
            "event_local_time should be preserved as source-local text unless "
            "source_timezone_hint can support event_utc normalization."
        ),
        claim_kind="rc:SchemaClaim",
        claim_targets=[clock, timezone, normalized],
        evidence_sources=["test://awkward-temporal-claim"],
    )
    pattern = db.record_pattern(
        summary="Temporal meaning spans raw clock, timezone hint, and UTC.",
        pattern_text=(
            "Dispatch event time cannot be represented as a simple column "
            "helper fact: raw local clock text, timezone evidence, nullable "
            "normalized UTC, and ingest partition date each carry different "
            "semantics."
        ),
        rationale=(
            "A durable model needs an explicit interpretation scope or a "
            "pattern-level caveat, not just a changed physical type."
        ),
        pattern_targets=[dataset, clock, timezone, normalized, partition],
        supporting_observations=[observation.observation_iri],
        supporting_claims=[claim.claim_iri],
        evidence_iri=claim.evidence_iri,
        map_implications=[temporal_scope, caveat],
    )
    shared_ontology = """
    @prefix ft: <https://example.test/awkward-temporal/systematisation#> .
    @prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
    @prefix rc: <https://richcanopy.org/ns/rc#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    ft:TemporalInterpretationScope a rdfs:Class ;
        rdfs:label "Temporal interpretation scope" .

    ft:TemporalInterpretationPattern a rdfs:Class ;
        rdfs:subClassOf rc:Pattern ;
        rdfs:label "Temporal interpretation pattern" .

    ft:clockColumn a rdf:Property ;
        rdfs:label "clock column" .

    ft:timezoneEvidenceColumn a rdf:Property ;
        rdfs:label "timezone evidence column" .

    ft:normalizedInstantColumn a rdf:Property ;
        rdfs:label "normalized instant column" .

    ft:partitionColumn a rdf:Property ;
        rdfs:label "partition column" .
    """
    shared_shape = """
    @prefix ft: <https://example.test/awkward-temporal/systematisation#> .
    @prefix sh: <http://www.w3.org/ns/shacl#> .

    ft:TemporalInterpretationScopeShape a sh:NodeShape ;
        sh:targetClass ft:TemporalInterpretationScope ;
        sh:property [
            sh:path ft:timezoneEvidenceColumn ;
            sh:minCount 1 ;
            sh:nodeKind sh:IRI ;
            sh:message "Temporal scopes must name the timezone evidence column."
        ] .
    """
    incomplete_map_framing = f"""
    @prefix ft: <https://example.test/awkward-temporal/systematisation#> .
    @prefix rc: <https://richcanopy.org/ns/rc#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    <{dataset}> a rc:Dataset ;
        rdfs:label "Dispatch Events" ;
        rc:hasKnownCaveat <{caveat}> .

    <{caveat}> a rc:KnownCaveat ;
        rdfs:label "Temporal interpretation caveat" ;
        rc:caveatDescription "Raw event time, timezone hints, UTC, and partition dates are related but not interchangeable." .

    <{temporal_scope}> a ft:TemporalInterpretationScope ;
        rdfs:label "Dispatch event temporal scope" ;
        ft:clockColumn <{clock}> ;
        ft:normalizedInstantColumn <{normalized}> ;
        ft:partitionColumn <{partition}> .
    """
    repaired_map_framing = f"""
    @prefix ft: <https://example.test/awkward-temporal/systematisation#> .
    @prefix rc: <https://richcanopy.org/ns/rc#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    <{dataset}> a rc:Dataset ;
        rdfs:label "Dispatch Events" ;
        rc:hasKnownCaveat <{caveat}> .

    <{caveat}> a rc:KnownCaveat ;
        rdfs:label "Temporal interpretation caveat" ;
        rc:caveatDescription "Raw event time, timezone hints, UTC, and partition dates are related but not interchangeable." .

    <{temporal_scope}> a ft:TemporalInterpretationScope ;
        rdfs:label "Dispatch event temporal scope" ;
        ft:clockColumn <{clock}> ;
        ft:timezoneEvidenceColumn <{timezone}> ;
        ft:normalizedInstantColumn <{normalized}> ;
        ft:partitionColumn <{partition}> .
    """
    pattern_first_framing = f"""
    @prefix ft: <https://example.test/awkward-temporal/systematisation#> .
    @prefix dcterms: <http://purl.org/dc/terms/> .
    @prefix rc: <https://richcanopy.org/ns/rc#> .
    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

    ft:temporal_interpretation_pattern
        a rc:Pattern, ft:TemporalInterpretationPattern ;
        rdfs:label "Temporal interpretation pattern" ;
        rc:summary "Temporal meaning spans raw clock, timezone hint, and UTC." ;
        rc:patternText "Preserve the cross-column temporal judgement without promoting a current-best map scope yet." ;
        rc:rationale "The pattern framing keeps the semantic caveat visible while map vocabulary is still settling." ;
        rc:patternTarget <{clock}>, <{timezone}>, <{normalized}>, <{partition}> ;
        rc:evidence ft:temporal_interpretation_evidence ;
        rc:patternStability rc:EmergingPattern .

    ft:temporal_interpretation_evidence a rc:Evidence ;
        rc:summary "Synthetic support for the temporal interpretation pattern." ;
        dcterms:source "tests/test_doxabase_core.py" .
    """

    draft = db.stage_pattern_promotion(
        patterns=[pattern.pattern_iri],
        summary="Promote temporal interpretation alternatives",
        intent=(
            "Stage alternative RDF framings for temporal semantics that do not "
            "fit a simple dataset or column map helper."
        ),
        shared_additions=[
            {"graph": "ontology", "content": shared_ontology},
            {"graph": "shapes", "content": shared_shape},
        ],
        framings=[
            {
                "label": "Incomplete map scope without timezone evidence",
                "graph": "map",
                "content": incomplete_map_framing,
                "review_note": (
                    "Intentionally omits timezoneEvidenceColumn so validation "
                    "can show the missing semantic dependency."
                ),
                "review_recommendation": (
                    "Do not apply; use this as the repair diagnostic."
                ),
            },
            {
                "label": "Repaired map scope with timezone evidence",
                "graph": "map",
                "content": repaired_map_framing,
                "review_recommendation": (
                    "Ready after semantic review; compare with the "
                    "pattern-first alternative."
                ),
            },
            {
                "label": "Pattern-first temporal lore",
                "graph": "patterns",
                "content": pattern_first_framing,
                "stance": "rc:AlternativeSystematisation",
                "review_recommendation": (
                    "Keep as the primary handoff unless more datasets confirm "
                    "the scope model."
                ),
            },
        ],
        validation_scope="all",
    )

    revision_iris = [revision.revision_iri for revision in draft.staged_revisions]
    assert draft.result_kind == "systematisation_draft"
    assert [framing.validation_conforms for framing in draft.framings] == [
        False,
        True,
        True,
    ]
    assert [framing.validation_result_count for framing in draft.framings] == [
        1,
        0,
        0,
    ]
    assert draft.next_action_queue == {
        "repair_or_replace": [revision_iris[0]],
        "apply_after_review": [revision_iris[1], revision_iris[2]],
    }
    assert draft.next_action_queue_item_counts == {
        "repair_or_replace": 1,
        "apply_after_review": 2,
    }
    assert draft.semantic_review_required_queue_counts == {}
    assert [
        item.application_status for item in draft.next_action_queue_items
    ] == [
        "validation_failed",
        "ready",
        "ready",
    ]
    assert any(
        "First framing 'Incomplete map scope without timezone evidence'" in warning
        and "failed staged validation" in warning
        and revision_iris[0] in warning
        and "link_alternatives=False" in warning
        for warning in draft.warnings
    )
    assert [
        warning.warning_code for warning in draft.structured_warnings
    ] == [
        "shared_semantic_context_applies_to_all_framings",
        "first_alternative_anchor_not_ready",
    ]
    shared_warning = draft.structured_warnings[0]
    assert shared_warning.message in draft.warnings
    assert shared_warning.affected_revision_iris == revision_iris
    assert (
        shared_warning.suggested_action
        == "rerun_with_shared_semantic_context_moved_to_framings"
    )
    assert shared_warning.suggested_rerun_arguments == {
        "move_shared_patch_graphs_into_framing_patches": ["ontology", "shapes"],
        "shared_patch_sources_to_move": [
            {
                "source_argument": "shared_additions",
                "source_index": 0,
                "operation": "addition",
                "graph": "ontology",
            },
            {
                "source_argument": "shared_additions",
                "source_index": 1,
                "operation": "addition",
                "graph": "shapes",
            },
        ],
        "target_framing_selection_required": True,
        "target_framing_selection_note": (
            "Choose which framings should receive the moved ontology/shapes "
            "patches. fallback_revision_iris_with_shared_semantic_context is "
            "an inspection subset of later framings currently carrying shared "
            "context, not an automatic drop list."
        ),
    }
    assert (
        shared_warning.fallback_revision_iris_with_shared_semantic_context
        == revision_iris[1:]
    )
    assert [
        (summary.target_graph, summary.triple_count, summary.count_basis)
        for summary in shared_warning.shared_patch_summaries
    ] == [
        ("ontology", 13, "target_graph_plus_base_ontology"),
        ("shapes", 7, "target_graph_plus_base_shapes"),
    ]
    assert all(
        summary.operation == RC + "AdditionPatch"
        and summary.operation_label == "addition patch"
        and summary.patch_role == RC + "SharedContextPatch"
        and summary.patch_role_label == "shared context patch"
        and summary.format == "turtle"
        for summary in shared_warning.shared_patch_summaries
    )
    structured_warning = draft.structured_warnings[1]
    assert structured_warning.warning_code == "first_alternative_anchor_not_ready"
    assert structured_warning.message in draft.warnings
    assert structured_warning.affected_revision_iris == revision_iris
    assert (
        structured_warning.suggested_action
        == "rerun_with_explicit_alternative_routing"
    )
    assert structured_warning.suggested_rerun_arguments == {
        "link_alternatives": False
    }
    rerun_action = draft.suggested_next_actions[0]
    assert rerun_action.tool_name == "stage_systematisation"
    assert rerun_action.action_label == (
        "Rerun with explicit alternative routing"
    )
    assert rerun_action.arguments["summary"] == (
        "Promote temporal interpretation alternatives"
    )
    assert rerun_action.arguments["intent"] == (
        "Stage alternative RDF framings for temporal semantics that do not "
        "fit a simple dataset or column map helper."
    )
    assert rerun_action.arguments["link_alternatives"] is False
    assert rerun_action.arguments["shared_additions"] == [
        {"graph": "ontology", "content": shared_ontology},
        {"graph": "shapes", "content": shared_shape},
    ]
    assert [framing["label"] for framing in rerun_action.arguments["framings"]] == [
        "Incomplete map scope without timezone evidence",
        "Repaired map scope with timezone evidence",
        "Pattern-first temporal lore",
    ]
    assert "link_alternatives=False" in rerun_action.reason
    export_action = draft.suggested_next_actions[1]
    assert export_action.tool_name == "export_staged_revisions"
    assert export_action.arguments["revision_iris"] == revision_iris
    assert export_action.arguments["path"].startswith(
        "/tmp/systematisation-review-"
    )
    assert export_action.arguments["path"].endswith(".md")
    assert [
        action.arguments
        for action in draft.suggested_next_actions
        if action.tool_name == "check_staged_revision_apply"
    ] == [{"iri": revision_iri} for revision_iri in revision_iris]
    export_path = tmp_path / "temporal-interpretation-review.md"
    export = db.export_staged_revisions(
        revision_iris,
        export_path,
        title="Temporal interpretation alternatives",
    )
    exported = export_path.read_text(encoding="utf-8")

    assert export.bundle_summary.next_action_queue == {
        "repair_or_replace": [revision_iris[0]],
        "apply_after_review": [revision_iris[1], revision_iris[2]],
    }
    assert export.bundle_summary.semantic_risk_queue_counts == {
        "repair_or_replace": 1,
        "apply_after_review": 2,
    }
    assert export.bundle_summary.semantic_review_required_queue_counts == {}
    assert export.bundle_summary.shared_context_graphs == ["ontology", "shapes"]
    assert (
        export.bundle_summary.fallback_revision_iris_with_shared_semantic_context
        == revision_iris[1:]
    )
    assert [
        (summary.target_graph, summary.triple_count, summary.count_basis)
        for summary in export.bundle_summary.shared_context_patch_summaries
    ] == [
        ("ontology", 13, "target_graph_plus_base_ontology"),
        ("shapes", 7, "target_graph_plus_base_shapes"),
    ]
    assert len(export.bundle_summary.shared_semantic_context_warnings) == 1
    bundle_shared_warning = export.bundle_summary.shared_semantic_context_warnings[0]
    assert bundle_shared_warning.warning_code == (
        "shared_semantic_context_applies_to_all_framings"
    )
    assert bundle_shared_warning.affected_revision_iris == revision_iris
    assert bundle_shared_warning.shared_context_graphs == ["ontology", "shapes"]
    assert (
        bundle_shared_warning.fallback_revision_iris_with_shared_semantic_context
        == revision_iris[1:]
    )
    assert any(
        "Shared ontology or shapes context patches are present across this staged bundle"
        in warning
        for warning in export.bundle_summary.warnings
    )
    assert export.bundle_summary.recommended_repair_review_iris == [
        revision_iris[0]
    ]
    assert export.bundle_summary.recommended_apply_or_restage_review_iris == [
        revision_iris[1],
        revision_iris[2],
    ]
    assert export.bundle_summary.modelling_choice_summary is not None
    assert "repair_diagnostic: 1" in export.bundle_summary.modelling_choice_summary
    assert "map_candidate: 1" in export.bundle_summary.modelling_choice_summary
    assert (
        "pattern_first_alternative: 1"
        in export.bundle_summary.modelling_choice_summary
    )
    assert [
        row.modelling_role
        for row in export.bundle_summary.modelling_choice_rows
    ] == [
        "repair_diagnostic",
        "map_candidate",
        "pattern_first_alternative",
    ]
    assert [
        row.queue for row in export.bundle_summary.modelling_choice_rows
    ] == [
        "repair_or_replace",
        "apply_after_review",
        "apply_after_review",
    ]
    assert [
        row.shared_context_graphs
        for row in export.bundle_summary.modelling_choice_rows
    ] == [["ontology", "shapes"], ["ontology", "shapes"], ["ontology", "shapes"]]
    assert all(
        row.shared_context_applies
        for row in export.bundle_summary.modelling_choice_rows
    )
    assert [
        row.support_counts["patterns"]
        for row in export.bundle_summary.modelling_choice_rows
    ] == [1, 1, 1]
    assert [summary.apply_status for summary in export.revision_summaries] == [
        "validation_failed",
        "ready",
        "ready",
    ]
    assert [
        summary.semantic_risk_level for summary in export.revision_summaries
    ] == [
        "attention",
        "attention",
        "attention",
    ]
    assert [
        summary.shared_context_patch_count for summary in export.revision_summaries
    ] == [2, 2, 2]
    assert [
        summary.shared_context_graphs for summary in export.revision_summaries
    ] == [["ontology", "shapes"], ["ontology", "shapes"], ["ontology", "shapes"]]
    assert [
        item.semantic_risk_level
        for item in export.bundle_summary.next_action_queue_items
    ] == [
        "attention",
        "attention",
        "attention",
    ]
    assert all(
        summary.semantic_risk_reasons for summary in export.revision_summaries
    )
    assert "## Modelling Choice Summary" in exported
    assert "repair_diagnostic" in exported
    assert "pattern_first_alternative" in exported
    assert "Shared ontology/shapes context applies to 3 row(s)" in exported
    assert "## Review Queues" in exported
    assert "Shared ontology or shapes context patches are present" in exported
    assert (
        "- Next action - apply after review: "
        f"`{revision_iris[1]}`, `{revision_iris[2]}`"
    ) in exported
    assert (
        f"- Next action - repair or replace: `{revision_iris[0]}`"
    ) in exported
    assert f"- Repair review: `{revision_iris[0]}`" in exported
    assert "Temporal scopes must name the timezone evidence column." in exported


def test_stage_systematisation_routes_profile_sources_per_framing(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    status_column = "https://example.test/project#OrdersStatus"
    status_value_type = "https://example.test/project#OperationalStatusCode"
    evidence = "https://example.test/project#OrdersProfileEvidence"

    db.record_map_dataset(dataset, label="Orders", is_table=True)
    db.record_map_column(
        status_column,
        table_iri=dataset,
        column_name="status",
    )
    profile = db.record_dataset_profile(
        dataset,
        summary="Orders were profiled for status semantics.",
        evidence_summary="Synthetic profile run for status value-type review.",
        evidence_sources=["test://orders-profile"],
        evidence_iri=evidence,
        sample_size=12,
        sample_scope="All Orders rows.",
        sample_method="Synthetic full-table profile.",
        row_count=12,
        update_map_snapshot=False,
    )
    profile_iri = profile.observation.observation_iri
    route_group_key = "profile-route-group:orders-status-value-type"

    def route_source(step: str, semantic_move: str) -> dict[str, object]:
        return {
            "review_lane": "profile_type_review",
            "route_group_key": route_group_key,
            "route_step_key": f"profile-route-step:{step}",
            "semantic_move": semantic_move,
            "route_anchor_iris": [status_column, status_value_type],
            "duplicate_profile_observation_iris": [profile_iri],
            "type_advisory_indexes": [0],
        }

    define_source = route_source("define-value-type", "define_value_type")
    assert_source = route_source("assert-map-type", "assert_map_type")
    fallback_source = route_source("caveat-fallback", "caveat_fallback")

    draft = db.stage_systematisation(
        summary="Review status value-type alternatives",
        intent=(
            "Compare the direct ontology+map type framing with a pattern-only "
            "fallback for the same profile type finding."
        ),
        anchors=[dataset, status_column, status_value_type],
        supporting_observations=[profile_iri],
        evidence=[evidence],
        framings=[
            {
                "label": "Define and assert value type",
                "additions": [
                    {
                        "graph": "ontology",
                        "content": f"""
                            @prefix rc: <https://richcanopy.org/ns/rc#> .
                            @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                            <{status_value_type}> a rc:ValueType ;
                                rdfs:label "Operational status code" .
                        """,
                    },
                    {
                        "graph": "map",
                        "content": f"""
                            @prefix rc: <https://richcanopy.org/ns/rc#> .

                            <{status_column}> rc:valueType <{status_value_type}> .
                        """,
                    },
                ],
                "profile_route_sources": [define_source, assert_source],
            },
            {
                "label": "Pattern-only fallback",
                "graph": "patterns",
                "content": f"""
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    <https://example.test/project#StatusTypeFallbackPattern>
                        a rc:Pattern ;
                        rc:summary "Status values need semantic review." ;
                        rc:patternText "Status codes look domain-specific, but the project value type is not durable yet." ;
                        rc:rationale "Keep the type finding tentative if ontology and map promotion are premature." ;
                        rc:patternTarget <{status_column}> ;
                        rc:supportingObservation <{profile_iri}> .
                """,
                "profileRouteSources": [fallback_source],
            },
        ],
        validation_scope="all",
    )

    assert draft.profile_route_source_count == 3
    review = db.export_profile_insight_review_bundle(
        dataset,
        evidence,
        tmp_path / "status-type-review.md",
    )
    candidates = {
        candidate.revision_iri: candidate for candidate in review.candidates
    }
    direct_candidate = candidates[draft.staged_revisions[0].revision_iri]
    fallback_candidate = candidates[draft.staged_revisions[1].revision_iri]
    direct_groups = {
        group["review_lane"]: group for group in direct_candidate.profile_route_groups
    }
    fallback_groups = {
        group["review_lane"]: group
        for group in fallback_candidate.profile_route_groups
    }

    assert direct_groups["profile_type_review"]["match_strength"] == (
        "direct_action"
    )
    assert set(direct_groups["profile_type_review"]["direct_semantic_moves"]) == {
        "define_value_type",
        "assert_map_type",
    }
    assert "caveat_fallback" not in direct_groups["profile_type_review"][
        "direct_semantic_moves"
    ]
    assert fallback_groups["profile_type_review"]["match_strength"] == (
        "direct_action"
    )
    assert fallback_groups["profile_type_review"]["direct_semantic_moves"] == [
        "caveat_fallback"
    ]
    assert "define_value_type" not in fallback_groups["profile_type_review"][
        "direct_semantic_moves"
    ]
    assert "assert_map_type" not in fallback_groups["profile_type_review"][
        "direct_semantic_moves"
    ]
    assert set(review.closed_semantic_moves) == {
        "define_value_type",
        "assert_map_type",
        "caveat_fallback",
    }
    assert review.bulk_apply_allowed is False
    assert review.safe_single_apply_candidate_revision_iris == []
    assert review.semantic_apply_gate_counts["blocked_candidates"] == 2
    assert "semantic_or_support_candidate_present" in (
        review.semantic_apply_gate_blocking_reasons
    )
    assert direct_candidate.semantic_apply_role == "profile_type_candidate"
    assert direct_candidate.semantic_choice_group_key == route_group_key
    assert direct_candidate.apply_cardinality == (
        "one_semantic_choice_then_recheck"
    )
    assert direct_candidate.safe_single_apply_candidate is False
    assert direct_candidate.bulk_apply_allowed is False
    assert fallback_candidate.semantic_apply_role == (
        "semantic_fallback_candidate"
    )
    assert fallback_candidate.semantic_choice_group_key == route_group_key
    assert fallback_candidate.apply_cardinality == (
        "one_semantic_choice_then_recheck"
    )
    exported = (tmp_path / "status-type-review.md").read_text(encoding="utf-8")
    assert "### Semantic Apply Gate" in exported
    assert "Do not bulk apply this profile insight bundle" in exported
    assert "profile_type_candidate" in exported
    assert "semantic_fallback_candidate" in exported


