def test_record_claim_observation_writes_common_rdf_pattern(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    result = db.record_claim_observation(
        summary="The Enron body_top column is transformed message text.",
        claim_text="body_top stores text above reply separators after footer stripping.",
        claim_kind="rc:TransformationClaim",
        claim_targets=["https://example.test/enron#eml_messages_body_top"],
        observed_asset="https://example.test/enron#eml_messages",
        observed_at="2026-05-31T00:00:00Z",
        observed_by="urn:doxabase:test-agent",
        evidence_summary="README body processing section.",
        source_path="/home/james/github.com/jamtho/enron-emails/README.md",
        source_section="Body processing",
        start_line=186,
        end_line=191,
        source_kind="rc:DocumentationSource",
        confidence="rc:HighConfidence",
        observation_status="rc:Checked",
        proposed_assertions=[
            "https://example.test/enron#body_top_transformation_caveat",
        ],
    )

    assert result.claim_iri.startswith(
        "https://richcanopy.org/doxabase/generated/claim/"
    )
    assert result.source_span_iri is not None
    assert result.observation_triples > 0
    assert result.evidence_triples > 0
    assert db.validate_graph(scope="all").conforms

    claims = db.list_entities(
        type="rc:Claim",
        graph="observations",
        text="reply separators",
    )
    assert [claim.iri for claim in claims.entities] == [result.claim_iri]
    assert claims.entities[0].label == (
        "body_top stores text above reply separators after footer stripping."
    )

    context = db.describe_resource(result.claim_iri, graph="observations")
    outgoing_predicates = {triple.predicate for triple in context.outgoing}

    assert context.label == (
        "body_top stores text above reply separators after footer stripping."
    )
    assert "https://richcanopy.org/ns/rc#claimKind" in outgoing_predicates
    assert "https://richcanopy.org/ns/rc#claimTarget" in outgoing_predicates
    assert any(
        triple.subject == result.observation_iri
        and triple.predicate == "https://richcanopy.org/ns/rc#hasClaim"
        for triple in context.incoming
    )

    evidence_context = db.describe_resource(result.evidence_iri, graph="evidence")
    assert any(
        triple.predicate == "https://richcanopy.org/ns/rc#sourceSpan"
        and triple.object == result.source_span_iri
        for triple in evidence_context.outgoing
    )


def test_describe_resource_reports_counts_and_offsets(tmp_path: Path) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    hub = "https://example.test/project#Hub"
    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix rc: <https://richcanopy.org/ns/rc#> .
        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

        ex:Hub a rc:Dataset ;
            rdfs:label "Hub" ;
            ex:link ex:Item00, ex:Item01, ex:Item02, ex:Item03, ex:Item04,
                ex:Item05, ex:Item06, ex:Item07, ex:Item08, ex:Item09 .

        ex:Item00 ex:pointsTo ex:Hub .
        ex:Item01 ex:pointsTo ex:Hub .
        ex:Item02 ex:pointsTo ex:Hub .
        ex:Item03 ex:pointsTo ex:Hub .
        ex:Item04 ex:pointsTo ex:Hub .
        ex:Item05 ex:pointsTo ex:Hub .
        ex:Item06 ex:pointsTo ex:Hub .
        ex:Item07 ex:pointsTo ex:Hub .
        ex:Item08 ex:pointsTo ex:Hub .
        ex:Item09 ex:pointsTo ex:Hub .
        """,
        graph="map",
    )

    context = db.describe_resource(
        hub,
        graph="map",
        limit=3,
        outgoing_offset=2,
        incoming_offset=4,
    )

    assert context.outgoing_total_count == 12
    assert context.outgoing_returned_count == 3
    assert context.outgoing_omitted_count == 7
    assert context.outgoing_offset == 2
    assert len(context.outgoing) == 3
    assert context.incoming_total_count == 10
    assert context.incoming_returned_count == 3
    assert context.incoming_omitted_count == 3
    assert context.incoming_offset == 4
    assert len(context.incoming) == 3

    with pytest.raises(DoxaBaseError, match="outgoing_offset"):
        db.describe_resource(hub, outgoing_offset=-1)
    with pytest.raises(DoxaBaseError, match="incoming_offset"):
        db.describe_resource(hub, incoming_offset=-1)


def test_describe_resource_can_include_bounded_blank_node_closure(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    shape = "https://example.test/project#SignalShape"
    db.import_turtle(
        """
        @prefix ex: <https://example.test/project#> .
        @prefix sh: <http://www.w3.org/ns/shacl#> .
        @prefix xsd: <http://www.w3.org/2001/XMLSchema#> .
        @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

        ex:SignalShape a sh:NodeShape ;
            rdfs:label "Signal shape" ;
            sh:targetClass ex:Signal ;
            sh:property [
                sh:path ex:score ;
                sh:datatype xsd:decimal ;
                sh:message "Score is decimal." ;
                sh:qualifiedValueShape [
                    sh:path ex:source ;
                    sh:datatype xsd:string
                ]
            ] ;
            sh:property [
                sh:path ex:status ;
                sh:datatype xsd:string ;
                sh:message "Status is text."
            ] .
        """,
        graph="shapes",
    )

    default_context = db.describe_resource(shape, graph="shapes")
    assert default_context.include_blank_node_closure is False
    assert default_context.blank_node_triples == []
    assert any(
        triple.predicate == "http://www.w3.org/ns/shacl#property"
        and triple.object_kind == "bnode"
        for triple in default_context.outgoing
    )

    context = db.describe_resource(
        shape,
        graph="shapes",
        include_blank_node_closure=True,
        blank_node_depth=2,
        blank_node_limit=4,
    )

    assert context.include_blank_node_closure is True
    assert context.blank_node_depth == 2
    assert context.blank_node_limit == 4
    assert context.blank_node_returned_count == 4
    assert context.blank_node_total_count > context.blank_node_returned_count
    assert context.blank_node_omitted_count == (
        context.blank_node_total_count - context.blank_node_returned_count
    )
    assert context.blank_node_depth_exhausted is False
    assert context.blank_node_unvisited_count == 0
    blank_node_predicates = {triple.predicate for triple in context.blank_node_triples}
    assert "http://www.w3.org/ns/shacl#path" in blank_node_predicates
    assert "http://www.w3.org/ns/shacl#datatype" in blank_node_predicates

    shallow_context = db.describe_resource(
        shape,
        graph="shapes",
        include_blank_node_closure=True,
        blank_node_depth=1,
    )
    assert shallow_context.blank_node_depth_exhausted is True
    assert shallow_context.blank_node_unvisited_count == 1

    with pytest.raises(DoxaBaseError, match="blank_node_depth"):
        db.describe_resource(shape, include_blank_node_closure=True, blank_node_depth=-1)
    with pytest.raises(DoxaBaseError, match="blank_node_limit"):
        db.describe_resource(shape, include_blank_node_closure=True, blank_node_limit=0)


def test_record_query_result_writes_query_source_evidence(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    db.record_map_dataset(dataset, label="Orders", is_table=True)

    result = db.record_query_result(
        summary="Orders paid-count query returned two rows.",
        observed_asset=dataset,
        execution_status="succeeded",
        engine="python-csv",
        query_source_path="queries/orders_paid_count.sql",
        query_source_section="paid-count aggregate",
        start_line=3,
        end_line=5,
        query_hash="sha256:abc123",
        result_sources=["/tmp/orders-paid-count.json"],
        scanned_source_paths=["warehouse/orders.csv"],
        sample_size=3,
        sample_scope="All rows in the scratch Orders CSV.",
        sample_method="External read-only aggregate query.",
        row_count=2,
        profile_metrics=[
            {
                "metric": "rc:MaximumValue",
                "value": "31.75",
                "datatype": "xsd:decimal",
            }
        ],
    )

    assert result.observation_type == "profile"
    assert result.execution_status == "succeeded"
    assert result.engine == "python-csv"
    assert result.query_hash == "sha256:abc123"
    assert result.source_span_iri is not None
    assert result.scanned_source_paths == ["warehouse/orders.csv"]
    assert len(result.scanned_source_span_iris) == 1
    assert result.evidence_triples > result.source_span_triples > 0
    assert [action.tool_name for action in result.suggested_next_actions] == [
        "describe_profile_run",
        "describe_query_context",
    ]
    assert result.suggested_next_actions[0].arguments == {
        "dataset_iri": dataset,
        "evidence_iri": result.evidence_iri,
    }
    assert result.suggested_next_actions[1].arguments == {"iri": dataset}
    assert result.suggested_next_calls == [
        (
            f"describe_profile_run(dataset_iri='{dataset}', "
            f"evidence_iri='{result.evidence_iri}')"
        ),
        f"describe_query_context(iri='{dataset}')",
    ]
    assert db.validate_graph(scope="all").conforms

    evidence = db.describe_resource(result.evidence_iri, graph="evidence")
    assert any(
        triple.predicate == RC + "sourceSpan"
        and triple.object == result.source_span_iri
        for triple in evidence.outgoing
    )
    assert any(
        triple.predicate == RC + "sourceSpan"
        and triple.object == result.scanned_source_span_iris[0]
        for triple in evidence.outgoing
    )
    outgoing = {(triple.predicate, triple.object) for triple in evidence.outgoing}
    assert (RC + "queryExecutionStatus", "succeeded") in outgoing
    assert (RC + "queryEngine", "python-csv") in outgoing
    assert (RC + "queryHash", "sha256:abc123") in outgoing
    source_span = db.describe_resource(result.source_span_iri, graph="evidence")
    span_outgoing = {
        (triple.predicate, triple.object) for triple in source_span.outgoing
    }
    assert (RC + "sourcePath", "queries/orders_paid_count.sql") in span_outgoing
    assert (RC + "sourceKind", RC + "QuerySource") in span_outgoing
    scanned_span = db.describe_resource(
        result.scanned_source_span_iris[0],
        graph="evidence",
    )
    scanned_span_outgoing = {
        (triple.predicate, triple.object) for triple in scanned_span.outgoing
    }
    assert (RC + "sourcePath", "warehouse/orders.csv") in scanned_span_outgoing
    assert (RC + "sourceKind", RC + "DataSampleSource") in scanned_span_outgoing

    matches = db.search("paid-count", graph="observations")
    assert result.observation_iri in {match.iri for match in matches.matches}


def test_record_query_result_preserves_database_relation_source_handle(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#WarehouseOrders"
    storage = db.record_map_storage_access(
        "https://example.test/project#warehouse_orders_database_storage",
        label="Warehouse orders database connection",
        storage_protocol="rc:DatabaseStorage",
        location_kind="connection",
        storage_root="warehouse-prod",
        path_templates=["mart.orders"],
        endpoint_profile="warehouse-prod",
        credential_reference="profile:warehouse-readonly",
        layout_verification_status="rc:VerifiedByQueryLayout",
    )
    layout = db.record_map_physical_layout(
        "https://example.test/project#warehouse_orders_table_layout",
        file_format="rc:PostgreSQLTable",
        layout_verification_status="rc:VerifiedByQueryLayout",
    )
    db.record_map_dataset(
        dataset,
        label="Warehouse orders",
        is_table=True,
        storage_accesses=[storage.iri],
        physical_layouts=[layout.iri],
        layout_verification_status="rc:VerifiedByQueryLayout",
    )
    plan = db.draft_query_plan(dataset)

    assert plan.handoff_kind == "database_relation_handoff"
    assert plan.scan.relation_identifier == "mart.orders"
    assert plan.scan.connection_reference == "warehouse-prod"
    assert plan.scan.uri_template is None

    relation_handle = (
        f"{plan.scan.connection_reference}:{plan.scan.relation_identifier}"
    )
    result = db.record_query_result(
        summary=(
            "Warehouse Orders status aggregate ran through an external "
            "database client after the database relation handoff."
        ),
        observed_asset=dataset,
        execution_status="succeeded",
        engine="external-postgres-client",
        query_source_path=str(tmp_path / "orders_status_summary.sql"),
        result_sources=[str(tmp_path / "orders_status_summary.result.json")],
        scanned_source_paths=[relation_handle],
    )

    assert result.observation_type == "observation"
    assert result.scanned_source_paths == [relation_handle]
    scanned_span = db.describe_resource(
        result.scanned_source_span_iris[0],
        graph="evidence",
    )
    scanned_span_outgoing = {
        (triple.predicate, triple.object) for triple in scanned_span.outgoing
    }
    assert (RC + "sourcePath", relation_handle) in scanned_span_outgoing
    assert (RC + "sourceKind", RC + "DataSampleSource") in scanned_span_outgoing
    evidence_slice = db.describe_context_slice(
        result.evidence_iri,
        profile="resource_brief",
        max_triples=80,
    )
    assert result.scanned_source_span_iris[0] in {
        resource.iri for resource in evidence_slice.resources
    }
    assert db.validate_graph(scope="all").conforms


def test_record_query_result_rejects_conflicting_source_span_reuse_without_mutation(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    source_span = "https://example.test/evidence#orders-paid-count-query-span"
    db.record_map_dataset(dataset, label="Orders", is_table=True)

    first = db.record_query_result(
        summary="Orders paid-count query returned two rows.",
        observed_asset=dataset,
        execution_status="succeeded",
        engine="python-csv",
        query_source_path="queries/orders_paid_count.sql",
        query_source_section="paid-count aggregate",
        start_line=3,
        end_line=5,
        result_sources=["/tmp/orders-paid-count.json"],
        source_span_iri=source_span,
    )
    assert first.source_span_iri == source_span
    before_counts = _mutable_graph_counts(db)

    with pytest.raises(DoxaBaseError, match="source_span_iri.*conflicting"):
        db.record_query_result(
            summary="Orders paid-count rerun used a different query file.",
            observed_asset=dataset,
            execution_status="succeeded",
            engine="python-csv",
            query_source_path="queries/orders_paid_count_v2.sql",
            query_source_section="paid-count aggregate",
            start_line=3,
            end_line=5,
            result_sources=["/tmp/orders-paid-count-v2.json"],
            source_span_iri=source_span,
        )

    assert _mutable_graph_counts(db) == before_counts
    assert db.validate_graph(scope="all").conforms

    reused = db.record_query_result(
        summary="Orders paid-count query reran from the same source range.",
        observed_asset=dataset,
        execution_status="succeeded",
        engine="python-csv",
        query_source_path="queries/orders_paid_count.sql",
        query_source_section="paid-count aggregate",
        start_line=3,
        end_line=5,
        result_sources=["/tmp/orders-paid-count-repeat.json"],
        source_span_iri=source_span,
    )

    assert reused.source_span_iri == source_span
    assert db.validate_graph(scope="all").conforms


