def test_profile_summary_surfaces_run_candidates_in_mixed_profile_history(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    older_evidence = "https://example.test/project#OlderProfileEvidence"
    newer_evidence = "https://example.test/project#NewerProfileRunEvidence"

    db.record_dataset_profile(
        dataset,
        summary="Older dataset-only profile result.",
        evidence_summary="Older one-off profiling pass.",
        evidence_sources=["test://orders-profile-old"],
        evidence_iri=older_evidence,
        row_count=80,
        map_label="Orders",
        is_table=True,
    )
    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Newer profile bundle over dataset and columns.",
        evidence_summary="Newer shared profiling pass.",
        evidence_sources=["test://orders-profile-new"],
        shared_evidence_iri=newer_evidence,
        sample_size=100,
        sample_scope="All rows in the local Orders table.",
        sample_method="DuckDB full-table profiling query.",
        row_count=100,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": "https://example.test/project#OrdersStatus",
                "column_name": "status",
                "summary": "Status values were profiled.",
                "distinct_count": 3,
            },
            {
                "column_iri": "https://example.test/project#OrdersAmount",
                "column_name": "amount",
                "summary": "Amount values were profiled.",
                "null_count": 0,
            },
        ],
    )

    description = db.describe_dataset(dataset)

    assert description.profile_summary.returned_profile_count == 4
    assert description.profile_summary.evidence_profile_counts == {
        newer_evidence: 3,
        older_evidence: 1,
    }
    assert description.profile_summary.shared_evidence_iris == []
    assert [
        candidate.evidence_iri
        for candidate in description.profile_summary.profile_run_candidates
    ] == [newer_evidence]
    run_candidate = description.profile_summary.profile_run_candidates[0]
    assert run_candidate.returned_profile_count == 3
    assert run_candidate.dataset_profile_row_counts == [100]
    assert run_candidate.dataset_profile_row_count_bases == {"100": ["full_scan"]}
    assert run_candidate.row_count_snapshot_matches is False
    assert run_candidate.row_count_snapshot_basis is None
    assert set(run_candidate.profile_observation_iris) == {
        bundle.dataset_profile.observation.observation_iri,
        *(
            column_profile.observation.observation_iri
            for column_profile in bundle.column_profiles
        ),
    }
    assert run_candidate.shared_by_all_returned_profiles is False


def test_profile_run_candidates_are_count_ranked_and_ignore_singletons(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    evidence_a = "https://example.test/project#EvidenceA"
    evidence_b = "https://example.test/project#EvidenceB"
    evidence_c = "https://example.test/project#EvidenceC"
    evidence_singleton = "https://example.test/project#EvidenceSingleton"
    status_column = "https://example.test/project#OrdersStatus"
    amount_column = "https://example.test/project#OrdersAmount"

    db.record_map_dataset(dataset, label="Orders", is_table=True)
    db.record_map_column(status_column, column_name="status", table_iri=dataset)
    db.record_map_column(amount_column, column_name="amount", table_iri=dataset)
    for index in range(3):
        db.record_observation(
            summary=f"A-backed profile {index}",
            observation_type="profile",
            observed_asset=dataset,
            evidence_summary="Profile pass A.",
            evidence_iri=evidence_a,
        )
    for index in range(2):
        db.record_observation(
            summary=f"B-backed profile {index}",
            observation_type="profile",
            observed_asset=dataset,
            observed_column=status_column,
            evidence_summary="Profile pass B.",
            evidence_iri=evidence_b,
        )
        db.record_observation(
            summary=f"C-backed profile {index}",
            observation_type="profile",
            observed_asset=dataset,
            observed_column=amount_column,
            evidence_summary="Profile pass C.",
            evidence_iri=evidence_c,
        )
    db.record_observation(
        summary="One-off singleton profile",
        observation_type="profile",
        observed_asset=dataset,
        evidence_summary="One-off profile.",
        evidence_iri=evidence_singleton,
    )

    candidates = db.describe_dataset(dataset).profile_summary.profile_run_candidates

    assert [
        (
            candidate.evidence_iri,
            candidate.returned_profile_count,
            candidate.dataset_profile_row_counts,
            candidate.dataset_profile_row_count_bases,
            candidate.row_count_snapshot_matches,
            candidate.row_count_snapshot_basis,
        )
        for candidate in candidates
    ] == [
        (evidence_a, 3, [], {}, False, None),
        (evidence_b, 2, [], {}, False, None),
        (evidence_c, 2, [], {}, False, None),
    ]
    assert all(
        not candidate.shared_by_all_returned_profiles for candidate in candidates
    )
    assert all(candidate.profile_observation_iris for candidate in candidates)


def test_profile_run_candidates_prefer_row_count_snapshot_match_on_ties(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Orders"
    status_column = "https://example.test/project#OrdersStatus"
    storage = "https://example.test/project#OrdersStorage"
    layout = "https://example.test/project#OrdersParquetLayout"
    old_evidence = "https://example.test/project#AOldProfileEvidence"
    matching_evidence = "https://example.test/project#ZMatchingProfileEvidence"

    db.record_map_storage_access(
        storage,
        label="Orders local storage",
        storage_protocol="rc:LocalFilesystemStorage",
        location_kind="directory",
        storage_root=str(tmp_path / "warehouse"),
        datasets=[dataset],
    )
    db.record_map_physical_layout(
        layout,
        file_format="rc:Parquet",
        layout_verification_status="rc:VerifiedByQueryLayout",
        datasets=[dataset],
    )
    db.record_map_dataset(
        dataset,
        label="Orders",
        is_table=True,
        row_count_snapshot=120,
        path_templates=["orders/dt={date}.parquet"],
        storage_accesses=[storage],
        physical_layouts=[layout],
        layout_verification_status="rc:VerifiedByQueryLayout",
    )
    db.record_map_column(
        status_column,
        table_iri=dataset,
        column_name="status",
    )
    db.record_profile_bundle(
        dataset,
        dataset_summary="Older profile run with stale row count.",
        evidence_summary="Older profile evidence.",
        evidence_sources=["test://orders-profile-old"],
        shared_evidence_iri=old_evidence,
        row_count=80,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": status_column,
                "column_name": "status",
                "summary": "Status was profiled in the older run.",
            }
        ],
    )
    db.record_profile_bundle(
        dataset,
        dataset_summary="Matching profile run with current row count.",
        evidence_summary="Matching profile evidence.",
        evidence_sources=["test://orders-profile-current"],
        shared_evidence_iri=matching_evidence,
        row_count=120,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": status_column,
                "column_name": "status",
                "summary": "Status was profiled in the matching run.",
            }
        ],
    )

    description = db.describe_dataset(dataset)

    assert [
        (
            candidate.evidence_iri,
            candidate.returned_profile_count,
            candidate.dataset_profile_row_counts,
            candidate.dataset_profile_row_count_bases,
            candidate.row_count_snapshot_matches,
            candidate.row_count_snapshot_basis,
        )
        for candidate in description.profile_summary.profile_run_candidates
    ] == [
        (matching_evidence, 2, [120], {"120": ["unknown"]}, True, "unknown"),
        (old_evidence, 2, [80], {"80": ["unknown"]}, False, None),
    ]

    context = db.describe_query_context(dataset)

    assert context.suggested_next_actions[0].tool_name == "describe_profile_run"
    assert context.suggested_next_actions[0].arguments == {
        "dataset_iri": dataset,
        "evidence_iri": matching_evidence,
    }
    assert [
        action.tool_name for action in context.suggested_next_actions[:3]
    ] == [
        "describe_profile_run",
        "describe_profile_run",
        "draft_query_plan",
    ]
    assert context.suggested_next_actions[1].action_label == (
        "Inspect additional profile run evidence"
    )
    assert context.suggested_next_actions[1].arguments == {
        "dataset_iri": dataset,
        "evidence_iri": old_evidence,
    }
    assert "sampled, unknown, or mixed basis" in (
        context.suggested_next_actions[1].reason
    )
    matching_run = db.describe_profile_run(dataset, matching_evidence)
    old_run = db.describe_profile_run(dataset, old_evidence)
    assert matching_run.row_count_snapshot == 120
    assert matching_run.dataset_profile_row_counts == [120]
    assert matching_run.dataset_profile_row_count_bases == {"120": ["unknown"]}
    assert matching_run.row_count_snapshot_matches is True
    assert matching_run.row_count_snapshot_basis == "unknown"
    assert old_run.row_count_snapshot == 120
    assert old_run.dataset_profile_row_counts == [80]
    assert old_run.dataset_profile_row_count_bases == {"80": ["unknown"]}
    assert old_run.row_count_snapshot_matches is False
    assert old_run.row_count_snapshot_basis is None


def test_describe_profile_run_returns_wide_shared_evidence_run(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#WideOrders"
    shared_evidence = "https://example.test/project#WideOrdersProfileRunEvidence"

    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Wide Orders dataset was profiled with many columns.",
        evidence_summary="Wide profile pass.",
        evidence_sources=["test://wide-orders-profile"],
        shared_evidence_iri=shared_evidence,
        row_count=100,
        map_label="Wide Orders",
        is_table=True,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": f"https://example.test/project#WideOrdersColumn{index}",
                "column_name": f"column_{index}",
                "summary": f"Wide Orders column {index} was profiled.",
                "distinct_count": index + 1,
            }
            for index in range(8)
        ],
    )

    bounded = db.describe_dataset(dataset)
    assert bounded.profile_summary.returned_profile_count == 6
    assert bounded.profile_summary.total_profile_count == 9
    assert bounded.profile_summary.omitted_profile_count == 3
    assert (
        bounded.profile_summary.profile_run_candidates[0].returned_profile_count
        == 6
    )

    profile_run = db.describe_profile_run(dataset, shared_evidence)

    assert profile_run.evidence_iri == shared_evidence
    assert profile_run.returned_dataset_profile_count == 1
    assert profile_run.returned_mapped_column_profile_count == 0
    assert profile_run.returned_unmapped_column_profile_count == 8
    assert profile_run.returned_profile_count == 9
    assert profile_run.total_profile_count == 9
    assert profile_run.omitted_profile_count == 0
    assert set(profile_run.profile_observation_iris) == {
        bundle.dataset_profile.observation.observation_iri,
        *(
            column_profile.observation.observation_iri
            for column_profile in bundle.column_profiles
        ),
    }
    assert "no separate persisted profile-run node" in profile_run.retrieval_note

    capped = db.describe_profile_run(dataset, shared_evidence, limit=3)

    assert capped.returned_profile_count == 3
    assert capped.total_profile_count == 9
    assert capped.omitted_profile_count == 6
    assert len(capped.profile_observation_iris) == 3


def test_describe_profile_run_works_for_observation_only_dataset(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#ObservationOnlyOrders"
    shared_evidence = "https://example.test/project#ObservationOnlyProfileRunEvidence"

    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Observation-only Orders profile.",
        evidence_summary="Observation-only profile pass.",
        evidence_sources=["test://observation-only-profile"],
        shared_evidence_iri=shared_evidence,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": "https://example.test/project#ObservationOnlyStatus",
                "column_name": "status",
                "summary": "Observation-only status profile.",
            }
        ],
    )

    assert bundle.handoff_entrypoints.map_dataset_recorded is False
    assert bundle.handoff_entrypoints.dataset_describe_available is False
    assert bundle.handoff_entrypoints.profile_run_available is True
    assert bundle.handoff_entrypoints.profile_observation_iris == [
        bundle.dataset_profile.observation.observation_iri,
        bundle.column_profiles[0].observation.observation_iri,
    ]
    assert bundle.handoff_entrypoints.suggested_next_calls[0] == (
        f"describe_profile_run('{dataset}', '{shared_evidence}')"
    )
    assert [
        action.tool_name for action in bundle.handoff_entrypoints.suggested_next_actions
    ] == [
        "describe_profile_run",
        "describe_context_slice",
    ]
    assert bundle.handoff_entrypoints.suggested_next_actions[0].arguments == {
        "dataset_iri": dataset,
        "evidence_iri": shared_evidence,
    }
    assert bundle.handoff_entrypoints.suggested_next_actions[-1].arguments == {
        "seed_iris": bundle.handoff_entrypoints.profile_observation_iris,
        "profile": "dataset_brief",
    }
    assert bundle.handoff_entrypoints.suggested_next_calls[-1] == (
        "describe_context_slice("
        f"{bundle.handoff_entrypoints.profile_observation_iris!r}, "
        "profile='dataset_brief')"
    )
    assert not any(
        call.startswith("describe_dataset")
        for call in bundle.handoff_entrypoints.suggested_next_calls
    )
    assert "No map dataset subject" in bundle.handoff_entrypoints.handoff_note

    with pytest.raises(DoxaBaseError, match="was not found") as exc_info:
        db.describe_dataset(dataset)
    error_message = str(exc_info.value)
    assert "profile observation(s) reference this dataset" in error_message
    assert "describe_profile_run" in error_message
    assert shared_evidence in error_message
    assert "seed describe_context_slice" in error_message
    assert "record_map_dataset" in error_message

    profile_run = db.describe_profile_run(dataset, shared_evidence)

    assert profile_run.dataset.iri == dataset
    assert profile_run.returned_dataset_profile_count == 1
    assert profile_run.returned_unmapped_column_profile_count == 1
    assert profile_run.returned_profile_count == 2


def test_profile_bundle_handoff_distinguishes_existing_map_context_without_snapshot(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#ExistingMapOrders"
    status_column = "https://example.test/project#ExistingMapOrdersStatus"
    shared_evidence = "https://example.test/project#ExistingMapOrdersProfileEvidence"
    db.record_map_dataset(dataset, label="Existing Map Orders", is_table=True)

    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Existing map Orders profile stayed observation-only.",
        evidence_summary="Profile pass over existing map shell.",
        evidence_sources=["test://existing-map-orders-profile"],
        shared_evidence_iri=shared_evidence,
        row_count=120,
        update_map_snapshot=False,
        profile_metrics=[{"metric": "rc:MeanValue", "value": 4.5}],
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": status_column,
                "column_name": "status",
                "summary": "Existing map Orders status values were profiled.",
                "distinct_count": 3,
                "profile_metrics": [{"metric": "rc:MaximumValue", "value": 9}],
            }
        ],
    )

    assert bundle.dataset_profile.map_dataset is None
    assert bundle.handoff_entrypoints.map_dataset_recorded is False
    assert bundle.handoff_entrypoints.dataset_describe_available is True
    assert bundle.handoff_entrypoints.profile_run_available is True
    assert bundle.handoff_entrypoints.suggested_next_calls[:2] == [
        f"describe_dataset('{dataset}')",
        f"describe_profile_run('{dataset}', '{shared_evidence}')",
    ]
    assert bundle.handoff_entrypoints.suggested_next_calls[2] == (
        f"draft_profile_map_updates('{dataset}', '{shared_evidence}')"
    )
    assert "already existed" in bundle.handoff_entrypoints.handoff_note
    assert "did not write dataset map facts" in bundle.handoff_entrypoints.handoff_note
    assert "row-count snapshot" in bundle.handoff_entrypoints.handoff_note

    description = db.describe_dataset(dataset)
    assert description.row_count_snapshot is None
    assert description.profile_summary.returned_profile_count == 2

    profile_run = db.describe_profile_run(dataset, shared_evidence)
    assert profile_run.returned_profile_count == 2
    assert set(profile_run.profile_observation_iris) == set(
        bundle.handoff_entrypoints.profile_observation_iris
    )

    context_slice = db.describe_context_slice(
        bundle.handoff_entrypoints.profile_observation_iris,
        profile="dataset_brief",
    )
    assert {
        profile.iri for profile in context_slice.seed_profile_observations
    } == set(bundle.handoff_entrypoints.profile_observation_iris)
    assert context_slice.route_counts["observed_profile_metric"] == 2


def test_profile_bundle_mixed_run_handoff_actions_route_without_guessing(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    base = "https://example.test/handoff-trial#"
    mixed = f"{base}MixedOrders"
    amount = f"{base}MixedOrdersAmount"
    run_a = f"{base}MixedOrdersProfileRunA"
    run_b = f"{base}MixedOrdersProfileRunB"
    shadow = f"{base}ShadowEvents"
    shadow_run = f"{base}ShadowEventsObservationOnlyRun"

    def run_handoff_actions(actions) -> None:
        for action in actions:
            if action.tool_name == "describe_dataset":
                db.describe_dataset(**action.arguments)
            elif action.tool_name == "describe_profile_run":
                db.describe_profile_run(**action.arguments)
            elif action.tool_name == "draft_profile_map_updates":
                db.draft_profile_map_updates(**action.arguments)
            elif action.tool_name == "describe_context_slice":
                db.describe_context_slice(**action.arguments)
            else:
                raise AssertionError(f"Unexpected action {action.tool_name!r}")

    run_a_bundle = db.record_profile_bundle(
        mixed,
        dataset_summary="Mixed orders run A profile.",
        observed_at="2026-06-01T00:00:00Z",
        evidence_summary="Mixed orders profile run A.",
        evidence_sources=["test://mixed-orders/run-a"],
        shared_evidence_iri=run_a,
        row_count=1000,
        map_label="Mixed Orders",
        is_table=True,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": amount,
                "column_name": "amount",
                "summary": "Run A amount values were profiled.",
                "null_count": 0,
                "update_map_column": True,
                "physical_type": "rc:Decimal",
                "nullable": False,
            },
            *(
                {
                    "column_iri": f"{base}MixedOrdersRunAExtra{index}",
                    "column_name": f"run_a_extra_{index}",
                    "summary": f"Run A extra column {index} was profiled.",
                    "distinct_count": index + 1,
                }
                for index in range(4)
            ),
        ],
    )
    run_b_bundle = db.record_profile_bundle(
        mixed,
        dataset_summary="Mixed orders run B profile over existing map context.",
        observed_at="2026-06-02T00:00:00Z",
        evidence_summary="Mixed orders profile run B.",
        evidence_sources=["test://mixed-orders/run-b"],
        shared_evidence_iri=run_b,
        row_count=1200,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": amount,
                "column_name": "amount",
                "summary": "Run B amount values were profiled without map writes.",
                "null_count": 1,
            },
            *(
                {
                    "column_iri": f"{base}MixedOrdersRunBExtra{index}",
                    "column_name": f"run_b_extra_{index}",
                    "summary": f"Run B extra column {index} was profiled.",
                    "distinct_count": index + 2,
                }
                for index in range(3)
            ),
        ],
    )
    shadow_bundle = db.record_profile_bundle(
        shadow,
        dataset_summary="Shadow events profile stayed observation-only.",
        observed_at="2026-06-03T00:00:00Z",
        evidence_summary="Shadow events observation-only run.",
        evidence_sources=["test://shadow-events/profile"],
        shared_evidence_iri=shadow_run,
        update_map_snapshot=False,
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": f"{base}ShadowEventsKind",
                "column_name": "kind",
                "summary": "Shadow event kind was profiled.",
            },
            {
                "column_iri": f"{base}ShadowEventsPayload",
                "column_name": "payload",
                "summary": "Shadow event payload was profiled.",
            },
        ],
    )

    assert run_a_bundle.handoff_entrypoints.updated_map_column_iris == [amount]
    assert run_a_bundle.handoff_entrypoints.mapped_profiled_column_iris == [amount]
    assert run_b_bundle.handoff_entrypoints.updated_map_column_iris == []
    assert run_b_bundle.handoff_entrypoints.map_column_iris == []
    assert run_b_bundle.handoff_entrypoints.mapped_profiled_column_iris == [amount]
    assert shadow_bundle.handoff_entrypoints.dataset_describe_available is False
    assert [
        action.tool_name
        for action in shadow_bundle.handoff_entrypoints.suggested_next_actions
    ] == ["describe_profile_run", "describe_context_slice"]

    all_actions = [
        *run_a_bundle.handoff_entrypoints.suggested_next_actions,
        *run_b_bundle.handoff_entrypoints.suggested_next_actions,
        *shadow_bundle.handoff_entrypoints.suggested_next_actions,
    ]
    assert len(all_actions) == 12
    run_handoff_actions(all_actions)

    description = db.describe_dataset(mixed)
    summary = description.profile_summary
    assert summary.total_profile_count == 11
    assert summary.returned_profile_count == 9
    assert summary.omitted_profile_count == 2
    assert summary.shared_evidence_iris == []
    candidates = {
        candidate.evidence_iri: candidate
        for candidate in summary.profile_run_candidates
    }
    assert set(candidates) == {run_a, run_b}
    assert candidates[run_b].returned_profile_count == 5
    assert candidates[run_a].returned_profile_count == 4
    assert all(
        candidate.shared_by_all_returned_profiles is False
        for candidate in candidates.values()
    )

    run_a_full = db.describe_profile_run(mixed, run_a)
    run_b_full = db.describe_profile_run(mixed, run_b)
    shadow_full = db.describe_profile_run(shadow, shadow_run)
    assert run_a_full.returned_profile_count == 6
    assert run_b_full.returned_profile_count == 5
    assert shadow_full.returned_profile_count == 3
    assert set(run_a_full.profile_observation_iris) == set(
        run_a_bundle.handoff_entrypoints.profile_observation_iris
    )
    assert set(run_b_full.profile_observation_iris) == set(
        run_b_bundle.handoff_entrypoints.profile_observation_iris
    )
    assert set(shadow_full.profile_observation_iris) == set(
        shadow_bundle.handoff_entrypoints.profile_observation_iris
    )


def test_draft_profile_map_updates_surfaces_review_candidates(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/project#Payments"
    status_column = "https://example.test/project#PaymentsStatus"
    amount_column = "https://example.test/project#PaymentsAmount"
    settlement_column = "https://example.test/project#PaymentsSettlementMethod"
    evidence = "https://example.test/project#PaymentsProfileRunEvidence"
    project_metric = "https://example.test/project#CompletenessRatio"

    db.record_map_dataset(
        dataset,
        label="Payments",
        is_table=True,
        row_count_snapshot=10,
    )
    db.record_map_column(
        status_column,
        table_iri=dataset,
        column_name="status",
        nullable=False,
    )
    db.record_map_column(
        amount_column,
        table_iri=dataset,
        column_name="amount",
        nullable=False,
    )

    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Payments were profiled with a full-table scan.",
        evidence_summary="Synthetic profile run.",
        evidence_sources=["test://payments-profile"],
        shared_evidence_iri=evidence,
        sample_size=12,
        sample_scope="All rows in the test Payments table.",
        sample_method="DuckDB full-table aggregate profile.",
        row_count=12,
        update_map_snapshot=False,
        profile_metrics=[
            {
                "metric": project_metric,
                "value": "0.90",
                "datatype": "xsd:decimal",
            }
        ],
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": status_column,
                "column_name": "status",
                "summary": "Status had nulls in the full scan.",
                "null_count": 2,
                "distinct_count": 3,
            },
            {
                "column_iri": amount_column,
                "column_name": "amount",
                "summary": "Amount had no nulls in the full scan.",
                "null_count": 0,
                "distinct_count": 12,
            },
            {
                "column_iri": settlement_column,
                "column_name": "settlement_method",
                "summary": "Settlement method was observed but is unmapped.",
                "null_count": 0,
                "distinct_count": 2,
            },
        ],
    )
    profile_pattern = db.record_pattern(
        summary="Payments profile run supports map updates.",
        pattern_text=(
            "The Payments profile run observed row-count and column-nullability "
            "findings that should travel with staged map updates."
        ),
        rationale=(
            "The profile map update lane should preserve same-evidence "
            "profile-pattern support instead of requiring a second lookup."
        ),
        pattern_targets=[dataset, status_column],
        supporting_observations=bundle.handoff_entrypoints.profile_observation_iris,
        evidence_iri=evidence,
        map_implications=[dataset, status_column, settlement_column],
    )
    metric_pattern = db.record_pattern(
        summary="Payments completeness ratio needs vocabulary.",
        pattern_text=(
            "The Payments profile run used a project-specific completeness ratio "
            "that should be reviewed in the metric vocabulary lane."
        ),
        rationale=(
            "Sharing profile observations should not automatically make a "
            "metric-vocabulary pattern supporting context for staged map facts."
        ),
        pattern_targets=[project_metric],
        supporting_observations=bundle.handoff_entrypoints.profile_observation_iris,
        evidence_iri=evidence,
        map_implications=[project_metric],
    )
    unrelated_same_evidence_pattern = db.record_pattern(
        summary="Refunds profile evidence should stay separate.",
        pattern_text=(
            "This pattern intentionally shares the Payments profile evidence "
            "but targets a different asset and map implication."
        ),
        rationale=(
            "Same evidence alone should not make a pattern supporting context "
            "for profile-derived Payments map updates."
        ),
        pattern_targets=["https://example.test/project#Refunds"],
        evidence_iri=evidence,
        map_implications=["https://example.test/project#RefundsReason"],
    )

    draft = db.draft_profile_map_updates(dataset, evidence)

    assert draft.map_dataset_found is True
    assert draft.evidence_iri == evidence
    assert draft.pending_staged_profile_update_iris == []
    assert draft.pending_staged_profile_update_count == 0
    assert len(draft.profile_observation_iris) == 4
    assert "read-only review context" in draft.review_note
    assert draft.recommendation_count == 3
    assert draft.representative_recommendation_indexes == [0, 1, 2]
    assert [
        (
            recommendation.recommendation_index,
            recommendation.kind,
            recommendation.resource.iri,
        )
        for recommendation in draft.recommendations
    ] == [
        (0, "dataset_row_count_snapshot", dataset),
        (1, "column_nullable", status_column),
        (2, "unmapped_profiled_column", settlement_column),
    ]
    assert draft.suggested_next_actions[0].tool_name == (
        "stage_profile_map_updates"
    )
    assert draft.suggested_next_actions[0].arguments == {
        "dataset_iri": dataset,
        "evidence_iri": evidence,
        "accepted_recommendation_indexes": [0, 1, 2],
        "supporting_patterns": [profile_pattern.pattern_iri],
    }
    assert unrelated_same_evidence_pattern.pattern_iri not in (
        draft.suggested_next_actions[0].arguments["supporting_patterns"]
    )
    assert metric_pattern.pattern_iri not in (
        draft.suggested_next_actions[0].arguments["supporting_patterns"]
    )
    assert draft.suggested_next_calls[0].startswith("stage_profile_map_updates(")
    assert list(draft.suggested_next_action_groups) == [
        "profile_map_updates",
        "metric_vocabulary_review",
    ]
    assert draft.suggested_next_actions == [
        *draft.suggested_next_action_groups["profile_map_updates"],
        *draft.suggested_next_action_groups["metric_vocabulary_review"],
    ]
    assert [
        action.tool_name
        for action in draft.suggested_next_action_groups["profile_map_updates"]
    ] == ["stage_profile_map_updates"]
    profile_map_action = draft.suggested_next_action_groups[
        "profile_map_updates"
    ][0]
    map_source = profile_map_action.source_profile_map_update
    assert map_source["review_lane"] == "profile_map_updates"
    assert map_source["route_group_key"].startswith("profile_map_updates:")
    assert map_source["route_step_key"].startswith("profile-route-step:")
    assert map_source["recommendation_indexes"] == [0, 1, 2]
    assert map_source["duplicate_group_keys"] == [
        draft.recommendations[index].duplicate_group_key for index in [0, 1, 2]
    ]
    assert map_source["route_anchor_iris"] == [
        dataset,
        status_column,
        settlement_column,
    ]
    assert [
        action.tool_name
        for action in draft.suggested_next_action_groups[
            "metric_vocabulary_review"
        ]
    ] == [
        "describe_context_slice",
        "list_entities",
        "stage_systematisation",
        "describe_pattern",
        "stage_pattern_promotion",
    ]
    metric_fallback_action = draft.suggested_next_action_groups[
        "metric_vocabulary_review"
    ][2]
    assert metric_fallback_action.arguments["profile_route_sources"] == [
        metric_fallback_action.source_profile_advisory
    ]
    assert metric_fallback_action.arguments["framings"][0]["graph"] == "patterns"
    metric_action_sources = [
        action.source_profile_advisory
        for action in draft.suggested_next_action_groups[
            "metric_vocabulary_review"
        ]
    ]
    assert {
        tuple(source["advisory_indexes"]) for source in metric_action_sources
    } == {(0,)}
    assert {
        source["advisory_kind"] for source in metric_action_sources
    } == {"metric_vocabulary_review"}
    assert {
        source["index_field"] for source in metric_action_sources
    } == {"metric_advisory_index"}
    assert {
        source["route_group_key"] for source in metric_action_sources
    } == {metric_action_sources[0]["route_group_key"]}
    assert all(
        source["route_group_key"].startswith("metric_vocabulary_review:")
        for source in metric_action_sources
    )
    assert all(
        source["route_step_key"].startswith("profile-route-step:")
        for source in metric_action_sources
    )
    assert {
        tuple(source["observed_metric_iris"]) for source in metric_action_sources
    } == {(draft.metric_advisories[0].observed_metric_iri,)}
    assert draft.suggested_next_call_groups["profile_map_updates"] == [
        draft.suggested_next_calls[0]
    ]
    staged_from_suggestion = db.stage_profile_map_updates(
        **draft.suggested_next_actions[0].arguments
    )
    assert staged_from_suggestion.staged_revision is not None
    described_staged = db.describe_staged_revision(
        staged_from_suggestion.staged_revision.revision_iri
    )
    assert {item.iri for item in described_staged.supporting_patterns} == {
        profile_pattern.pattern_iri
    }
    assert unrelated_same_evidence_pattern.pattern_iri not in {
        item.iri for item in described_staged.supporting_patterns
    }
    assert metric_pattern.pattern_iri not in {
        item.iri for item in described_staged.supporting_patterns
    }

    rerun_draft = db.draft_profile_map_updates(dataset, evidence)
    assert rerun_draft.pending_staged_profile_update_iris == [
        staged_from_suggestion.staged_revision.revision_iri
    ]
    assert rerun_draft.pending_staged_profile_update_count == 1
    assert "pending staged profile map update" in rerun_draft.review_note
    rerun_profile_map_actions = rerun_draft.suggested_next_action_groups[
        "profile_map_updates"
    ]
    assert [action.tool_name for action in rerun_profile_map_actions] == [
        "plan_staged_revision_recovery",
        "stage_profile_map_updates",
    ]
    pending_action = rerun_profile_map_actions[0]
    assert pending_action.arguments == {
        "revision_iris": [staged_from_suggestion.staged_revision.revision_iri]
    }
    pending_source = pending_action.source_profile_map_update
    assert pending_source["action_status"] == "already_pending"
    assert pending_source["pending_staged_profile_update_iris"] == [
        staged_from_suggestion.staged_revision.revision_iri
    ]
    assert pending_source["pending_staged_profile_update_count"] == 1
    duplicate_stage_action = rerun_profile_map_actions[1]
    assert "Pending staged profile map update" in duplicate_stage_action.reason
    duplicate_stage_source = duplicate_stage_action.source_profile_map_update
    assert duplicate_stage_source["action_status"] == (
        "available_after_pending_review"
    )
    assert duplicate_stage_source["pending_staged_profile_update_iris"] == [
        staged_from_suggestion.staged_revision.revision_iri
    ]
    assert rerun_draft.suggested_next_actions[0] == pending_action
    with pytest.raises(DoxaBaseError, match="pending staged profile map update"):
        db.stage_profile_map_updates(**duplicate_stage_action.arguments)
    forced_duplicate = db.stage_profile_map_updates(
        **duplicate_stage_action.arguments,
        allow_pending_profile_updates=True,
    )
    assert forced_duplicate.staged_revision is not None

    row_count = draft.recommendations[0]
    assert row_count.action == "replace_map_value"
    assert row_count.current_value == 10
    assert row_count.observed_value == 12
    assert row_count.sample_size == 12
    assert row_count.sample_scope == "All rows in the test Payments table."
    assert row_count.sample_method == "DuckDB full-table aggregate profile."
    assert row_count.profile_row_count == 12
    assert row_count.basis == "full_scan"
    assert row_count.confidence == "high"
    assert row_count.helper_name == "record_map_dataset"
    assert row_count.helper_arguments == {
        "iri": dataset,
        "row_count_snapshot": 12,
    }

    nullable = draft.recommendations[1]
    assert nullable.action == "replace_map_value"
    assert nullable.current_value is False
    assert nullable.observed_value is True
    assert nullable.observed_count == 2
    assert nullable.sample_size == 12
    assert nullable.helper_arguments == {
        "iri": status_column,
        "table_iri": dataset,
        "column_name": "status",
        "nullable": True,
    }

    unmapped = draft.recommendations[2]
    assert unmapped.action == "add_map_column_shell"
    assert unmapped.current_value is None
    assert unmapped.observed_value == "settlement_method"
    assert unmapped.helper_arguments == {
        "iri": settlement_column,
        "table_iri": dataset,
        "column_name": "settlement_method",
    }

    assert len(draft.metric_advisories) == 1
    assert draft.metric_advisory_count == 1
    assert draft.metric_advisory_status_counts == {
        "project_metric_undefined": 1,
    }
    metric_advisory = draft.metric_advisories[0]
    assert metric_advisory.metric.iri == project_metric
    assert metric_advisory.observed_metric_iri.startswith(
        "https://richcanopy.org/doxabase/generated/observed-profile-metric/"
    )
    assert metric_advisory.advisory_status == "project_metric_undefined"
    assert metric_advisory.definition_found is False
    assert metric_advisory.definition is None
    assert [action.tool_name for action in metric_advisory.suggested_next_actions] == [
        "describe_context_slice",
        "list_entities",
        "stage_systematisation",
        "describe_pattern",
        "stage_pattern_promotion",
    ]
    metric_fallback_action = metric_advisory.suggested_next_actions[2]
    assert metric_fallback_action.arguments["profile_route_sources"] == [
        metric_fallback_action.source_profile_advisory
    ]
    assert metric_fallback_action.arguments["framings"][0]["graph"] == "patterns"
    assert [item.iri for item in metric_advisory.promotion_patterns] == [
        metric_pattern.pattern_iri
    ]
    assert metric_advisory.suggested_next_actions[0].arguments == {
        "seed_iris": [metric_advisory.observed_metric_iri],
        "profile": "dataset_brief",
    }
    assert metric_advisory.recommendation == (
        "review_metric_vocabulary_before_reuse"
    )

    description = db.describe_dataset(dataset)
    assert description.row_count_snapshot == 10
    assert {
        column.iri: column.nullable for column in description.columns
    } == {
        status_column: False,
        amount_column: False,
    }


def test_export_profile_insight_review_bundle_discovers_related_staged_revisions(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/profile-review#SupportEvents"
    status_column = "https://example.test/profile-review#SupportEventsState"
    evidence = "https://example.test/profile-review#SupportEventsProfileEvidence"
    metric = "https://example.test/profile-review#WorkflowFlipRate"
    caveat = "https://example.test/profile-review#WorkflowFlipRateCaveat"
    fake_secret = "FAKE_SECRET_DO_NOT_USE_PROFILE"
    secret_text = f"Bearer {fake_secret}"

    db.record_map_dataset(
        dataset,
        label="Support Events",
        is_table=True,
        row_count_snapshot=8,
        path_templates=["support/events/*.parquet"],
    )
    db.record_map_column(
        status_column,
        table_iri=dataset,
        column_name="workflow_state",
        nullable=False,
    )
    bundle = db.record_profile_bundle(
        dataset,
        dataset_summary="Support Events were profiled with a full-table scan.",
        evidence_summary="Synthetic profile run for profile insight review.",
        evidence_sources=["test://support-events-profile"],
        shared_evidence_iri=evidence,
        sample_size=10,
        sample_scope="All rows in the Support Events table.",
        sample_method="DuckDB full-table aggregate profile.",
        row_count=10,
        update_map_snapshot=False,
        profile_metrics=[
            {
                "metric": metric,
                "target": dataset,
                "value": "0.217",
                "datatype": "xsd:decimal",
            }
        ],
        column_defaults={"update_map_column": False},
        column_profiles=[
            {
                "column_iri": status_column,
                "column_name": "workflow_state",
                "summary": "Workflow state had nulls in the full scan.",
                "null_count": 1,
                "distinct_count": 4,
                "physical_type": "rc:Varchar",
            }
        ],
    )
    related_pattern = db.record_pattern(
        summary="Workflow flip rate needs scoped review.",
        pattern_text=(
            "Workflow flip rate is useful only when replay and backfill rows "
            "are scoped out of the denominator."
        ),
        rationale=(
            "The same profile evidence supports map drift review, metric "
            "vocabulary review, and a caveat alternative."
        ),
        pattern_targets=[dataset, metric],
        supporting_observations=bundle.handoff_entrypoints.profile_observation_iris,
        evidence_iri=evidence,
        map_implications=[metric, caveat],
    )
    unrelated_pattern = db.record_pattern(
        summary="Unrelated same-evidence note.",
        pattern_text="This note intentionally shares evidence but targets refunds.",
        rationale="It should not make unrelated staged work part of the bundle.",
        pattern_targets=["https://example.test/profile-review#Refunds"],
        evidence_iri=evidence,
        map_implications=["https://example.test/profile-review#RefundReason"],
    )

    draft = db.draft_profile_map_updates(dataset, evidence)
    query_context_action = draft.suggested_next_action_groups[
        "query_context_review"
    ][0]
    query_route_key = query_context_action.source_query_context["route_group_key"]
    assert query_context_action.source_query_context["route_anchor_iris"] == [
        dataset
    ]
    profile_map_route_key = draft.suggested_next_action_groups[
        "profile_map_updates"
    ][0].source_profile_map_update["route_group_key"]
    staged_map = db.stage_profile_map_updates(
        dataset,
        evidence,
        accepted_recommendation_indexes=[0, 1],
        supporting_patterns=[related_pattern.pattern_iri],
    )
    promotion_action = next(
        action
        for action in draft.suggested_next_action_groups["metric_vocabulary_review"]
        if action.tool_name == "stage_pattern_promotion"
    )
    metric_route_key = promotion_action.source_profile_advisory["route_group_key"]
    assert promotion_action.arguments["profile_route_sources"] == [
        promotion_action.source_profile_advisory
    ]
    metric_promotion = db.stage_pattern_promotion(**promotion_action.arguments)
    assert metric_promotion.profile_route_source_count == 1
    storage_access = "https://example.test/profile-review#SupportEventsStorage"
    query_repair_draft = db.stage_systematisation(
        summary="Review Support Events storage access",
        intent="Keep the query-context blocker repair reviewable beside profile-derived map updates.",
        rationale=(
            "The profile draft routed agents through query_context_review before "
            "using profile-derived map updates as query-planning context."
        ),
        anchors=[dataset, storage_access],
        profile_route_sources=[query_context_action.source_query_context],
        framings=[
            {
                "label": "Map storage access",
                "graph": "map",
                "content": f"""
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    <{dataset}> rc:hasStorageAccess <{storage_access}> .

                    <{storage_access}> a rc:StorageAccess ;
                        rc:storageProtocol rc:LocalFilesystemStorage ;
                        rc:storageRoot "/tmp/support-events.parquet" .
                """,
            }
        ],
        validation_scope="all",
    )
    assert query_repair_draft.profile_route_source_count == 1
    caveat_draft = db.stage_systematisation(
        summary="Review workflow flip caveat",
        intent="Keep the denominator caveat reviewable beside profile map updates.",
        rationale=(
            "The caveat is profile-derived but should remain a staged semantic "
            "choice rather than being hidden in the row-count update."
        ),
        anchors=[dataset, metric, caveat],
        supporting_observations=bundle.handoff_entrypoints.profile_observation_iris,
        supporting_patterns=[related_pattern.pattern_iri],
        evidence=[evidence],
        framings=[
            {
                "label": "Map caveat",
                "graph": "map",
                "content": f"""
                    @prefix rc: <https://richcanopy.org/ns/rc#> .
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    <{caveat}> a rc:KnownCaveat ;
                        rdfs:label "Workflow flip denominator caveat" ;
                        rc:caveatDescription "Workflow flip rate excludes replay and backfill rows. Scratch credential paste: {secret_text}" .

                    <{dataset}> rc:hasKnownCaveat <{caveat}> .
                """,
            }
        ],
        validation_scope="all",
    )
    unrelated_draft = db.stage_systematisation(
        summary="Unrelated refunds review",
        intent="Provide an unrelated same-evidence staged row.",
        rationale="This row shares no profile-derived anchors or related pattern.",
        supporting_patterns=[unrelated_pattern.pattern_iri],
        framings=[
            {
                "label": "Refund note",
                "graph": "patterns",
                "content": """
                    @prefix ex: <https://example.test/profile-review#> .
                    @prefix rc: <https://richcanopy.org/ns/rc#> .

                    ex:RefundReviewPattern a rc:Pattern ;
                        rc:summary "Refunds need separate review." ;
                        rc:patternText "Refunds are not part of the support event profile insight." ;
                        rc:rationale "Synthetic unrelated row." ;
                        rc:patternTarget ex:Refunds .
                """,
            }
        ],
        validation_scope="all",
    )

    export_path = tmp_path / "profile-insight-review.md"
    result = db.export_profile_insight_review_bundle(
        dataset,
        evidence,
        export_path,
    )

    expected_revision_iris = {
        staged_map.staged_revision.revision_iri,
        metric_promotion.staged_revisions[0].revision_iri,
        query_repair_draft.staged_revisions[0].revision_iri,
        caveat_draft.staged_revisions[0].revision_iri,
    }
    assert set(result.candidate_revision_iris) == expected_revision_iris
    assert unrelated_draft.staged_revisions[0].revision_iri not in (
        result.candidate_revision_iris
    )
    assert result.candidate_count == 4
    assert result.export is not None
    assert set(result.export.revision_iris) == expected_revision_iris
    candidates_by_iri = {
        candidate.revision_iri: candidate for candidate in result.candidates
    }
    assert profile_map_route_key in candidates_by_iri[
        staged_map.staged_revision.revision_iri
    ].profile_route_keys
    map_route_groups = {
        group["review_lane"]: group
        for group in candidates_by_iri[
            staged_map.staged_revision.revision_iri
        ].profile_route_groups
    }
    assert map_route_groups["profile_map_updates"]["match_strength"] == (
        "direct_action"
    )
    assert map_route_groups["metric_vocabulary_review"]["match_strength"] == (
        "strong_support"
    )
    assert metric_route_key in candidates_by_iri[
        metric_promotion.staged_revisions[0].revision_iri
    ].profile_route_keys
    metric_route_groups = {
        group["review_lane"]: group
        for group in candidates_by_iri[
            metric_promotion.staged_revisions[0].revision_iri
        ].profile_route_groups
    }
    assert metric_route_groups["metric_vocabulary_review"]["match_strength"] == (
        "direct_action"
    )
    assert metric_route_groups["profile_map_updates"]["match_strength"] == (
        "strong_support"
    )
    assert query_route_key in candidates_by_iri[
        query_repair_draft.staged_revisions[0].revision_iri
    ].profile_route_keys
    query_route_groups = {
        group["review_lane"]: group
        for group in candidates_by_iri[
            query_repair_draft.staged_revisions[0].revision_iri
        ].profile_route_groups
    }
    assert query_route_groups["query_context_review"]["match_strength"] == (
        "direct_action"
    )
    assert all(
        group["route_step_keys"]
        for candidate in result.candidates
        for group in candidate.profile_route_groups
    )
    assert result.artifact_kind == "profile_insight_review_bundle"
    assert result.importable is False
    assert result.recommended_import_tool is None
    assert result.recovery_complete is False
    assert result.export is not None
    assert result.export.artifact_kind == "staged_revisions_review_markdown"
    assert result.export.importable is False
    assert result.export.recommended_import_tool is None
    assert result.export.recovery_complete is False
    assert result.export.sensitive_literal_count == 1
    assert result.export.privacy_warnings
    assert fake_secret not in " ".join(result.export.privacy_warnings)
    assert related_pattern.pattern_iri in result.related_pattern_iris
    assert unrelated_pattern.pattern_iri not in result.related_pattern_iris
    assert all(candidate.relation_reasons for candidate in result.candidates)
    assert any(
        "supporting_profile_observation" in candidate.relation_reasons
        for candidate in result.candidates
    )
    assert export_path.exists()
    exported = export_path.read_text(encoding="utf-8")
    assert "Profile insight review: Support Events" in exported
    assert "## Privacy Warning" in exported
    assert "## Reviewer Decision Matrix" in exported
    assert "### Profile Route Bridge" in exported
    assert (
        "| Row | Candidate | Revision | Profile route keys | Review lanes | Matched by |"
        in exported
    )
    for row_number, candidate in enumerate(result.candidates, start=1):
        if not candidate.profile_route_groups:
            continue
        assert f"| {row_number} | {candidate.summary} |" in exported
        assert f"## Revision {row_number}: {candidate.summary}" in exported
    assert profile_map_route_key in exported
    assert metric_route_key in exported
    assert query_route_key in exported
    assert "profile_map_updates (direct_action)" in exported
    assert "metric_vocabulary_review (direct_action)" in exported
    assert "profile_map_updates (strong_support)" in exported
    assert "metric_vocabulary_review (strong_support)" in exported
    secret_line = _line_number_containing(exported, secret_text)
    assert f"line {secret_line} " in " ".join(result.export.privacy_warnings)
    assert "Workflow flip denominator caveat" in exported
    assert secret_text in exported
    assert "WorkflowFlipRate" in exported

    blocked_profile_path = tmp_path / "blocked-profile-insight-review.md"
    with pytest.raises(DoxaBaseError, match="fail_on_sensitive=True"):
        db.export_profile_insight_review_bundle(
            dataset,
            evidence,
            blocked_profile_path,
            fail_on_sensitive=True,
        )
    assert not blocked_profile_path.exists()


def test_profile_insight_review_bundle_reuses_apply_checks(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/profile-cache#Orders"
    evidence = "https://example.test/profile-cache#OrdersProfileEvidence"
    staged_note = "https://example.test/profile-cache#OrdersReviewNote"

    db.record_map_dataset(
        dataset,
        label="Orders",
        is_table=True,
        row_count_snapshot=10,
    )
    db.record_dataset_profile(
        dataset,
        summary="Orders profile pass.",
        evidence_summary="Synthetic profile output.",
        evidence_sources=["test://orders-profile"],
        evidence_iri=evidence,
        sample_size=10,
        sample_scope="All rows in the local Orders table.",
        sample_method="DuckDB full-table aggregate profile.",
        row_count=10,
        update_map_snapshot=False,
    )
    staged = db.stage_graph_revision(
        summary="Add Orders profile review note",
        rationale="Keep a profile-derived review note near the evidence.",
        additions=[
            {
                "graph": "map",
                "content": f"""
                    @prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .

                    <{staged_note}> rdfs:comment "Profile-derived review note." .
                """,
            }
        ],
        evidence=[evidence],
    )

    validate_preview_call_count = 0
    original_validate_graph_preview = db._validate_graph_preview

    def counted_validate_graph_preview(*args: object, **kwargs: object) -> object:
        nonlocal validate_preview_call_count
        validate_preview_call_count += 1
        return original_validate_graph_preview(*args, **kwargs)

    monkeypatch.setattr(db, "_validate_graph_preview", counted_validate_graph_preview)

    result = db.export_profile_insight_review_bundle(
        dataset,
        evidence,
        tmp_path / "profile-insight-review.md",
    )

    assert result.candidate_revision_iris == [staged.revision_iri]
    assert validate_preview_call_count == 1


def test_profile_insight_review_bundle_marks_plain_map_update_safe_single(
    tmp_path: Path,
) -> None:
    db = DoxaBase.create(tmp_path / "capsule.sqlite")
    dataset = "https://example.test/profile-gate#Orders"
    evidence = "https://example.test/profile-gate#OrdersProfileEvidence"

    db.record_map_dataset(
        dataset,
        label="Orders",
        is_table=True,
        row_count_snapshot=10,
    )
    db.record_dataset_profile(
        dataset,
        summary="Orders profile found a row-count drift.",
        evidence_summary="Synthetic full-table profile output.",
        evidence_sources=["test://orders-profile"],
        evidence_iri=evidence,
        sample_size=12,
        sample_scope="All rows in the local Orders table.",
        sample_method="DuckDB full-table aggregate profile.",
        row_count=12,
        update_map_snapshot=False,
    )
    staged = db.stage_profile_map_updates(
        dataset,
        evidence,
        accepted_recommendation_indexes=[0],
    )

    result = db.export_profile_insight_review_bundle(
        dataset,
        evidence,
        tmp_path / "profile-insight-map-only-review.md",
    )

    assert result.bulk_apply_allowed is True
    assert result.safe_single_apply_candidate_revision_iris == [
        staged.staged_revision.revision_iri
    ]
    assert result.semantic_apply_gate_counts["safe_single_apply_candidates"] == 1
    assert result.semantic_apply_gate_blocking_reasons == []
    assert result.executor_decision_summary["decision"] == (
        "bulk_apply_after_review"
    )
    assert result.executor_decision_summary["mutation_policy"] == (
        "bulk_apply_allowed_after_review"
    )
    assert result.executor_decision_summary[
        "safe_single_apply_candidate_revision_iris"
    ] == [staged.staged_revision.revision_iri]
    assert result.executor_decision_summary["open_review_lanes"] == []
    assert result.executor_decision_summary["candidate_roles"] == {
        "ordinary_profile_map_update": 1
    }
    candidate = result.candidates[0]
    assert candidate.semantic_apply_role == "ordinary_profile_map_update"
    assert candidate.apply_cardinality == "single_after_review"
    assert candidate.safe_single_apply_candidate is True
    assert candidate.bulk_apply_allowed is True
    exported = (tmp_path / "profile-insight-map-only-review.md").read_text(
        encoding="utf-8"
    )
    assert "### Semantic Apply Gate" in exported
    assert "Bulk application is mechanically allowed" in exported


